{
  "name": "Basis Labs Inventory Management",
  "description": "A comprehensive inventory management system for Basis Laboratories Pvt Ltd, featuring batch tracking, transaction history, and chemical property management."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ChemicalState {
  SOLID = 'Solid',
  LIQUID = 'Liquid'
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
}

export interface InventoryItem {
  batchNo: string; // Unique Identifier
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
  dateOfExpiry: string;
  transactions: Transaction[];
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights';

import React, { useState, useEffect, useCallback } from 'react';
import { 
  PlusIcon, 
  TableCellsIcon, 
  BeakerIcon, 
  ArrowPathIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  PencilSquareIcon,
  EyeIcon,
  ArchiveBoxIcon,
  LightBulbIcon
} from '@heroicons/react/24/outline';
import { InventoryItem, ViewState, ChemicalState, Transaction } from './types';
import InventoryForm from './components/InventoryForm';
import InventoryTable from './components/InventoryTable';
import ItemDetails from './components/ItemDetails';
import DashboardStats from './components/DashboardStats';
import AIInsights from './components/AIInsights';

const App: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [view, setView] = useState<ViewState>('dashboard');
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // Load initial data from localStorage if available
  useEffect(() => {
    const saved = localStorage.getItem('basis_labs_inventory');
    if (saved) {
      try {
        setItems(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load inventory", e);
      }
    }
  }, []);

  // Save to localStorage whenever items change
  useEffect(() => {
    localStorage.setItem('basis_labs_inventory', JSON.stringify(items));
  }, [items]);

  const handleAddItem = (item: InventoryItem) => {
    if (items.some(i => i.batchNo === item.batchNo)) {
      alert("Error: Batch Number must be unique.");
      return;
    }
    setItems([...items, item]);
    setView('dashboard');
  };

  const handleUpdateItem = (updatedItem: InventoryItem) => {
    setItems(items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i));
    setView('dashboard');
    setSelectedItem(null);
  };

  const handleRecordUsage = (batchNo: string, transaction: Transaction) => {
    setItems(prevItems => prevItems.map(item => {
      if (item.batchNo === batchNo) {
        const newQuantity = item.quantity - transaction.amount;
        if (newQuantity < 0) {
          alert("Insufficient quantity available!");
          return item;
        }
        return {
          ...item,
          quantity: newQuantity,
          transactions: [transaction, ...item.transactions]
        };
      }
      return item;
    }));
  };

  const filteredItems = items.filter(item => 
    item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.batchNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vendorName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-2 mb-8">
            <BeakerIcon className="w-8 h-8 text-teal-400" />
            <span className="text-xl font-bold tracking-tight">Basis Labs</span>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => setView('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'dashboard' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <TableCellsIcon className="w-5 h-5" />
              Inventory
            </button>
            <button 
              onClick={() => setView('add')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'add' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <PlusIcon className="w-5 h-5" />
              Add Stock
            </button>
            <button 
              onClick={() => setView('ai-insights')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'ai-insights' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <LightBulbIcon className="w-5 h-5" />
              AI Insights
            </button>
          </nav>
        </div>

        <div className="mt-auto p-6 border-t border-slate-800 text-xs text-slate-400">
          v1.0.4 Laboratory MS
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
              {view === 'dashboard' && 'Inventory Dashboard'}
              {view === 'add' && 'Register New Batch'}
              {view === 'edit' && `Editing Batch: ${selectedItem?.batchNo}`}
              {view === 'details' && `Details: ${selectedItem?.chemicalName}`}
              {view === 'ai-insights' && 'AI Inventory Analysis'}
            </h1>
            <p className="text-slate-500">
              {view === 'dashboard' && 'Manage and monitor laboratory chemical stocks.'}
              {view !== 'dashboard' && 'Update or view laboratory resource details.'}
            </p>
          </div>

          {view === 'dashboard' && (
            <div className="relative">
              <MagnifyingGlassIcon className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input 
                type="text" 
                placeholder="Search chemical, batch, or vendor..."
                className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-full md:w-80 focus:ring-2 focus:ring-teal-500 outline-none transition-all shadow-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          )}
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable 
                items={filteredItems} 
                onEdit={(item) => {
                  setSelectedItem(item);
                  setView('edit');
                }}
                onView={(item) => {
                  setSelectedItem(item);
                  setView('details');
                }}
              />
            </>
          )}

          {(view === 'add' || view === 'edit') && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <InventoryForm 
                initialData={view === 'edit' ? selectedItem : null}
                onSubmit={view === 'edit' ? handleUpdateItem : handleAddItem}
                onCancel={() => setView('dashboard')}
              />
            </div>
          )}

          {view === 'details' && selectedItem && (
            <ItemDetails 
              item={selectedItem} 
              onBack={() => setView('dashboard')}
              onRecordUsage={(transaction) => handleRecordUsage(selectedItem.batchNo, transaction)}
            />
          )}

          {view === 'ai-insights' && (
            <AIInsights items={items} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { InventoryItem, ChemicalState } from '../types';

interface InventoryFormProps {
  initialData?: InventoryItem | null;
  onSubmit: (item: InventoryItem) => void;
  onCancel: () => void;
}

const InventoryForm: React.FC<InventoryFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Omit<InventoryItem, 'transactions'>>({
    batchNo: '',
    vendorName: '',
    vendorQualification: '',
    quantity: 0,
    unit: 'kg',
    chemicalName: '',
    description: ChemicalState.SOLID,
    dateOfManufacturing: '',
    dateOfAnalysis: '',
    dateOfRetest: '',
    dateOfExpiry: '',
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseFloat(value) || 0 : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      ...formData,
      transactions: initialData?.transactions || []
    });
  };

  const inputClasses = "w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-slate-900 text-sm focus:ring-teal-500 focus:border-teal-500 block outline-none transition-all";
  const labelClasses = "block mb-2 text-sm font-medium text-slate-700";

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Basic Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Basic Identification</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className={labelClasses}>Chemical Name</label>
              <input 
                name="chemicalName" 
                value={formData.chemicalName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="e.g. Sodium Chloride"
              />
            </div>
            <div>
              <label className={labelClasses}>Batch No (Unique ID)</label>
              <input 
                name="batchNo" 
                value={formData.batchNo} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                disabled={!!initialData}
                placeholder="B-2024-001"
              />
            </div>
            <div>
              <label className={labelClasses}>Physical Description</label>
              <select 
                name="description" 
                value={formData.description} 
                onChange={handleChange} 
                className={inputClasses}
              >
                <option value={ChemicalState.SOLID}>Solid</option>
                <option value={ChemicalState.LIQUID}>Liquid</option>
              </select>
            </div>
          </div>
        </div>

        {/* Vendor Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Vendor & Quality</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Vendor Name</label>
              <input 
                name="vendorName" 
                value={formData.vendorName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="Global Chemicals Inc."
              />
            </div>
            <div>
              <label className={labelClasses}>Vendor Qualification</label>
              <input 
                name="vendorQualification" 
                value={formData.vendorQualification} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="ISO 9001 Certified"
              />
            </div>
          </div>
        </div>

        {/* Quantity */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Stock Details</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Quantity</label>
              <input 
                type="number" 
                step="0.01" 
                name="quantity" 
                value={formData.quantity} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
              />
            </div>
            <div>
              <label className={labelClasses}>Unit</label>
              <input 
                name="unit" 
                value={formData.unit} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="kg, L, g, etc."
              />
            </div>
          </div>
        </div>

        {/* Dates */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Date Schedule</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div>
              <label className={labelClasses}>Manufacturing Date</label>
              <input type="date" name="dateOfManufacturing" value={formData.dateOfManufacturing} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Analysis Date</label>
              <input type="date" name="dateOfAnalysis" value={formData.dateOfAnalysis} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Retest Date</label>
              <input type="date" name="dateOfRetest" value={formData.dateOfRetest} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Expiry Date</label>
              <input type="date" name="dateOfExpire" value={formData.dateOfExpiry} onChange={handleChange} className={inputClasses} required />
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-6 border-t">
        <button 
          type="button" 
          onClick={onCancel}
          className="px-6 py-2.5 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors"
        >
          Cancel
        </button>
        <button 
          type="submit"
          className="px-6 py-2.5 text-sm font-medium text-white bg-teal-600 rounded-lg hover:bg-teal-700 transition-colors shadow-sm"
        >
          {initialData ? 'Update Record' : 'Save Inventory'}
        </button>
      </div>
    </form>
  );
};

export default InventoryForm;

import React from 'react';
import { InventoryItem, ChemicalState } from '../types';
import { PencilSquareIcon, EyeIcon, BeakerIcon } from '@heroicons/react/24/outline';

interface InventoryTableProps {
  items: InventoryItem[];
  onEdit: (item: InventoryItem) => void;
  onView: (item: InventoryItem) => void;
}

const InventoryTable: React.FC<InventoryTableProps> = ({ items, onEdit, onView }) => {
  if (items.length === 0) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 p-12 text-center">
        <ArchiveBoxIcon className="w-12 h-12 text-slate-300 mx-auto mb-4" />
        <h3 className="text-lg font-medium text-slate-600">No inventory items found</h3>
        <p className="text-slate-400">Try adjusting your search or add a new chemical batch.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 border-b border-slate-200 text-slate-600 uppercase text-xs font-semibold">
            <tr>
              <th className="px-6 py-4">Chemical / Batch</th>
              <th className="px-6 py-4">Vendor</th>
              <th className="px-6 py-4">Quantity</th>
              <th className="px-6 py-4">State</th>
              <th className="px-6 py-4">Expiry Date</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200">
            {items.map((item) => {
              const isExpired = new Date(item.dateOfExpiry) < new Date();
              const isLowStock = item.quantity < 5; // Arbitrary low stock threshold

              return (
                <tr key={item.batchNo} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-lg ${item.description === ChemicalState.SOLID ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                        <BeakerIcon className="w-5 h-5" />
                      </div>
                      <div>
                        <div className="font-semibold text-slate-800">{item.chemicalName}</div>
                        <div className="text-xs text-slate-500 font-mono">#{item.batchNo}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-slate-700">{item.vendorName}</div>
                    <div className="text-xs text-slate-400">{item.vendorQualification}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className={`font-medium ${isLowStock ? 'text-red-600 font-bold' : 'text-slate-700'}`}>
                      {item.quantity} {item.unit}
                    </div>
                    {isLowStock && <span className="text-[10px] uppercase font-bold text-red-500">Low Stock</span>}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-[11px] font-bold uppercase tracking-wider ${
                      item.description === ChemicalState.SOLID ? 'bg-amber-50 text-amber-700' : 'bg-blue-50 text-blue-700'
                    }`}>
                      {item.description}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className={isExpired ? 'text-red-600 font-semibold' : 'text-slate-600'}>
                      {item.dateOfExpiry}
                    </div>
                    {isExpired && <span className="text-[10px] uppercase font-bold text-red-500">Expired</span>}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => onView(item)}
                        className="p-1.5 text-slate-400 hover:text-teal-600 transition-colors"
                        title="View Usage"
                      >
                        <EyeIcon className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => onEdit(item)}
                        className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors"
                        title="Edit Record"
                      >
                        <PencilSquareIcon className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default InventoryTable;

import { ArchiveBoxIcon } from '@heroicons/react/24/outline';

import React from 'react';
import { InventoryItem } from '../types';
import { 
  CircleStackIcon, 
  ExclamationTriangleIcon, 
  ClockIcon, 
  CheckCircleIcon 
} from '@heroicons/react/24/solid';

interface DashboardStatsProps {
  items: InventoryItem[];
}

const DashboardStats: React.FC<DashboardStatsProps> = ({ items }) => {
  const totalBatches = items.length;
  const expiredCount = items.filter(i => new Date(i.dateOfExpiry) < new Date()).length;
  const lowStockCount = items.filter(i => i.quantity < 5).length;
  const retestSoonCount = items.filter(i => {
    const retestDate = new Date(i.dateOfRetest);
    const today = new Date();
    const diffDays = Math.ceil((retestDate.getTime() - today.getTime()) / (1000 * 3600 * 24));
    return diffDays > 0 && diffDays < 30;
  }).length;

  const stats = [
    { label: 'Total Batches', value: totalBatches, icon: CircleStackIcon, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Expired Items', value: expiredCount, icon: ExclamationTriangleIcon, color: 'text-red-600', bg: 'bg-red-50' },
    { label: 'Low Stock Alerts', value: lowStockCount, icon: ClockIcon, color: 'text-amber-600', bg: 'bg-amber-50' },
    { label: 'Retest in 30 Days', value: retestSoonCount, icon: CheckCircleIcon, color: 'text-teal-600', bg: 'bg-teal-50' },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
      {stats.map((stat, idx) => (
        <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center gap-4">
          <div className={`${stat.bg} ${stat.color} p-3 rounded-lg`}>
            <stat.icon className="w-6 h-6" />
          </div>
          <div>
            <div className="text-2xl font-bold text-slate-800">{stat.value}</div>
            <div className="text-xs text-slate-500 font-medium uppercase tracking-wider">{stat.label}</div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default DashboardStats;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { InventoryItem } from '../types';
import { SparklesIcon, ArrowPathIcon } from '@heroicons/react/24/outline';

interface AIInsightsProps {
  items: InventoryItem[];
}

const AIInsights: React.FC<AIInsightsProps> = ({ items }) => {
  const [insight, setInsight] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const generateInsights = async () => {
    if (items.length === 0) return;

    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const inventorySummary = items.map(i => ({
        chemical: i.chemicalName,
        qty: i.quantity,
        unit: i.unit,
        expiry: i.dateOfExpiry,
        retest: i.dateOfRetest
      }));

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze this laboratory inventory data and provide 3-4 professional, actionable bullet points for Basis Laboratories Pvt Ltd. Focus on potential risks (expiring soon, retest dates), resource optimization, and replenishment advice. Data: ${JSON.stringify(inventorySummary)}`,
        config: {
            systemInstruction: "You are a senior Laboratory Manager and Supply Chain Expert. Provide concise, professional insights in Markdown format. Use bullet points."
        }
      });

      setInsight(response.text || "Unable to generate insights at this time.");
    } catch (error) {
      console.error("AI Error:", error);
      setInsight("Error connecting to AI Analysis service. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (items.length > 0) {
      generateInsights();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-gradient-to-r from-teal-600 to-teal-800 p-6 flex justify-between items-center text-white">
        <div className="flex items-center gap-3">
          <SparklesIcon className="w-8 h-8 text-teal-300" />
          <div>
            <h2 className="text-xl font-bold">Smart Inventory Insights</h2>
            <p className="text-teal-100 text-sm">AI-driven analysis for Basis Laboratories Pvt Ltd</p>
          </div>
        </div>
        <button 
          onClick={generateInsights}
          disabled={loading}
          className="p-2 bg-white/10 hover:bg-white/20 rounded-lg transition-colors disabled:opacity-50"
          title="Refresh Insights"
        >
          <ArrowPathIcon className={`w-6 h-6 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      <div className="p-8">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-12 text-slate-400 space-y-4">
            <div className="w-10 h-10 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="animate-pulse">Consulting Gemini for laboratory optimization strategies...</p>
          </div>
        ) : insight ? (
          <div className="prose prose-slate max-w-none">
            <div className="whitespace-pre-line text-slate-700 leading-relaxed font-medium">
              {insight.split('\n').map((line, i) => (
                <div key={i} className="mb-2 last:mb-0">{line}</div>
              ))}
            </div>
            <div className="mt-8 p-4 bg-slate-50 border-l-4 border-teal-500 rounded-r-lg text-xs text-slate-500 flex items-center gap-2">
              <SparklesIcon className="w-4 h-4" />
              This analysis is generated by AI based on current inventory snapshots. Always verify critical safety dates manually.
            </div>
          </div>
        ) : (
          <div className="text-center py-12 text-slate-400">
            <p>No inventory data available for AI analysis. Add items to see insights.</p>
          </div>
        )}
      </div>
    </div>
  );
};

