                <div className="relative">
                  <LinkIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="url" 
                    placeholder="https://onedrive.live.com/..."
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    value={excelLink}
                    onChange={(e) => setExcelLink(e.target.value)}
                  />
                </div>
                <p className="mt-2 text-xs text-slate-500 leading-relaxed">
                  Tip: Use a Microsoft Power Automate Webhook or a public OneDrive share link. 
                  Data is pushed every 60 seconds when changes are detected.
                </p>
              </div>
              <div className="bg-amber-50 border border-amber-100 p-3 rounded-lg flex gap-3">
                <LightBulbIcon className="w-5 h-5 text-amber-600 flex-shrink-0" />
                <p className="text-[11px] text-amber-800">
                  Ensure your Excel file columns match the <strong>Blueprint</strong> exactly to ensure synchronization works correctly.
                </p>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => {
                    localStorage.removeItem('basis_labs_excel_link');
                    setExcelLink('');
                    setShowLinkModal(false);
                  }}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Unlink Sheet
                </button>
                <button 
                  onClick={() => {
                    localStorage.setItem('basis_labs_excel_link', excelLink);
                    setShowLinkModal(false);
                    performSync();
                  }}
                  className="flex-1 py-3 text-sm font-medium text-white bg-emerald-600 rounded-xl hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all"
                >
                  Save & Sync Now
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum ChemicalState {
  SOLID = 'Solid',
  LIQUID = 'Liquid'
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
}

export interface InventoryItem {
  batchNo: string; // Unique Identifier
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
  dateOfExpiry: string;
  transactions: Transaction[];
}

export type RequestType = 'R&D' | 'QC' | 'Production';

export interface MaterialRequest {
  id: string;
  type: RequestType;
  chemicalName: string;
  batchNo: string;
  quantity: number;
  unit: string;
  requestedBy: string;
  date: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  departmentNotes?: string;
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights' | 'requests';

import React, { useState, useEffect, useCallback } from 'react';
import { 
  PlusIcon, 
  TableCellsIcon, 
  BeakerIcon, 
  ArrowPathIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  PencilSquareIcon,
  EyeIcon,
  ArchiveBoxIcon,
  LightBulbIcon,
  CloudArrowUpIcon,
  LinkIcon,
  ArrowDownTrayIcon,
  DocumentArrowDownIcon,
  ClipboardDocumentCheckIcon
} from '@heroicons/react/24/outline';
import * as XLSX from 'xlsx';
import { InventoryItem, ViewState, ChemicalState, Transaction, MaterialRequest } from './types';
import InventoryForm from './components/InventoryForm';
import InventoryTable from './components/InventoryTable';
import ItemDetails from './components/ItemDetails';
import DashboardStats from './components/DashboardStats';
import AIInsights from './components/AIInsights';
import RequestSystem from './components/RequestSystem';

const LOGO_URL = "https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U";

const App: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);
  const [view, setView] = useState('dashboard' as ViewState);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // Excel Sync State
  const [excelLink, setExcelLink] = useState<string>(localStorage.getItem('basis_labs_excel_link') || '');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showLinkModal, setShowLinkModal] = useState(false);

  useEffect(() => {
    const savedItems = localStorage.getItem('basis_labs_inventory');
    const savedRequests = localStorage.getItem('basis_labs_requests');
    if (savedItems) {
      try { setItems(JSON.parse(savedItems)); } catch (e) { console.error(e); }
    }
    if (savedRequests) {
      try { setRequests(JSON.parse(savedRequests)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('basis_labs_inventory', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('basis_labs_requests', JSON.stringify(requests));
  }, [requests]);

  // Simulated Auto-Sync Every 1 Minute
  useEffect(() => {
    const syncInterval = setInterval(() => {
      if (excelLink) {
        performSync();
      }
    }, 60000); // 60 seconds
    return () => clearInterval(syncInterval);
  }, [excelLink, items]);

  const performSync = async () => {
    setIsSyncing(true);
    await new Promise(resolve => setTimeout(resolve, 2000));
    setLastSync(new Date());
    setIsSyncing(false);
  };

  const downloadBlueprint = () => {
    const headers = [
      'Batch No', 'Vendor Name', 'Vendor Qualification', 'Quantity', 'Unit', 
      'Chemical Name', 'Description (Solid/Liquid)', 'Date of Manufacturing', 
      'Date of Analysis', 'Date of Retest', 'Date of Expiry'
    ];
    const exampleData = [{
      'Batch No': 'B-12345',
      'Vendor Name': 'Sigma-Aldrich Pvt Ltd',
      'Vendor Qualification': 'Qualified',
      'Quantity': 100.00,
      'Unit': 'kg',
      'Chemical Name': 'Sodium Hydroxide',
      'Description (Solid/Liquid)': 'Solid',
      'Date of Manufacturing': '2024-01-15',
      'Date of Analysis': '2024-01-20',
      'Date of Retest': '2025-01-15',
      'Date of Expiry': '2026-01-15'
    }];
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(exampleData, { header: headers });
    ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length, 15) }));
    XLSX.utils.book_append_sheet(wb, ws, "Inventory_Blueprint");
    XLSX.writeFile(wb, "BasisLabs_Inventory_Blueprint.xlsx");
  };

  const exportToExcel = () => {
    const worksheetData = items.map(item => ({
      'Batch No': item.batchNo,
      'Chemical Name': item.chemicalName,
      'Vendor': item.vendorName,
      'Qualification': item.vendorQualification,
      'Quantity': item.quantity,
      'Unit': item.unit,
      'Description': item.description,
      'Mfg Date': item.dateOfManufacturing,
      'Analysis Date': item.dateOfAnalysis,
      'Retest Date': item.dateOfRetest,
      'Expiry Date': item.dateOfExpiry,
      'Usage Records': item.transactions.length
    }));
    const workbook = XLSX.utils.book_new();
    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    XLSX.utils.book_append_sheet(workbook, worksheet, "Inventory");
    XLSX.writeFile(workbook, `BasisLabs_Inventory_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleAddItem = (item: InventoryItem) => {
    if (items.some(i => i.batchNo === item.batchNo)) {
      alert("Error: Batch Number must be unique.");
      return;
    }
    setItems([...items, item]);
    setView('dashboard');
  };

  const handleUpdateItem = (updatedItem: InventoryItem) => {
    setItems(items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i));
    setView('dashboard');
    setSelectedItem(null);
  };

  const handleRecordUsage = (batchNo: string, transaction: Transaction) => {
    setItems(prevItems => prevItems.map(item => {
      if (item.batchNo === batchNo) {
        const newQuantity = item.quantity - transaction.amount;
        if (newQuantity < 0) {
          alert("Insufficient quantity available!");
          return item;
        }
        return {
          ...item,
          quantity: newQuantity,
          transactions: [transaction, ...item.transactions]
        };
      }
      return item;
    }));
  };

  const handleAddRequest = (request: MaterialRequest) => {
    setRequests([request, ...requests]);
  };

  const filteredItems = items.filter(item => 
    item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.batchNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vendorName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col sticky top-0 h-screen overflow-y-auto">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <img 
              src={LOGO_URL} 
              alt="Basis Laboratories Logo" 
              className="w-10 h-10 rounded-lg shadow-sm border border-slate-700 bg-white"
            />
            <div className="flex flex-col">
              <span className="text-lg font-bold tracking-tight leading-none">Basis</span>
              <span className="text-xs text-slate-400 font-medium tracking-wide uppercase">Laboratories</span>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => setView('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'dashboard' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <TableCellsIcon className="w-5 h-5" />
              Inventory
            </button>
            <button 
              onClick={() => setView('add')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'add' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <PlusIcon className="w-5 h-5" />
              Add Stock
            </button>
            <button 
              onClick={() => setView('requests')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'requests' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <ClipboardDocumentCheckIcon className="w-5 h-5" />
              Material Requests
            </button>
            <button 
              onClick={() => setView('ai-insights')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'ai-insights' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <LightBulbIcon className="w-5 h-5" />
              AI Insights
            </button>
          </nav>
        </div>

        {/* Sync Status Sidebar Widget */}
        <div className="mt-auto p-4 m-4 bg-slate-800 rounded-xl border border-slate-700">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] uppercase font-bold text-slate-400">Excel Online Sync</span>
            {isSyncing ? (
              <ArrowPathIcon className="w-3 h-3 text-teal-400 animate-spin" />
            ) : (
              <CloudArrowUpIcon className="w-3 h-3 text-slate-500" />
            )}
          </div>
          <div className="flex flex-col gap-1">
            <div className="text-xs font-medium flex items-center gap-2">
              <div className={`w-1.5 h-1.5 rounded-full ${excelLink ? 'bg-teal-500 sync-pulse' : 'bg-slate-600'}`}></div>
              {excelLink ? 'Linked & Active' : 'Not Linked'}
            </div>
            {lastSync && (
              <div className="text-[10px] text-slate-500">
                Last updated: {lastSync.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </div>
            )}
            {!excelLink && (
              <button 
                onClick={() => setShowLinkModal(true)}
                className="mt-2 text-[10px] bg-teal-600 hover:bg-teal-700 py-1 rounded text-center transition-colors"
              >
                Setup Linking
              </button>
            )}
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 text-xs text-slate-400">
          v1.0.8 Laboratory MS
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
              {view === 'dashboard' && 'Inventory Dashboard'}
              {view === 'add' && 'Register New Batch'}
              {view === 'edit' && `Editing Batch: ${selectedItem?.batchNo}`}
              {view === 'details' && `Details: ${selectedItem?.chemicalName}`}
              {view === 'ai-insights' && 'AI Inventory Analysis'}
              {view === 'requests' && 'Material Request System'}
            </h1>
          </div>

          <div className="flex items-center gap-3">
            {view === 'dashboard' && (
              <>
                <div className="relative hidden lg:block">
                  <MagnifyingGlassIcon className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Search records..."
                    className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-64 focus:ring-2 focus:ring-teal-500 outline-none transition-all shadow-sm text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={exportToExcel}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-sm text-sm font-medium"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Export Excel
                </button>
                <button 
                  onClick={() => setShowLinkModal(true)}
                  className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm"
                  title="Cloud Sync Settings"
                >
                  <LinkIcon className="w-5 h-5" />
                </button>
              </>
            )}
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable 
                items={filteredItems} 
                onEdit={(item) => {
                  setSelectedItem(item);
                  setView('edit');
                }}
                onView={(item) => {
                  setSelectedItem(item);
                  setView('details');
                }}
              />
            </>
          )}

          {(view === 'add' || view === 'edit') && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <InventoryForm 
                initialData={view === 'edit' ? selectedItem : null}
                onSubmit={view === 'edit' ? handleUpdateItem : handleAddItem}
                onCancel={() => setView('dashboard')}
              />
            </div>
          )}

          {view === 'details' && selectedItem && (
            <ItemDetails 
              item={selectedItem} 
              onBack={() => setView('dashboard')}
              onRecordUsage={(transaction) => handleRecordUsage(selectedItem.batchNo, transaction)}
            />
          )}

          {view === 'requests' && (
            <RequestSystem 
              inventory={items} 
              existingRequests={requests}
              onAddRequest={handleAddRequest}
            />
          )}

          {view === 'ai-insights' && <AIInsights items={items} />}
        </div>
      </main>

      {/* Excel Link Modal */}
      {showLinkModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="bg-emerald-600 p-6 text-white">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                    <CloudArrowUpIcon className="w-6 h-6" />
