import React, { useState } from 'react';
import { InventoryItem, MaterialRequest, RequestType } from '../types';
import { 
  BeakerIcon, 
  AcademicCapIcon, 
  CpuChipIcon, 
  ArrowLeftIcon,
  CheckCircleIcon,
  ClockIcon,
