import React, { useState, useEffect } from 'react';
import { InventoryItem, ChemicalState } from '../types';
import { HashtagIcon } from '@heroicons/react/24/outline';

interface InventoryFormProps {
  initialData?: InventoryItem | null;
  onSubmit: (item: InventoryItem) => void;
  onCancel: () => void;
}

const InventoryForm: React.FC<InventoryFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Omit<InventoryItem, 'transactions'>>({
    batchNo: '',
    vendorName: '',
    vendorQualification: 'New',
    quantity: 0,
    unit: 'kg',
    chemicalName: '',
    description: ChemicalState.SOLID,
    dateOfManufacturing: '',
    dateOfAnalysis: '',
    dateOfRetest: '',
    dateOfExpiry: '',
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseFloat(value) || 0 : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      ...formData,
      transactions: initialData?.transactions || []
    });
  };

  const inputClasses = "w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-slate-900 text-sm focus:ring-teal-500 focus:border-teal-500 block outline-none transition-all";
  const labelClasses = "block mb-2 text-sm font-medium text-slate-700";

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Basic Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Primary Identity</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="md:col-span-1">
              <label className={labelClasses}>Unique Batch No</label>
              <div className="relative">
                <HashtagIcon className="w-4 h-4 absolute left-3 top-3 text-slate-400" />
                <input 
                  name="batchNo" 
                  value={formData.batchNo} 
                  onChange={handleChange} 
                  className={`${inputClasses} pl-9 font-mono font-bold`} 
                  required 
                  disabled={!!initialData}
                  placeholder="e.g. B-2024-X100"
                />
              </div>
            </div>
            <div className="md:col-span-1">
              <label className={labelClasses}>Chemical Name</label>
              <input 
                name="chemicalName" 
                value={formData.chemicalName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="e.g. Sodium Chloride"
              />
            </div>
            <div className="md:col-span-1">
              <label className={labelClasses}>Physical Description</label>
              <select 
                name="description" 
                value={formData.description} 
                onChange={handleChange} 
                className={inputClasses}
              >
                <option value={ChemicalState.SOLID}>Solid</option>
                <option value={ChemicalState.LIQUID}>Liquid</option>
              </select>
            </div>
          </div>
        </div>

        {/* Vendor Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Vendor & Quality</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Vendor Name</label>
              <input 
                name="vendorName" 
                value={formData.vendorName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="Supplier Name"
              />
            </div>
            <div>
              <label className={labelClasses}>Vendor Qualification</label>
              <select 
                name="vendorQualification" 
                value={formData.vendorQualification} 
                onChange={handleChange} 
                className={inputClasses}
                required
              >
                <option value="Qualified">Qualified</option>
                <option value="New">New</option>
              </select>
            </div>
          </div>
        </div>

        {/* Quantity */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Stock Details</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Quantity</label>
              <input 
                type="number" 
                step="0.01" 
                name="quantity" 
                value={formData.quantity} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
              />
            </div>
            <div>
              <label className={labelClasses}>Unit</label>
              <input 
                name="unit" 
                value={formData.unit} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="kg, L, etc."
              />
            </div>
          </div>
        </div>

        {/* Dates */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Date Schedule</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div>
              <label className={labelClasses}>Manufacturing Date</label>
              <input type="date" name="dateOfManufacturing" value={formData.dateOfManufacturing} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Analysis Date</label>
              <input type="date" name="dateOfAnalysis" value={formData.dateOfAnalysis} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Retest Date</label>
              <input type="date" name="dateOfRetest" value={formData.dateOfRetest} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Expiry Date</label>
              <input type="date" name="dateOfExpiry" value={formData.dateOfExpiry} onChange={handleChange} className={inputClasses} required />
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-6 border-t">
        <button 
          type="button" 
          onClick={onCancel}
          className="px-6 py-2.5 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors"
        >
          Cancel
        </button>
        <button 
          type="submit"
          className="px-6 py-2.5 text-sm font-medium text-white bg-teal-600 rounded-lg hover:bg-teal-700 transition-colors shadow-sm"
        >
          {initialData ? 'Update Identity' : 'Save Identity'}
        </button>
      </div>
    </form>
  );
};

export default InventoryForm;

export enum ChemicalState {
  SOLID = 'Solid',
  LIQUID = 'Liquid'
}

export enum BatchStatus {
  QUARANTINE = 'Quarantine',
  APPROVED = 'Approved',
  REJECTED = 'Rejected'
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
}

export interface InventoryItem {
  batchNo: string; // Unique Identifier
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  status: BatchStatus; // New field
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
  dateOfExpiry: string;
  transactions: Transaction[];
}

export type RequestType = 'R&D' | 'QC' | 'Production';

export interface MaterialRequest {
  id: string;
  type: RequestType;
  chemicalName: string;
  batchNo: string;
  quantity: number;
  unit: string;
  requestedBy: string;
  acceptedBy?: string; // New field
  date: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  departmentNotes?: string;
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights' | 'requests';

import React, { useState, useEffect, useCallback } from 'react';
import { 
  PlusIcon, 
  TableCellsIcon, 
  BeakerIcon, 
  ArrowPathIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  PencilSquareIcon,
  EyeIcon,
  ArchiveBoxIcon,
  LightBulbIcon,
  CloudArrowUpIcon,
  LinkIcon,
  ArrowDownTrayIcon,
  DocumentArrowDownIcon,
  ClipboardDocumentCheckIcon,
  BellAlertIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import * as XLSX from 'xlsx';
import { InventoryItem, ViewState, ChemicalState, Transaction, MaterialRequest, BatchStatus } from './types';
import InventoryForm from './components/InventoryForm';
import InventoryTable from './components/InventoryTable';
import ItemDetails from './components/ItemDetails';
import DashboardStats from './components/DashboardStats';
import AIInsights from './components/AIInsights';
import RequestSystem from './components/RequestSystem';

const LOGO_URL = "https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U";

const App: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);
  const [view, setView] = useState('dashboard' as ViewState);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showNotifications, setShowNotifications] = useState(false);

  // Excel Sync State
  const [excelLink, setExcelLink] = useState<string>(localStorage.getItem('basis_labs_excel_link') || '');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showLinkModal, setShowLinkModal] = useState(false);

  useEffect(() => {
    const savedItems = localStorage.getItem('basis_labs_inventory');
    const savedRequests = localStorage.getItem('basis_labs_requests');
    if (savedItems) {
      try { setItems(JSON.parse(savedItems)); } catch (e) { console.error(e); }
    }
    if (savedRequests) {
      try { setRequests(JSON.parse(savedRequests)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('basis_labs_inventory', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('basis_labs_requests', JSON.stringify(requests));
  }, [requests]);

  // Simulated Auto-Sync Every 1 Minute
  useEffect(() => {
    const syncInterval = setInterval(() => {
      if (excelLink) {
        performSync();
      }
    }, 60000); // 60 seconds
    return () => clearInterval(syncInterval);
  }, [excelLink, items]);

  const performSync = async () => {
    setIsSyncing(true);
    await new Promise(resolve => setTimeout(resolve, 2000));
    setLastSync(new Date());
    setIsSyncing(false);
  };

  const downloadBlueprint = () => {
    const headers = [
      'Batch No', 'Vendor Name', 'Vendor Qualification', 'Quantity', 'Unit', 
      'Chemical Name', 'Description (Solid/Liquid)', 'Batch Status', 'Date of Manufacturing', 
      'Date of Analysis', 'Date of Retest', 'Date of Expiry'
    ];
    const exampleData = [{
      'Batch No': 'B-12345',
      'Vendor Name': 'Sigma-Aldrich Pvt Ltd',
      'Vendor Qualification': 'Qualified',
      'Quantity': 100.00,
      'Unit': 'kg',
      'Chemical Name': 'Sodium Hydroxide',
      'Description (Solid/Liquid)': 'Solid',
      'Batch Status': 'Quarantine',
      'Date of Manufacturing': '2024-01-15',
      'Date of Analysis': '2024-01-20',
      'Date of Retest': '2025-01-15',
      'Date of Expiry': '2026-01-15'
    }];
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(exampleData, { header: headers });
    ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length, 15) }));
    XLSX.utils.book_append_sheet(wb, ws, "Inventory_Blueprint");
    XLSX.writeFile(wb, "BasisLabs_Inventory_Blueprint.xlsx");
  };

  const exportToExcel = () => {
    const worksheetData = items.map(item => ({
      'Batch No': item.batchNo,
      'Chemical Name': item.chemicalName,
      'Vendor': item.vendorName,
      'Status': item.status,
      'Qualification': item.vendorQualification,
      'Quantity': item.quantity,
      'Unit': item.unit,
      'Description': item.description,
      'Mfg Date': item.dateOfManufacturing,
      'Analysis Date': item.dateOfAnalysis,
      'Retest Date': item.dateOfRetest,
      'Expiry Date': item.dateOfExpiry,
      'Usage Records': item.transactions.length
    }));
    const workbook = XLSX.utils.book_new();
    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    XLSX.utils.book_append_sheet(workbook, worksheet, "Inventory");
    XLSX.writeFile(workbook, `BasisLabs_Inventory_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleAddItem = (item: InventoryItem) => {
    if (items.some(i => i.batchNo === item.batchNo)) {
      alert("Error: Batch Number must be unique.");
      return;
    }
    setItems([...items, item]);
    setView('dashboard');
  };

  const handleUpdateItem = (updatedItem: InventoryItem) => {
    setItems(items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i));
    setView('dashboard');
    setSelectedItem(null);
  };

  const handleRecordUsage = (batchNo: string, transaction: Transaction) => {
    setItems(prevItems => prevItems.map(item => {
      if (item.batchNo === batchNo) {
        const newQuantity = item.quantity - transaction.amount;
        if (newQuantity < 0) {
          alert("Insufficient quantity available!");
          return item;
        }
        return {
          ...item,
          quantity: newQuantity,
          transactions: [transaction, ...item.transactions]
        };
      }
      return item;
    }));
  };

  const handleAddRequest = (request: MaterialRequest) => {
    setRequests([request, ...requests]);
  };

  const handleUpdateRequest = (updatedReq: MaterialRequest) => {
    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));

    // If approved, automatically record usage if you wish, or keep it separate.
    // Usually, "Approved" means it's ready for handover.
  };

  const lowStockItems = items.filter(i => i.quantity < 5);
  const expiredItems = items.filter(i => new Date(i.dateOfExpiry) < new Date());
  const quarantineItems = items.filter(i => i.status === BatchStatus.QUARANTINE);

  const filteredItems = items.filter(item => 
    item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.batchNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vendorName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col sticky top-0 h-screen overflow-y-auto z-40">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <img 
              src={LOGO_URL} 
              alt="Basis Laboratories Logo" 
              className="w-10 h-10 rounded-lg shadow-sm border border-slate-700 bg-white"
            />
            <div className="flex flex-col">
              <span className="text-lg font-bold tracking-tight leading-none">Basis</span>
              <span className="text-xs text-slate-400 font-medium tracking-wide uppercase">Laboratories</span>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => setView('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'dashboard' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <TableCellsIcon className="w-5 h-5" />
              Inventory
            </button>
            <button 
              onClick={() => setView('add')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'add' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <PlusIcon className="w-5 h-5" />
              Add Stock
            </button>
            <button 
              onClick={() => setView('requests')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'requests' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <div className="relative">
                <ClipboardDocumentCheckIcon className="w-5 h-5" />
                {requests.filter(r => r.status === 'Pending').length > 0 && (
                  <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full animate-ping"></span>
                )}
              </div>
              Material Requests
            </button>
            <button 
              onClick={() => setView('ai-insights')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'ai-insights' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <LightBulbIcon className="w-5 h-5" />
              AI Insights
            </button>
          </nav>
        </div>

        {/* Sync Status Sidebar Widget */}
        <div className="mt-auto p-4 m-4 bg-slate-800 rounded-xl border border-slate-700">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] uppercase font-bold text-slate-400">Excel Online Sync</span>
            {isSyncing ? (
              <ArrowPathIcon className="w-3 h-3 text-teal-400 animate-spin" />
            ) : (
              <CloudArrowUpIcon className="w-3 h-3 text-slate-500" />
            )}
          </div>
          <div className="flex flex-col gap-1">
            <div className="text-xs font-medium flex items-center gap-2">
              <div className={`w-1.5 h-1.5 rounded-full ${excelLink ? 'bg-teal-500 sync-pulse' : 'bg-slate-600'}`}></div>
              {excelLink ? 'Linked & Active' : 'Not Linked'}
            </div>
            {lastSync && (
              <div className="text-[10px] text-slate-500">
                Last updated: {lastSync.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </div>
            )}
            {!excelLink && (
              <button 
                onClick={() => setShowLinkModal(true)}
                className="mt-2 text-[10px] bg-teal-600 hover:bg-teal-700 py-1 rounded text-center transition-colors"
              >
                Setup Linking
              </button>
            )}
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 text-xs text-slate-400">
          v1.0.9 Laboratory MS
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 bg-slate-50/80 backdrop-blur-md z-30 py-4 -mt-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
              {view === 'dashboard' && 'Inventory Dashboard'}
              {view === 'add' && 'Register New Batch'}
              {view === 'edit' && `Editing Batch: ${selectedItem?.batchNo}`}
              {view === 'details' && `Details: ${selectedItem?.chemicalName}`}
              {view === 'ai-insights' && 'AI Inventory Analysis'}
              {view === 'requests' && 'Material Request System'}
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative">
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm relative"
                title="System Notifications"
              >
                <BellAlertIcon className="w-5 h-5" />
                {(lowStockItems.length + expiredItems.length + quarantineItems.length) > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[8px] font-bold px-1 rounded-full border border-white">
                    {lowStockItems.length + expiredItems.length + quarantineItems.length}
                  </span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-2 w-80 bg-white border border-slate-200 rounded-xl shadow-xl z-50 max-h-96 overflow-y-auto p-4">
                  <div className="flex justify-between items-center mb-3 pb-2 border-b border-slate-100">
                    <h4 className="font-bold text-slate-800 text-sm">Action Required</h4>
                    <button onClick={() => setShowNotifications(false)} className="text-slate-400 hover:text-slate-600">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>
                  <div className="space-y-3">
                    {lowStockItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-amber-50 border border-amber-100 rounded-lg text-xs">
                        <div className="font-bold text-amber-800">Low Stock Alert: {item.batchNo}</div>
                        <div className="text-amber-700">Chemical: {item.chemicalName}</div>
                        <div className="text-amber-600 font-semibold">Remaining: {item.quantity} {item.unit}</div>
                      </div>
                    ))}
                    {expiredItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-red-50 border border-red-100 rounded-lg text-xs">
                        <div className="font-bold text-red-800">Batch Expired: {item.batchNo}</div>
                        <div className="text-red-700">Expiry: {item.dateOfExpiry}</div>
                      </div>
                    ))}
                    {quarantineItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-blue-50 border border-blue-100 rounded-lg text-xs">
                        <div className="font-bold text-blue-800">In Quarantine: {item.batchNo}</div>
                        <div className="text-blue-700">Needs testing/approval.</div>
                      </div>
                    ))}
                    {lowStockItems.length === 0 && expiredItems.length === 0 && quarantineItems.length === 0 && (
                      <div className="text-center py-4 text-slate-400 text-xs">
                        All systems normal. No pending alerts.
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>

            {view === 'dashboard' && (
              <>
                <div className="relative hidden lg:block">
                  <MagnifyingGlassIcon className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Search records..."
                    className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-64 focus:ring-2 focus:ring-teal-500 outline-none transition-all shadow-sm text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={exportToExcel}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-sm text-sm font-medium"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Export Excel
                </button>
                <button 
                  onClick={() => setShowLinkModal(true)}
                  className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm"
                  title="Cloud Sync Settings"
                >
                  <LinkIcon className="w-5 h-5" />
                </button>
              </>
            )}
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable 
                items={filteredItems} 
                onEdit={(item) => {
                  setSelectedItem(item);
                  setView('edit');
                }}
                onView={(item) => {
                  setSelectedItem(item);
                  setView('details');
                }}
              />
            </>
          )}

          {(view === 'add' || view === 'edit') && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <InventoryForm 
                initialData={view === 'edit' ? selectedItem : null}
                onSubmit={view === 'edit' ? handleUpdateItem : handleAddItem}
                onCancel={() => setView('dashboard')}
              />
            </div>
          )}

          {view === 'details' && selectedItem && (
            <ItemDetails 
              item={selectedItem} 
              onBack={() => setView('dashboard')}
              onRecordUsage={(transaction) => handleRecordUsage(selectedItem.batchNo, transaction)}
              requests={requests.filter(r => r.batchNo === selectedItem.batchNo)}
            />
          )}

          {view === 'requests' && (
            <RequestSystem 
              inventory={items} 
              existingRequests={requests}
              onAddRequest={handleAddRequest}
              onUpdateRequest={handleUpdateRequest}
            />
          )}

          {view === 'ai-insights' && <AIInsights items={items} />}
        </div>
      </main>

      {/* Excel Link Modal */}
      {showLinkModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="bg-emerald-600 p-6 text-white">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                    <CloudArrowUpIcon className="w-6 h-6" />
                  </div>
                  <h3 className="text-xl font-bold">Link Excel Online</h3>
                </div>
                <button 
                  onClick={downloadBlueprint}
                  className="flex items-center gap-2 px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded-lg text-xs font-semibold transition-all"
                  title="Download correct format blueprint"
                >
                  <DocumentArrowDownIcon className="w-4 h-4" />
                  Download Blueprint
                </button>
              </div>
              <p className="text-emerald-100 text-sm">
                Connect your laboratory records to a cloud spreadsheet for live reporting.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Excel Webhook or Share URL</label>
                <div className="relative">
                  <LinkIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="url" 
                    placeholder="https://onedrive.live.com/..."
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    value={excelLink}
                    onChange={(e) => setExcelLink(e.target.value)}
                  />
                </div>
                <p className="mt-2 text-xs text-slate-500 leading-relaxed">
                  Tip: Use a Microsoft Power Automate Webhook or a public OneDrive share link. 
                </p>
              </div>
              <div className="bg-amber-50 border border-amber-100 p-3 rounded-lg flex gap-3">
                <LightBulbIcon className="w-5 h-5 text-amber-600 flex-shrink-0" />
                <p className="text-[11px] text-amber-800">
                  Ensure your Excel file columns match the <strong>Blueprint</strong> exactly to ensure synchronization works correctly.
                </p>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => {
                    localStorage.removeItem('basis_labs_excel_link');
                    setExcelLink('');
                    setShowLinkModal(false);
                  }}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Unlink Sheet
                </button>
                <button 
                  onClick={() => {
                    localStorage.setItem('basis_labs_excel_link', excelLink);
                    setShowLinkModal(false);
                    performSync();
                  }}
                  className="flex-1 py-3 text-sm font-medium text-white bg-emerald-600 rounded-xl hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all"
                >
                  Save & Sync Now
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { InventoryItem, ChemicalState, BatchStatus } from '../types';
import { HashtagIcon } from '@heroicons/react/24/outline';

interface InventoryFormProps {
  initialData?: InventoryItem | null;
  onSubmit: (item: InventoryItem) => void;
  onCancel: () => void;
}

const InventoryForm: React.FC<InventoryFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Omit<InventoryItem, 'transactions'>>({
    batchNo: '',
    vendorName: '',
    vendorQualification: 'New',
    quantity: 0,
    unit: 'kg',
    chemicalName: '',
    description: ChemicalState.SOLID,
    status: BatchStatus.QUARANTINE,
    dateOfManufacturing: '',
    dateOfAnalysis: '',
    dateOfRetest: '',
    dateOfExpiry: '',
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseFloat(value) || 0 : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      ...formData,
      transactions: initialData?.transactions || []
    });
  };

  const inputClasses = "w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-slate-900 text-sm focus:ring-teal-500 focus:border-teal-500 block outline-none transition-all";
  const labelClasses = "block mb-2 text-sm font-medium text-slate-700";

  return (
    <form onSubmit={handleSubmit} className="space-y-6 text-left">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Basic Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Primary Identity</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="md:col-span-1">
              <label className={labelClasses}>Unique Batch No</label>
              <div className="relative">
                <HashtagIcon className="w-4 h-4 absolute left-3 top-3 text-slate-400" />
                <input 
                  name="batchNo" 
                  value={formData.batchNo} 
                  onChange={handleChange} 
                  className={`${inputClasses} pl-9 font-mono font-bold`} 
                  required 
                  disabled={!!initialData}
                  placeholder="e.g. B-2024-X100"
                />
              </div>
            </div>
            <div className="md:col-span-1">
              <label className={labelClasses}>Chemical Name</label>
              <input 
                name="chemicalName" 
                value={formData.chemicalName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="e.g. Sodium Chloride"
              />
            </div>
            <div className="md:col-span-1">
              <label className={labelClasses}>Physical Description</label>
              <select 
                name="description" 
                value={formData.description} 
                onChange={handleChange} 
                className={inputClasses}
              >
                <option value={ChemicalState.SOLID}>Solid</option>
                <option value={ChemicalState.LIQUID}>Liquid</option>
              </select>
            </div>
          </div>
        </div>

        {/* Batch Status */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Batch Status Control</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Release Status</label>
              <select 
                name="status" 
                value={formData.status} 
                onChange={handleChange} 
                className={`${inputClasses} font-bold ${
                  formData.status === BatchStatus.APPROVED ? 'text-green-600 bg-green-50' : 
                  formData.status === BatchStatus.REJECTED ? 'text-red-600 bg-red-50' : 
                  'text-amber-600 bg-amber-50'
                }`}
                required
              >
                <option value={BatchStatus.QUARANTINE}>Quarantine (In Analysis)</option>
                <option value={BatchStatus.APPROVED}>Approved (Released)</option>
                <option value={BatchStatus.REJECTED}>Rejected (Failed)</option>
              </select>
            </div>
            <div className="flex items-center text-xs text-slate-500 italic mt-6">
              * Approved status allows production and QC release. Rejected batches should be investigated.
            </div>
          </div>
        </div>

        {/* Vendor Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Vendor & Quality</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Vendor Name</label>
              <input 
                name="vendorName" 
                value={formData.vendorName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="Supplier Name"
              />
            </div>
            <div>
              <label className={labelClasses}>Vendor Qualification</label>
              <select 
                name="vendorQualification" 
                value={formData.vendorQualification} 
                onChange={handleChange} 
                className={inputClasses}
                required
              >
                <option value="Qualified">Qualified</option>
                <option value="New">New</option>
              </select>
            </div>
          </div>
        </div>

        {/* Quantity */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Stock Details</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Quantity</label>
              <input 
                type="number" 
                step="0.01" 
                name="quantity" 
                value={formData.quantity} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
              />
            </div>
            <div>
              <label className={labelClasses}>Unit</label>
              <input 
                name="unit" 
                value={formData.unit} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="kg, L, etc."
              />
            </div>
          </div>
        </div>

        {/* Dates */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Date Schedule</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div>
              <label className={labelClasses}>Manufacturing Date</label>
              <input type="date" name="dateOfManufacturing" value={formData.dateOfManufacturing} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Analysis Date</label>
              <input type="date" name="dateOfAnalysis" value={formData.dateOfAnalysis} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Retest Date</label>
              <input type="date" name="dateOfRetest" value={formData.dateOfRetest} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Expiry Date</label>
              <input type="date" name="dateOfExpiry" value={formData.dateOfExpiry} onChange={handleChange} className={inputClasses} required />
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-6 border-t">
        <button 
          type="button" 
          onClick={onCancel}
          className="px-6 py-2.5 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors"
        >
          Cancel
        </button>
        <button 
          type="submit"
          className="px-6 py-2.5 text-sm font-medium text-white bg-teal-600 rounded-lg hover:bg-teal-700 transition-colors shadow-sm"
        >
          {initialData ? 'Update Identity' : 'Save Identity'}
        </button>
      </div>
    </form>
  );
};

export default InventoryForm;

import React from 'react';
import { InventoryItem, ChemicalState, BatchStatus } from '../types';
import { PencilSquareIcon, EyeIcon, BeakerIcon, ArchiveBoxIcon, HashtagIcon, ExclamationCircleIcon } from '@heroicons/react/24/outline';

interface InventoryTableProps {
  items: InventoryItem[];
  onEdit: (item: InventoryItem) => void;
  onView: (item: InventoryItem) => void;
}

const InventoryTable: React.FC<InventoryTableProps> = ({ items, onEdit, onView }) => {
  if (items.length === 0) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 p-12 text-center">
        <ArchiveBoxIcon className="w-12 h-12 text-slate-300 mx-auto mb-4" />
        <h3 className="text-lg font-medium text-slate-600">No inventory items found</h3>
        <p className="text-slate-400">Try adjusting your search or add a new unique batch.</p>
      </div>
    );
  }

  const getStatusStyle = (status: BatchStatus) => {
    switch (status) {
      case BatchStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case BatchStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      case BatchStatus.QUARANTINE: return 'bg-amber-100 text-amber-700 border-amber-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 border-b border-slate-200 text-slate-600 uppercase text-xs font-semibold">
            <tr>
              <th className="px-6 py-4">Unique Batch No</th>
              <th className="px-6 py-4">Chemical Name</th>
              <th className="px-6 py-4">Quantity</th>
              <th className="px-6 py-4">Batch Status</th>
              <th className="px-6 py-4">Expiry Date</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200">
            {items.map((item) => {
              const isExpired = new Date(item.dateOfExpiry) < new Date();
              const isLowStock = item.quantity < 5; // Arbitrary low stock threshold

              return (
                <tr key={item.batchNo} className={`hover:bg-slate-50 transition-colors ${isLowStock ? 'bg-amber-50/30' : ''}`}>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg text-slate-600">
                        <HashtagIcon className="w-5 h-5" />
                      </div>
                      <div className="font-mono font-bold text-slate-900 leading-none">
                        {item.batchNo}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${item.description === ChemicalState.SOLID ? 'bg-amber-400' : 'bg-blue-400'}`}></div>
                      <div className="font-semibold text-slate-700">{item.chemicalName}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`font-medium ${isLowStock ? 'text-red-600 font-bold' : 'text-slate-700'}`}>
                        {item.quantity} {item.unit}
                      </div>
                      {isLowStock && (
                        <div className="relative group">
                          <ExclamationCircleIcon className="w-4 h-4 text-red-500 animate-pulse" />
                          <div className="absolute left-full ml-2 hidden group-hover:block bg-red-600 text-white text-[10px] px-2 py-1 rounded whitespace-nowrap z-10">
                            CRITICAL LOW STOCK
                          </div>
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase border ${getStatusStyle(item.status)}`}>
                      {item.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className={isExpired ? 'text-red-600 font-semibold' : 'text-slate-600'}>
                      {item.dateOfExpiry}
                    </div>
                    {isExpired && <span className="text-[10px] uppercase font-bold text-red-500">Expired</span>}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => onView(item)}
                        className="p-1.5 text-slate-400 hover:text-teal-600 transition-colors"
                        title="View Full Details & Requests"
                      >
                        <EyeIcon className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => onEdit(item)}
                        className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors"
                        title="Edit Batch Profile"
                      >
                        <PencilSquareIcon className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default InventoryTable;

import React, { useState } from 'react';
import { InventoryItem, MaterialRequest, RequestType, BatchStatus } from '../types';
import { 
  BeakerIcon, 
  AcademicCapIcon, 
  CpuChipIcon, 
  ArrowLeftIcon,
  CheckCircleIcon,
  ClockIcon,
  UserIcon,
  InformationCircleIcon,
  HashtagIcon,
  XCircleIcon
} from '@heroicons/react/24/outline';

interface RequestSystemProps {
  inventory: InventoryItem[];
  existingRequests: MaterialRequest[];
  onAddRequest: (request: MaterialRequest) => void;
  onUpdateRequest: (request: MaterialRequest) => void;
}

const RequestSystem: React.FC<RequestSystemProps> = ({ inventory, existingRequests, onAddRequest, onUpdateRequest }) => {
  const [selectedType, setSelectedType] = useState<RequestType | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showApprovalModal, setShowApprovalModal] = useState<MaterialRequest | null>(null);
  const [acceptingPerson, setAcceptingPerson] = useState('');

  const [formData, setFormData] = useState({
    batchNo: '',
    quantity: 0,
    requestedBy: '',
    notes: ''
  });

  const handleTypeSelect = (type: RequestType) => {
    setSelectedType(type);
    setFormData({ batchNo: '', quantity: 0, requestedBy: '', notes: '' });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedType) return;

    const selectedItem = inventory.find(i => i.batchNo === formData.batchNo);
    if (!selectedItem) {
      alert("Please select a valid Unique Batch No.");
      return;
    }

    if (selectedItem.status === BatchStatus.REJECTED) {
      alert("This batch is REJECTED and cannot be requested for use.");
      return;
    }

    const newRequest: MaterialRequest = {
      id: Math.random().toString(36).substr(2, 9),
      type: selectedType,
      batchNo: formData.batchNo,
      chemicalName: selectedItem.chemicalName,
      quantity: formData.quantity,
      unit: selectedItem.unit,
      requestedBy: formData.requestedBy,
      date: new Date().toISOString().split('T')[0],
      status: 'Pending',
      departmentNotes: formData.notes
    };

    onAddRequest(newRequest);
    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      setSelectedType(null);
    }, 1500);
  };

  const handleApprove = () => {
    if (!showApprovalModal || !acceptingPerson.trim()) {
      alert("Please enter the accepting person's name.");
      return;
    }

    const updatedRequest: MaterialRequest = {
      ...showApprovalModal,
      status: 'Approved',
      acceptedBy: acceptingPerson
    };

    onUpdateRequest(updatedRequest);
    setShowApprovalModal(null);
    setAcceptingPerson('');
  };

  const handleReject = (req: MaterialRequest) => {
    const updatedRequest: MaterialRequest = {
      ...req,
      status: 'Rejected'
    };
    onUpdateRequest(updatedRequest);
  };

  const departmentConfigs = {
    'R&D': {
      icon: AcademicCapIcon,
      color: 'purple',
      description: 'Request chemicals for new research, prototyping, and experimentation.',
      bg: 'bg-purple-50',
      border: 'border-purple-200',
      text: 'text-purple-700',
      btn: 'bg-purple-600 hover:bg-purple-700'
    },
    'QC': {
      icon: BeakerIcon,
      color: 'amber',
      description: 'Request reference standards or reagents for quality analysis and testing.',
      bg: 'bg-amber-50',
      border: 'border-amber-200',
      text: 'text-amber-700',
      btn: 'bg-amber-600 hover:bg-amber-700'
    },
    'Production': {
      icon: CpuChipIcon,
      color: 'blue',
      description: 'Request bulk raw materials for ongoing manufacturing batches.',
      bg: 'bg-blue-50',
      border: 'border-blue-200',
      text: 'text-blue-700',
      btn: 'bg-blue-600 hover:bg-blue-700'
    }
  };

  if (isSubmitting) {
    return (
      <div className="flex flex-col items-center justify-center py-20 animate-pulse">
        <CheckCircleIcon className="w-20 h-20 text-teal-500 mb-4" />
        <h2 className="text-2xl font-bold text-slate-800">Request Submitted!</h2>
        <p className="text-slate-500">Routing request via Batch No to Material Management...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {!selectedType ? (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {(Object.keys(departmentConfigs) as RequestType[]).map((type) => {
              const config = departmentConfigs[type];
              return (
                <button
                  key={type}
                  onClick={() => handleTypeSelect(type)}
                  className={`flex flex-col items-center p-8 bg-white border ${config.border} rounded-2xl shadow-sm hover:shadow-md transition-all group`}
                >
                  <div className={`p-4 rounded-xl ${config.bg} ${config.text} mb-4 group-hover:scale-110 transition-transform`}>
                    <config.icon className="w-10 h-10" />
                  </div>
                  <h3 className={`text-xl font-bold ${config.text} mb-2`}>{type} Request</h3>
                  <p className="text-sm text-slate-500 text-center leading-relaxed">
                    {config.description}
                  </p>
                  <div className={`mt-6 py-2 px-6 rounded-lg font-semibold text-white ${config.btn} transition-colors`}>
                    Open Form
                  </div>
                </button>
              );
            })}
          </div>

          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <ClockIcon className="w-5 h-5 text-teal-600" />
                Material Requisition History
              </h3>
            </div>
            <div className="overflow-x-auto">
              {existingRequests.length === 0 ? (
                <div className="p-12 text-center text-slate-400">
                  <InformationCircleIcon className="w-10 h-10 mx-auto mb-2 opacity-20" />
                  <p>No material requests placed yet.</p>
                </div>
              ) : (
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                    <tr>
                      <th className="px-6 py-3">Dept</th>
                      <th className="px-6 py-3">Unique Batch No</th>
                      <th className="px-6 py-3">Chemical Name</th>
                      <th className="px-6 py-3">Qty</th>
                      <th className="px-6 py-3">Requested By</th>
                      <th className="px-6 py-3">Accepted By</th>
                      <th className="px-6 py-3">Status</th>
                      <th className="px-6 py-3 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {existingRequests.map((req) => (
                      <tr key={req.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${
                            req.type === 'R&D' ? 'bg-purple-100 text-purple-700' :
                            req.type === 'QC' ? 'bg-amber-100 text-amber-700' :
                            'bg-blue-100 text-blue-700'
                          }`}>
                            {req.type}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <div className="font-mono font-bold text-slate-900">{req.batchNo}</div>
                        </td>
                        <td className="px-6 py-4 text-slate-600">
                          {req.chemicalName}
                        </td>
                        <td className="px-6 py-4 font-semibold">
                          {req.quantity} {req.unit}
                        </td>
                        <td className="px-6 py-4 text-slate-600">{req.requestedBy}</td>
                        <td className="px-6 py-4 text-slate-600 font-medium">
                          {req.acceptedBy || '--'}
                        </td>
                        <td className="px-6 py-4">
                          <span className={`flex items-center gap-1.5 font-bold uppercase text-[10px] ${
                            req.status === 'Approved' ? 'text-green-600' : 
                            req.status === 'Rejected' ? 'text-red-600' : 
                            'text-amber-600 animate-pulse'
                          }`}>
                            {req.status === 'Approved' ? <CheckCircleIcon className="w-4 h-4" /> : 
                             req.status === 'Rejected' ? <XCircleIcon className="w-4 h-4" /> : 
                             <ClockIcon className="w-4 h-4" />}
                            {req.status}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          {req.status === 'Pending' && (
                            <div className="flex justify-end gap-2">
                              <button 
                                onClick={() => setShowApprovalModal(req)}
                                className="px-2 py-1 bg-green-600 text-white rounded text-[10px] font-bold hover:bg-green-700"
                              >
                                Approve
                              </button>
                              <button 
                                onClick={() => handleReject(req)}
                                className="px-2 py-1 bg-red-600 text-white rounded text-[10px] font-bold hover:bg-red-700"
                              >
                                Reject
                              </button>
                            </div>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </div>
        </>
      ) : (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden max-w-2xl mx-auto">
          <div className={`${departmentConfigs[selectedType].bg} p-6 border-b ${departmentConfigs[selectedType].border}`}>
            <button 
              onClick={() => setSelectedType(null)}
              className="flex items-center gap-2 text-slate-600 hover:text-slate-900 transition-colors mb-4 text-sm font-medium"
            >
              <ArrowLeftIcon className="w-4 h-4" />
              Change Request Type
            </button>
            <div className="flex items-center gap-4">
              <div className={`p-3 rounded-xl bg-white ${departmentConfigs[selectedType].text}`}>
                {React.createElement(departmentConfigs[selectedType].icon, { className: "w-8 h-8" })}
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800">{selectedType} Material Requisition</h2>
                <p className="text-slate-500 text-sm">Targeting Unique Batch Numbers for traceability.</p>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="p-8 space-y-6 text-left">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Select Unique ID (Batch No)</label>
                <div className="relative">
                  <HashtagIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <select 
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all appearance-none"
                    value={formData.batchNo}
                    onChange={(e) => setFormData({...formData, batchNo: e.target.value})}
                    required
                  >
                    <option value="">-- Select by Unique Batch No --</option>
                    {inventory.map(item => (
                      <option key={item.batchNo} value={item.batchNo} disabled={item.status === BatchStatus.REJECTED}>
                        {item.batchNo} | {item.chemicalName} {item.status === BatchStatus.REJECTED ? '(REJECTED)' : `(Avail: ${item.quantity} ${item.unit})`}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Quantity Required</label>
                <input 
                  type="number"
                  step="0.01"
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  placeholder="0.00"
                  value={formData.quantity}
                  onChange={(e) => setFormData({...formData, quantity: parseFloat(e.target.value) || 0})}
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Requested By (Staff Name)</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="Enter name"
                    value={formData.requestedBy}
                    onChange={(e) => setFormData({...formData, requestedBy: e.target.value})}
                    required
                  />
                </div>
              </div>

              <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Purpose / Additional Notes</label>
                <textarea 
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all h-24"
                  placeholder="Specific usage details..."
                  value={formData.notes}
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                ></textarea>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                type="button"
                onClick={() => setSelectedType(null)}
                className="flex-1 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-colors"
              >
                Cancel
              </button>
              <button 
                type="submit"
                className={`flex-1 py-3 text-white font-bold rounded-xl shadow-lg transition-all ${departmentConfigs[selectedType].btn}`}
              >
                Submit Request
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Acceptance Name Modal */}
      {showApprovalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="bg-green-600 p-6 text-white">
              <h3 className="text-xl font-bold">Approve Material Requisition</h3>
              <p className="text-green-100 text-sm">Batch: {showApprovalModal.batchNo}</p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Accepting Person Name</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Authorized Staff Name"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-green-500 outline-none transition-all"
                    value={acceptingPerson}
                    onChange={(e) => setAcceptingPerson(e.target.value)}
                  />
                </div>
                <p className="mt-2 text-xs text-slate-500">
                  Verification of physical handover or system release.
                </p>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => setShowApprovalModal(null)}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleApprove}
                  className="flex-1 py-3 text-sm font-medium text-white bg-green-600 rounded-xl hover:bg-green-700 shadow-lg shadow-green-200"
                >
                  Confirm & Approve
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RequestSystem;

export enum ChemicalState {
  SOLID = 'Solid',
  LIQUID = 'Liquid'
}

export enum BatchStatus {
  QUARANTINE = 'Quarantine',
  APPROVED = 'Approved',
  REJECTED = 'Rejected'
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
  requestId?: string; // Link to the request that triggered this deduction
}

export interface InventoryItem {
  batchNo: string; // Unique Identifier
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  status: BatchStatus;
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
  dateOfExpiry: string;
  transactions: Transaction[];
}

export type RequestType = 'R&D' | 'QC' | 'Production';

export interface MaterialRequest {
  id: string;
  type: RequestType;
  chemicalName: string;
  batchNo: string;
  quantity: number;
  unit: string;
  requestedBy: string;
  acceptedBy?: string;
  date: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  departmentNotes?: string;
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights' | 'requests';

import React, { useState, useEffect, useCallback } from 'react';
import { 
  PlusIcon, 
  TableCellsIcon, 
  BeakerIcon, 
  ArrowPathIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  PencilSquareIcon,
  EyeIcon,
  ArchiveBoxIcon,
  LightBulbIcon,
  CloudArrowUpIcon,
  LinkIcon,
  ArrowDownTrayIcon,
  DocumentArrowDownIcon,
  ClipboardDocumentCheckIcon,
  BellAlertIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import * as XLSX from 'xlsx';
import { InventoryItem, ViewState, ChemicalState, Transaction, MaterialRequest, BatchStatus } from './types';
import InventoryForm from './components/InventoryForm';
import InventoryTable from './components/InventoryTable';
import ItemDetails from './components/ItemDetails';
import DashboardStats from './components/DashboardStats';
import AIInsights from './components/AIInsights';
import RequestSystem from './components/RequestSystem';

const LOGO_URL = "https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U";

const App: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);
  const [view, setView] = useState('dashboard' as ViewState);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showNotifications, setShowNotifications] = useState(false);

  // Excel Sync State
  const [excelLink, setExcelLink] = useState<string>(localStorage.getItem('basis_labs_excel_link') || '');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showLinkModal, setShowLinkModal] = useState(false);

  useEffect(() => {
    const savedItems = localStorage.getItem('basis_labs_inventory');
    const savedRequests = localStorage.getItem('basis_labs_requests');
    if (savedItems) {
      try { setItems(JSON.parse(savedItems)); } catch (e) { console.error(e); }
    }
    if (savedRequests) {
      try { setRequests(JSON.parse(savedRequests)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('basis_labs_inventory', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('basis_labs_requests', JSON.stringify(requests));
  }, [requests]);

  // Simulated Auto-Sync Every 1 Minute
  useEffect(() => {
    const syncInterval = setInterval(() => {
      if (excelLink) {
        performSync();
      }
    }, 60000); // 60 seconds
    return () => clearInterval(syncInterval);
  }, [excelLink, items]);

  const performSync = async () => {
    setIsSyncing(true);
    await new Promise(resolve => setTimeout(resolve, 2000));
    setLastSync(new Date());
    setIsSyncing(false);
  };

  const downloadBlueprint = () => {
    const headers = [
      'Batch No', 'Vendor Name', 'Vendor Qualification', 'Quantity', 'Unit', 
      'Chemical Name', 'Description (Solid/Liquid)', 'Batch Status', 'Date of Manufacturing', 
      'Date of Analysis', 'Date of Retest', 'Date of Expiry'
    ];
    const exampleData = [{
      'Batch No': 'B-12345',
      'Vendor Name': 'Sigma-Aldrich Pvt Ltd',
      'Vendor Qualification': 'Qualified',
      'Quantity': 100.00,
      'Unit': 'kg',
      'Chemical Name': 'Sodium Hydroxide',
      'Description (Solid/Liquid)': 'Solid',
      'Batch Status': 'Quarantine',
      'Date of Manufacturing': '2024-01-15',
      'Date of Analysis': '2024-01-20',
      'Date of Retest': '2025-01-15',
      'Date of Expiry': '2026-01-15'
    }];
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(exampleData, { header: headers });
    ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length, 15) }));
    XLSX.utils.book_append_sheet(wb, ws, "Inventory_Blueprint");
    XLSX.writeFile(wb, "BasisLabs_Inventory_Blueprint.xlsx");
  };

  const exportToExcel = () => {
    const worksheetData = items.map(item => ({
      'Batch No': item.batchNo,
      'Chemical Name': item.chemicalName,
      'Vendor': item.vendorName,
      'Status': item.status,
      'Qualification': item.vendorQualification,
      'Quantity': item.quantity,
      'Unit': item.unit,
      'Description': item.description,
      'Mfg Date': item.dateOfManufacturing,
      'Analysis Date': item.dateOfAnalysis,
      'Retest Date': item.dateOfRetest,
      'Expiry Date': item.dateOfExpiry,
      'Usage Records': item.transactions.length
    }));
    const workbook = XLSX.utils.book_new();
    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    XLSX.utils.book_append_sheet(workbook, worksheet, "Inventory");
    XLSX.writeFile(workbook, `BasisLabs_Inventory_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleAddItem = (item: InventoryItem) => {
    if (items.some(i => i.batchNo === item.batchNo)) {
      alert("Error: Batch Number must be unique.");
      return;
    }
    setItems([...items, item]);
    setView('dashboard');
  };

  const handleUpdateItem = (updatedItem: InventoryItem) => {
    setItems(items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i));
    setView('dashboard');
    setSelectedItem(null);
  };

  const handleUpdateRequest = (updatedReq: MaterialRequest) => {
    const prevReq = requests.find(r => r.id === updatedReq.id);

    // Auto-deduct on Approval
    if (updatedReq.status === 'Approved' && prevReq?.status !== 'Approved') {
      const item = items.find(i => i.batchNo === updatedReq.batchNo);
      if (item) {
        if (item.quantity < updatedReq.quantity) {
          alert(`Error: Insufficient stock in Batch ${updatedReq.batchNo}. Request cannot be approved.`);
          return;
        }

        const transaction: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          batchNo: updatedReq.batchNo,
          amount: updatedReq.quantity,
          purpose: `Approved ${updatedReq.type} Request by ${updatedReq.requestedBy}`,
          date: new Date().toISOString().split('T')[0],
          requestId: updatedReq.id
        };

        setItems(prevItems => prevItems.map(i => {
          if (i.batchNo === updatedReq.batchNo) {
            return {
              ...i,
              quantity: i.quantity - updatedReq.quantity,
              transactions: [transaction, ...i.transactions]
            };
          }
          return i;
        }));
      }
    }

    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));
  };

  const handleRevertTransaction = (transactionId: string) => {
    const itemWithTx = items.find(i => i.transactions.some(tx => tx.id === transactionId));
    if (!itemWithTx) return;

    const transaction = itemWithTx.transactions.find(tx => tx.id === transactionId);
    if (!transaction) return;

    if (!confirm(`Are you sure you want to revert this transaction? The quantity (${transaction.amount} ${itemWithTx.unit}) will be added back to Batch ${itemWithTx.batchNo}.`)) {
      return;
    }

    // 1. Restore Inventory Quantity & Remove Transaction
    setItems(prevItems => prevItems.map(i => {
      if (i.batchNo === itemWithTx.batchNo) {
        return {
          ...i,
          quantity: i.quantity + transaction.amount,
          transactions: i.transactions.filter(tx => tx.id !== transactionId)
        };
      }
      return i;
    }));

    // 2. Reset Request status if it was linked
    if (transaction.requestId) {
      setRequests(prevReqs => prevReqs.map(r => {
        if (r.id === transaction.requestId) {
          return {
            ...r,
            status: 'Pending',
            acceptedBy: undefined
          };
        }
        return r;
      }));
    }

    // Refresh selected item if we're looking at details
    if (selectedItem?.batchNo === itemWithTx.batchNo) {
      setSelectedItem(prev => prev ? {
        ...prev,
        quantity: prev.quantity + transaction.amount,
        transactions: prev.transactions.filter(tx => tx.id !== transactionId)
      } : null);
    }
  };

  const lowStockItems = items.filter(i => i.quantity < 5);
  const expiredItems = items.filter(i => new Date(i.dateOfExpiry) < new Date());
  const quarantineItems = items.filter(i => i.status === BatchStatus.QUARANTINE);

  const filteredItems = items.filter(item => 
    item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.batchNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vendorName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col sticky top-0 h-screen overflow-y-auto z-40">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <img 
              src={LOGO_URL} 
              alt="Basis Laboratories Logo" 
              className="w-10 h-10 rounded-lg shadow-sm border border-slate-700 bg-white"
            />
            <div className="flex flex-col">
              <span className="text-lg font-bold tracking-tight leading-none">Basis</span>
              <span className="text-xs text-slate-400 font-medium tracking-wide uppercase">Laboratories</span>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => setView('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'dashboard' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <TableCellsIcon className="w-5 h-5" />
              Inventory
            </button>
            <button 
              onClick={() => setView('add')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'add' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <PlusIcon className="w-5 h-5" />
              Add Stock
            </button>
            <button 
              onClick={() => setView('requests')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'requests' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <div className="relative">
                <ClipboardDocumentCheckIcon className="w-5 h-5" />
                {requests.filter(r => r.status === 'Pending').length > 0 && (
                  <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full animate-ping"></span>
                )}
              </div>
              Material Requests
            </button>
            <button 
              onClick={() => setView('ai-insights')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'ai-insights' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <LightBulbIcon className="w-5 h-5" />
              AI Insights
            </button>
          </nav>
        </div>

        {/* Sync Status Sidebar Widget */}
        <div className="mt-auto p-4 m-4 bg-slate-800 rounded-xl border border-slate-700">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] uppercase font-bold text-slate-400">Excel Online Sync</span>
            {isSyncing ? (
              <ArrowPathIcon className="w-3 h-3 text-teal-400 animate-spin" />
            ) : (
              <CloudArrowUpIcon className="w-3 h-3 text-slate-500" />
            )}
          </div>
          <div className="flex flex-col gap-1">
            <div className="text-xs font-medium flex items-center gap-2">
              <div className={`w-1.5 h-1.5 rounded-full ${excelLink ? 'bg-teal-500 sync-pulse' : 'bg-slate-600'}`}></div>
              {excelLink ? 'Linked & Active' : 'Not Linked'}
            </div>
            {lastSync && (
              <div className="text-[10px] text-slate-500">
                Last updated: {lastSync.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </div>
            )}
            {!excelLink && (
              <button 
                onClick={() => setShowLinkModal(true)}
                className="mt-2 text-[10px] bg-teal-600 hover:bg-teal-700 py-1 rounded text-center transition-colors"
              >
                Setup Linking
              </button>
            )}
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 text-xs text-slate-400">
          v1.1.0 Laboratory MS
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 bg-slate-50/80 backdrop-blur-md z-30 py-4 -mt-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
              {view === 'dashboard' && 'Inventory Dashboard'}
              {view === 'add' && 'Register New Batch'}
              {view === 'edit' && `Editing Batch: ${selectedItem?.batchNo}`}
              {view === 'details' && `Details: ${selectedItem?.chemicalName}`}
              {view === 'ai-insights' && 'AI Inventory Analysis'}
              {view === 'requests' && 'Material Request System'}
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative">
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm relative"
                title="System Notifications"
              >
                <BellAlertIcon className="w-5 h-5" />
                {(lowStockItems.length + expiredItems.length + quarantineItems.length) > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[8px] font-bold px-1 rounded-full border border-white">
                    {lowStockItems.length + expiredItems.length + quarantineItems.length}
                  </span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-2 w-80 bg-white border border-slate-200 rounded-xl shadow-xl z-50 max-h-96 overflow-y-auto p-4">
                  <div className="flex justify-between items-center mb-3 pb-2 border-b border-slate-100">
                    <h4 className="font-bold text-slate-800 text-sm">Action Required</h4>
                    <button onClick={() => setShowNotifications(false)} className="text-slate-400 hover:text-slate-600">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>
                  <div className="space-y-3">
                    {lowStockItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-amber-50 border border-amber-100 rounded-lg text-xs">
                        <div className="font-bold text-amber-800">Low Stock Alert: {item.batchNo}</div>
                        <div className="text-amber-700">Chemical: {item.chemicalName}</div>
                        <div className="text-amber-600 font-semibold">Remaining: {item.quantity} {item.unit}</div>
                      </div>
                    ))}
                    {expiredItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-red-50 border border-red-100 rounded-lg text-xs">
                        <div className="font-bold text-red-800">Batch Expired: {item.batchNo}</div>
                        <div className="text-red-700">Expiry: {item.dateOfExpiry}</div>
                      </div>
                    ))}
                    {quarantineItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-blue-50 border border-blue-100 rounded-lg text-xs">
                        <div className="font-bold text-blue-800">In Quarantine: {item.batchNo}</div>
                        <div className="text-blue-700">Needs testing/approval.</div>
                      </div>
                    ))}
                    {lowStockItems.length === 0 && expiredItems.length === 0 && quarantineItems.length === 0 && (
                      <div className="text-center py-4 text-slate-400 text-xs">
                        All systems normal. No pending alerts.
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>

            {view === 'dashboard' && (
              <>
                <div className="relative hidden lg:block">
                  <MagnifyingGlassIcon className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Search records..."
                    className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-64 focus:ring-2 focus:ring-teal-500 outline-none transition-all shadow-sm text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={exportToExcel}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-sm text-sm font-medium"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Export Excel
                </button>
                <button 
                  onClick={() => setShowLinkModal(true)}
                  className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm"
                  title="Cloud Sync Settings"
                >
                  <LinkIcon className="w-5 h-5" />
                </button>
              </>
            )}
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable 
                items={filteredItems} 
                onEdit={(item) => {
                  setSelectedItem(item);
                  setView('edit');
                }}
                onView={(item) => {
                  setSelectedItem(item);
                  setView('details');
                }}
              />
            </>
          )}

          {(view === 'add' || view === 'edit') && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <InventoryForm 
                initialData={view === 'edit' ? selectedItem : null}
                onSubmit={view === 'edit' ? handleUpdateItem : handleAddItem}
                onCancel={() => setView('dashboard')}
              />
            </div>
          )}

          {view === 'details' && selectedItem && (
            <ItemDetails 
              item={selectedItem} 
              onBack={() => setView('dashboard')}
              onRevert={handleRevertTransaction}
              requests={requests.filter(r => r.batchNo === selectedItem.batchNo)}
            />
          )}

          {view === 'requests' && (
            <RequestSystem 
              inventory={items} 
              existingRequests={requests}
              onAddRequest={handleAddRequest}
              onUpdateRequest={handleUpdateRequest}
            />
          )}

          {view === 'ai-insights' && <AIInsights items={items} />}
        </div>
      </main>

      {/* Excel Link Modal */}
      {showLinkModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="bg-emerald-600 p-6 text-white">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                    <CloudArrowUpIcon className="w-6 h-6" />
                  </div>
                  <h3 className="text-xl font-bold">Link Excel Online</h3>
                </div>
                <button 
                  onClick={downloadBlueprint}
                  className="flex items-center gap-2 px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded-lg text-xs font-semibold transition-all"
                  title="Download correct format blueprint"
                >
                  <DocumentArrowDownIcon className="w-4 h-4" />
                  Download Blueprint
                </button>
              </div>
              <p className="text-emerald-100 text-sm">
                Connect your laboratory records to a cloud spreadsheet for live reporting.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Excel Webhook or Share URL</label>
                <div className="relative">
                  <LinkIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="url" 
                    placeholder="https://onedrive.live.com/..."
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    value={excelLink}
                    onChange={(e) => setExcelLink(e.target.value)}
                  />
                </div>
                <p className="mt-2 text-xs text-slate-500 leading-relaxed">
                  Tip: Use a Microsoft Power Automate Webhook or a public OneDrive share link. 
                </p>
              </div>
              <div className="bg-amber-50 border border-amber-100 p-3 rounded-lg flex gap-3">
                <LightBulbIcon className="w-5 h-5 text-amber-600 flex-shrink-0" />
                <p className="text-[11px] text-amber-800">
                  Ensure your Excel file columns match the <strong>Blueprint</strong> exactly to ensure synchronization works correctly.
                </p>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => {
                    localStorage.removeItem('basis_labs_excel_link');
                    setExcelLink('');
                    setShowLinkModal(false);
                  }}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Unlink Sheet
                </button>
                <button 
                  onClick={() => {
                    localStorage.setItem('basis_labs_excel_link', excelLink);
                    setShowLinkModal(false);
                    performSync();
                  }}
                  className="flex-1 py-3 text-sm font-medium text-white bg-emerald-600 rounded-xl hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all"
                >
                  Save & Sync Now
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  PlusIcon, 
  TableCellsIcon, 
  BeakerIcon, 
  ArrowPathIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  PencilSquareIcon,
  EyeIcon,
  ArchiveBoxIcon,
  LightBulbIcon,
  CloudArrowUpIcon,
  LinkIcon,
  ArrowDownTrayIcon,
  DocumentArrowDownIcon,
  ClipboardDocumentCheckIcon,
  BellAlertIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import * as XLSX from 'xlsx';
import { InventoryItem, ViewState, ChemicalState, Transaction, MaterialRequest, BatchStatus } from './types';
import InventoryForm from './components/InventoryForm';
import InventoryTable from './components/InventoryTable';
import ItemDetails from './components/ItemDetails';
import DashboardStats from './components/DashboardStats';
import AIInsights from './components/AIInsights';
import RequestSystem from './components/RequestSystem';

const LOGO_URL = "https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U";

const App: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);
  const [view, setView] = useState('dashboard' as ViewState);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showNotifications, setShowNotifications] = useState(false);

  // Excel Sync State
  const [excelLink, setExcelLink] = useState<string>(localStorage.getItem('basis_labs_excel_link') || '');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showLinkModal, setShowLinkModal] = useState(false);

  useEffect(() => {
    const savedItems = localStorage.getItem('basis_labs_inventory');
    const savedRequests = localStorage.getItem('basis_labs_requests');
    if (savedItems) {
      try { setItems(JSON.parse(savedItems)); } catch (e) { console.error(e); }
    }
    if (savedRequests) {
      try { setRequests(JSON.parse(savedRequests)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('basis_labs_inventory', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('basis_labs_requests', JSON.stringify(requests));
  }, [requests]);

  // Simulated Auto-Sync Every 1 Minute
  useEffect(() => {
    const syncInterval = setInterval(() => {
      if (excelLink) {
        performSync();
      }
    }, 60000); // 60 seconds
    return () => clearInterval(syncInterval);
  }, [excelLink, items]);

  const performSync = async () => {
    setIsSyncing(true);
    await new Promise(resolve => setTimeout(resolve, 2000));
    setLastSync(new Date());
    setIsSyncing(false);
  };

  const downloadBlueprint = () => {
    const headers = [
      'Batch No', 'Vendor Name', 'Vendor Qualification', 'Quantity', 'Unit', 
      'Chemical Name', 'Description (Solid/Liquid)', 'Batch Status', 'Date of Manufacturing', 
      'Date of Analysis', 'Date of Retest', 'Date of Expiry'
    ];
    const exampleData = [{
      'Batch No': 'B-12345',
      'Vendor Name': 'Sigma-Aldrich Pvt Ltd',
      'Vendor Qualification': 'Qualified',
      'Quantity': 100.00,
      'Unit': 'kg',
      'Chemical Name': 'Sodium Hydroxide',
      'Description (Solid/Liquid)': 'Solid',
      'Batch Status': 'Quarantine',
      'Date of Manufacturing': '2024-01-15',
      'Date of Analysis': '2024-01-20',
      'Date of Retest': '2025-01-15',
      'Date of Expiry': '2026-01-15'
    }];
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(exampleData, { header: headers });
    ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length, 15) }));
    XLSX.utils.book_append_sheet(wb, ws, "Inventory_Blueprint");
    XLSX.writeFile(wb, "BasisLabs_Inventory_Blueprint.xlsx");
  };

  const exportToExcel = () => {
    const worksheetData = items.map(item => ({
      'Batch No': item.batchNo,
      'Chemical Name': item.chemicalName,
      'Vendor': item.vendorName,
      'Status': item.status,
      'Qualification': item.vendorQualification,
      'Quantity': item.quantity,
      'Unit': item.unit,
      'Description': item.description,
      'Mfg Date': item.dateOfManufacturing,
      'Analysis Date': item.dateOfAnalysis,
      'Retest Date': item.dateOfRetest,
      'Expiry Date': item.dateOfExpiry,
      'Usage Records': item.transactions.length
    }));
    const workbook = XLSX.utils.book_new();
    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    XLSX.utils.book_append_sheet(workbook, worksheet, "Inventory");
    XLSX.writeFile(workbook, `BasisLabs_Inventory_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleAddItem = (item: InventoryItem) => {
    if (items.some(i => i.batchNo === item.batchNo)) {
      alert("Error: Batch Number must be unique.");
      return;
    }
    setItems([...items, item]);
    setView('dashboard');
  };

  const handleUpdateItem = (updatedItem: InventoryItem) => {
    setItems(items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i));
    setView('dashboard');
    setSelectedItem(null);
  };

  // Fix: Added missing handleAddRequest function to handle material requisitions
  const handleAddRequest = (request: MaterialRequest) => {
    setRequests(prevRequests => [...prevRequests, request]);
  };

  const handleUpdateRequest = (updatedReq: MaterialRequest) => {
    const prevReq = requests.find(r => r.id === updatedReq.id);

    // Auto-deduct on Approval
    if (updatedReq.status === 'Approved' && prevReq?.status !== 'Approved') {
      const item = items.find(i => i.batchNo === updatedReq.batchNo);
      if (item) {
        if (item.quantity < updatedReq.quantity) {
          alert(`Error: Insufficient stock in Batch ${updatedReq.batchNo}. Request cannot be approved.`);
          return;
        }

        const transaction: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          batchNo: updatedReq.batchNo,
          amount: updatedReq.quantity,
          purpose: `Approved ${updatedReq.type} Request by ${updatedReq.requestedBy}`,
          date: new Date().toISOString().split('T')[0],
          requestId: updatedReq.id
        };

        setItems(prevItems => prevItems.map(i => {
          if (i.batchNo === updatedReq.batchNo) {
            return {
              ...i,
              quantity: i.quantity - updatedReq.quantity,
              transactions: [transaction, ...i.transactions]
            };
          }
          return i;
        }));
      }
    }

    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));
  };

  const handleRevertTransaction = (transactionId: string) => {
    const itemWithTx = items.find(i => i.transactions.some(tx => tx.id === transactionId));
    if (!itemWithTx) return;

    const transaction = itemWithTx.transactions.find(tx => tx.id === transactionId);
    if (!transaction) return;

    if (!confirm(`Are you sure you want to revert this transaction? The quantity (${transaction.amount} ${itemWithTx.unit}) will be added back to Batch ${itemWithTx.batchNo}.`)) {
      return;
    }

    // 1. Restore Inventory Quantity & Remove Transaction
    setItems(prevItems => prevItems.map(i => {
      if (i.batchNo === itemWithTx.batchNo) {
        return {
          ...i,
          quantity: i.quantity + transaction.amount,
          transactions: i.transactions.filter(tx => tx.id !== transactionId)
        };
      }
      return i;
    }));

    // 2. Reset Request status if it was linked
    if (transaction.requestId) {
      setRequests(prevReqs => prevReqs.map(r => {
        if (r.id === transaction.requestId) {
          return {
            ...r,
            status: 'Pending',
            acceptedBy: undefined
          };
        }
        return r;
      }));
    }

    // Refresh selected item if we're looking at details
    if (selectedItem?.batchNo === itemWithTx.batchNo) {
      setSelectedItem(prev => prev ? {
        ...prev,
        quantity: prev.quantity + transaction.amount,
        transactions: prev.transactions.filter(tx => tx.id !== transactionId)
      } : null);
    }
  };

  const lowStockItems = items.filter(i => i.quantity < 5);
  const expiredItems = items.filter(i => new Date(i.dateOfExpiry) < new Date());
  const quarantineItems = items.filter(i => i.status === BatchStatus.QUARANTINE);

  const filteredItems = items.filter(item => 
    item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.batchNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vendorName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col sticky top-0 h-screen overflow-y-auto z-40">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <img 
              src={LOGO_URL} 
              alt="Basis Laboratories Logo" 
              className="w-10 h-10 rounded-lg shadow-sm border border-slate-700 bg-white"
            />
            <div className="flex flex-col">
              <span className="text-lg font-bold tracking-tight leading-none">Basis</span>
              <span className="text-xs text-slate-400 font-medium tracking-wide uppercase">Laboratories</span>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => setView('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'dashboard' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <TableCellsIcon className="w-5 h-5" />
              Inventory
            </button>
            <button 
              onClick={() => setView('add')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'add' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <PlusIcon className="w-5 h-5" />
              Add Stock
            </button>
            <button 
              onClick={() => setView('requests')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'requests' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <div className="relative">
                <ClipboardDocumentCheckIcon className="w-5 h-5" />
                {requests.filter(r => r.status === 'Pending').length > 0 && (
                  <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full animate-ping"></span>
                )}
              </div>
              Material Requests
            </button>
            <button 
              onClick={() => setView('ai-insights')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'ai-insights' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <LightBulbIcon className="w-5 h-5" />
              AI Insights
            </button>
          </nav>
        </div>

        {/* Sync Status Sidebar Widget */}
        <div className="mt-auto p-4 m-4 bg-slate-800 rounded-xl border border-slate-700">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] uppercase font-bold text-slate-400">Excel Online Sync</span>
            {isSyncing ? (
              <ArrowPathIcon className="w-3 h-3 text-teal-400 animate-spin" />
            ) : (
              <CloudArrowUpIcon className="w-3 h-3 text-slate-500" />
            )}
          </div>
          <div className="flex flex-col gap-1">
            <div className="text-xs font-medium flex items-center gap-2">
              <div className={`w-1.5 h-1.5 rounded-full ${excelLink ? 'bg-teal-500 sync-pulse' : 'bg-slate-600'}`}></div>
              {excelLink ? 'Linked & Active' : 'Not Linked'}
            </div>
            {lastSync && (
              <div className="text-[10px] text-slate-500">
                Last updated: {lastSync.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </div>
            )}
            {!excelLink && (
              <button 
                onClick={() => setShowLinkModal(true)}
                className="mt-2 text-[10px] bg-teal-600 hover:bg-teal-700 py-1 rounded text-center transition-colors"
              >
                Setup Linking
              </button>
            )}
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 text-xs text-slate-400">
          v1.1.0 Laboratory MS
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 bg-slate-50/80 backdrop-blur-md z-30 py-4 -mt-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
              {view === 'dashboard' && 'Inventory Dashboard'}
              {view === 'add' && 'Register New Batch'}
              {view === 'edit' && `Editing Batch: ${selectedItem?.batchNo}`}
              {view === 'details' && `Details: ${selectedItem?.chemicalName}`}
              {view === 'ai-insights' && 'AI Inventory Analysis'}
              {view === 'requests' && 'Material Request System'}
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative">
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm relative"
                title="System Notifications"
              >
                <BellAlertIcon className="w-5 h-5" />
                {(lowStockItems.length + expiredItems.length + quarantineItems.length) > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[8px] font-bold px-1 rounded-full border border-white">
                    {lowStockItems.length + expiredItems.length + quarantineItems.length}
                  </span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-2 w-80 bg-white border border-slate-200 rounded-xl shadow-xl z-50 max-h-96 overflow-y-auto p-4">
                  <div className="flex justify-between items-center mb-3 pb-2 border-b border-slate-100">
                    <h4 className="font-bold text-slate-800 text-sm">Action Required</h4>
                    <button onClick={() => setShowNotifications(false)} className="text-slate-400 hover:text-slate-600">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>
                  <div className="space-y-3">
                    {lowStockItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-amber-50 border border-amber-100 rounded-lg text-xs">
                        <div className="font-bold text-amber-800">Low Stock Alert: {item.batchNo}</div>
                        <div className="text-amber-700">Chemical: {item.chemicalName}</div>
                        <div className="text-amber-600 font-semibold">Remaining: {item.quantity} {item.unit}</div>
                      </div>
                    ))}
                    {expiredItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-red-50 border border-red-100 rounded-lg text-xs">
                        <div className="font-bold text-red-800">Batch Expired: {item.batchNo}</div>
                        <div className="text-red-700">Expiry: {item.dateOfExpiry}</div>
                      </div>
                    ))}
                    {quarantineItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-blue-50 border border-blue-100 rounded-lg text-xs">
                        <div className="font-bold text-blue-800">In Quarantine: {item.batchNo}</div>
                        <div className="text-blue-700">Needs testing/approval.</div>
                      </div>
                    ))}
                    {lowStockItems.length === 0 && expiredItems.length === 0 && quarantineItems.length === 0 && (
                      <div className="text-center py-4 text-slate-400 text-xs">
                        All systems normal. No pending alerts.
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>

            {view === 'dashboard' && (
              <>
                <div className="relative hidden lg:block">
                  <MagnifyingGlassIcon className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Search records..."
                    className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-64 focus:ring-2 focus:ring-teal-500 outline-none transition-all shadow-sm text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={exportToExcel}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-sm text-sm font-medium"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Export Excel
                </button>
                <button 
                  onClick={() => setShowLinkModal(true)}
                  className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm"
                  title="Cloud Sync Settings"
                >
                  <LinkIcon className="w-5 h-5" />
                </button>
              </>
            )}
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable 
                items={filteredItems} 
                onEdit={(item) => {
                  setSelectedItem(item);
                  setView('edit');
                }}
                onView={(item) => {
                  setSelectedItem(item);
                  setView('details');
                }}
              />
            </>
          )}

          {(view === 'add' || view === 'edit') && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <InventoryForm 
                initialData={view === 'edit' ? selectedItem : null}
                onSubmit={view === 'edit' ? handleUpdateItem : handleAddItem}
                onCancel={() => setView('dashboard')}
              />
            </div>
          )}

          {view === 'details' && selectedItem && (
            <ItemDetails 
              item={selectedItem} 
              onBack={() => setView('dashboard')}
              onRevert={handleRevertTransaction}
              requests={requests.filter(r => r.batchNo === selectedItem.batchNo)}
            />
          )}

          {view === 'requests' && (
            <RequestSystem 
              inventory={items} 
              existingRequests={requests}
              onAddRequest={handleAddRequest}
              onUpdateRequest={handleUpdateRequest}
            />
          )}

          {view === 'ai-insights' && <AIInsights items={items} />}
        </div>
      </main>

      {/* Excel Link Modal */}
      {showLinkModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="bg-emerald-600 p-6 text-white">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                    <CloudArrowUpIcon className="w-6 h-6" />
                  </div>
                  <h3 className="text-xl font-bold">Link Excel Online</h3>
                </div>
                <button 
                  onClick={downloadBlueprint}
                  className="flex items-center gap-2 px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded-lg text-xs font-semibold transition-all"
                  title="Download correct format blueprint"
                >
                  <DocumentArrowDownIcon className="w-4 h-4" />
                  Download Blueprint
                </button>
              </div>
              <p className="text-emerald-100 text-sm">
                Connect your laboratory records to a cloud spreadsheet for live reporting.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Excel Webhook or Share URL</label>
                <div className="relative">
                  <LinkIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="url" 
                    placeholder="https://onedrive.live.com/..."
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    value={excelLink}
                    onChange={(e) => setExcelLink(e.target.value)}
                  />
                </div>
                <p className="mt-2 text-xs text-slate-500 leading-relaxed">
                  Tip: Use a Microsoft Power Automate Webhook or a public OneDrive share link. 
                </p>
              </div>
              <div className="bg-amber-50 border border-amber-100 p-3 rounded-lg flex gap-3">
                <LightBulbIcon className="w-5 h-5 text-amber-600 flex-shrink-0" />
                <p className="text-[11px] text-amber-800">
                  Ensure your Excel file columns match the <strong>Blueprint</strong> exactly to ensure synchronization works correctly.
                </p>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => {
                    localStorage.removeItem('basis_labs_excel_link');
                    setExcelLink('');
                    setShowLinkModal(false);
                  }}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Unlink Sheet
                </button>
                <button 
                  onClick={() => {
                    localStorage.setItem('basis_labs_excel_link', excelLink);
                    setShowLinkModal(false);
                    performSync();
                  }}
                  className="flex-1 py-3 text-sm font-medium text-white bg-emerald-600 rounded-xl hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition-all"
                >
                  Save & Sync Now
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  PlusIcon, 
  TableCellsIcon, 
  BeakerIcon, 
  ArrowPathIcon, 
  ChartBarIcon, 
  MagnifyingGlassIcon,
  PencilSquareIcon,
  EyeIcon,
  ArchiveBoxIcon,
  LightBulbIcon,
  CloudArrowUpIcon,
  LinkIcon,
  ArrowDownTrayIcon,
  DocumentArrowDownIcon,
  ClipboardDocumentCheckIcon,
  BellAlertIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';
import * as XLSX from 'xlsx';
import { InventoryItem, ViewState, ChemicalState, Transaction, MaterialRequest, BatchStatus } from './types';
import InventoryForm from './components/InventoryForm';
import InventoryTable from './components/InventoryTable';
import ItemDetails from './components/ItemDetails';
import DashboardStats from './components/DashboardStats';
import AIInsights from './components/AIInsights';
import RequestSystem from './components/RequestSystem';

const LOGO_URL = "https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U";

const App: React.FC = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);
  const [view, setView] = useState('dashboard' as ViewState);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [showNotifications, setShowNotifications] = useState(false);

  // Excel Sync State
  const [excelLink, setExcelLink] = useState<string>(localStorage.getItem('basis_labs_excel_link') || '');
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<Date | null>(null);
  const [showLinkModal, setShowLinkModal] = useState(false);

  useEffect(() => {
    const savedItems = localStorage.getItem('basis_labs_inventory');
    const savedRequests = localStorage.getItem('basis_labs_requests');
    if (savedItems) {
      try { setItems(JSON.parse(savedItems)); } catch (e) { console.error(e); }
    }
    if (savedRequests) {
      try { setRequests(JSON.parse(savedRequests)); } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('basis_labs_inventory', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('basis_labs_requests', JSON.stringify(requests));
  }, [requests]);

  // Simulated Auto-Sync Every 1 Minute
  useEffect(() => {
    const syncInterval = setInterval(() => {
      if (excelLink) {
        performSync();
      }
    }, 60000); // 60 seconds
    return () => clearInterval(syncInterval);
  }, [excelLink, items]);

  const performSync = async () => {
    setIsSyncing(true);
    await new Promise(resolve => setTimeout(resolve, 2000));
    setLastSync(new Date());
    setIsSyncing(false);
  };

  const downloadBlueprint = () => {
    const headers = [
      'Batch No', 'Vendor Name', 'Vendor Qualification', 'Quantity', 'Unit', 
      'Chemical Name', 'Description (Solid/Liquid)', 'Batch Status', 'Date of Manufacturing', 
      'Date of Analysis', 'Date of Retest', 'Date of Expiry'
    ];
    const exampleData = [{
      'Batch No': 'B-12345',
      'Vendor Name': 'Sigma-Aldrich Pvt Ltd',
      'Vendor Qualification': 'Qualified',
      'Quantity': 100.00,
      'Unit': 'kg',
      'Chemical Name': 'Sodium Hydroxide',
      'Description (Solid/Liquid)': 'Solid',
      'Batch Status': 'Quarantine',
      'Date of Manufacturing': '2024-01-15',
      'Date of Analysis': '2024-01-20',
      'Date of Retest': '2025-01-15',
      'Date of Expiry': '2026-01-15'
    }];
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(exampleData, { header: headers });
    ws['!cols'] = headers.map(h => ({ wch: Math.max(h.length, 15) }));
    XLSX.utils.book_append_sheet(wb, ws, "Inventory_Blueprint");
    XLSX.writeFile(wb, "BasisLabs_Inventory_Blueprint.xlsx");
  };

  const exportToExcel = () => {
    // Generate accurate timestamp for the report filename
    const now = new Date();
    const formattedDate = now.toLocaleDateString().replace(/\//g, '-');
    const formattedTime = now.toLocaleTimeString().replace(/:/g, '-').replace(/\s/g, '');
    const timestamp = `${formattedDate}_${formattedTime}`;

    // Prepare Inventory Data Sheet
    const inventoryData = items.map(item => ({
      'Batch No': item.batchNo,
      'Chemical Name': item.chemicalName,
      'Vendor': item.vendorName,
      'Status': item.status,
      'Qualification': item.vendorQualification,
      'Quantity': item.quantity,
      'Unit': item.unit,
      'Description': item.description,
      'Mfg Date': item.dateOfManufacturing,
      'Analysis Date': item.dateOfAnalysis,
      'Retest Date': item.dateOfRetest,
      'Expiry Date': item.dateOfExpiry,
      'Total Transactions': item.transactions.length
    }));

    // Prepare Requests Data Sheet
    const requestsData = requests.map(req => ({
      'Request ID': req.id,
      'Department': req.type,
      'Batch No': req.batchNo,
      'Chemical Name': req.chemicalName,
      'Qty Requested': req.quantity,
      'Unit': req.unit,
      'Requested By': req.requestedBy,
      'Accepted By': req.acceptedBy || 'Pending',
      'Status': req.status,
      'Request Date': req.date
    }));

    // Create workbook and append sheets
    const workbook = XLSX.utils.book_new();

    const inventorySheet = XLSX.utils.json_to_sheet(inventoryData);
    XLSX.utils.book_append_sheet(workbook, inventorySheet, "Current Inventory");

    const requestsSheet = XLSX.utils.json_to_sheet(requestsData);
    XLSX.utils.book_append_sheet(workbook, requestsSheet, "Form Requests History");

    // Summary sheet with report meta info
    const summaryData = [
      { 'Report Info': 'Facility', 'Value': 'Basis Laboratories Pvt Ltd' },
      { 'Report Info': 'Export Date', 'Value': now.toLocaleDateString() },
      { 'Report Info': 'Export Time', 'Value': now.toLocaleTimeString() },
      { 'Report Info': 'Total Inventory Batches', 'Value': items.length },
      { 'Report Info': 'Total Requisitions', 'Value': requests.length }
    ];
    const summarySheet = XLSX.utils.json_to_sheet(summaryData);
    XLSX.utils.book_append_sheet(workbook, summarySheet, "Report Summary");

    XLSX.writeFile(workbook, `BasisLabs_Inventory_And_Requests_Report_${timestamp}.xlsx`);
  };

  const handleAddItem = (item: InventoryItem) => {
    if (items.some(i => i.batchNo === item.batchNo)) {
      alert("Error: Batch Number must be unique.");
      return;
    }
    setItems([...items, item]);
    setView('dashboard');
  };

  const handleUpdateItem = (updatedItem: InventoryItem) => {
    setItems(items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i));
    setView('dashboard');
    setSelectedItem(null);
  };

  // handleAddRequest function to handle material requisitions
  const handleAddRequest = (request: MaterialRequest) => {
    setRequests(prevRequests => [...prevRequests, request]);
  };

  const handleUpdateRequest = (updatedReq: MaterialRequest) => {
    const prevReq = requests.find(r => r.id === updatedReq.id);

    // Auto-deduct on Approval
    if (updatedReq.status === 'Approved' && prevReq?.status !== 'Approved') {
      const item = items.find(i => i.batchNo === updatedReq.batchNo);
      if (item) {
        if (item.quantity < updatedReq.quantity) {
          alert(`Error: Insufficient stock in Batch ${updatedReq.batchNo}. Request cannot be approved.`);
          return;
        }

        const transaction: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          batchNo: updatedReq.batchNo,
          amount: updatedReq.quantity,
          purpose: `Approved ${updatedReq.type} Request by ${updatedReq.requestedBy}`,
          date: new Date().toISOString().split('T')[0],
          requestId: updatedReq.id
        };

        setItems(prevItems => prevItems.map(i => {
          if (i.batchNo === updatedReq.batchNo) {
            return {
              ...i,
              quantity: i.quantity - updatedReq.quantity,
              transactions: [transaction, ...i.transactions]
            };
          }
          return i;
        }));
      }
    }

    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));
  };

  const handleRevertTransaction = (transactionId: string) => {
    const itemWithTx = items.find(i => i.transactions.some(tx => tx.id === transactionId));
    if (!itemWithTx) return;

    const transaction = itemWithTx.transactions.find(tx => tx.id === transactionId);
    if (!transaction) return;

    if (!confirm(`Are you sure you want to revert this transaction? The quantity (${transaction.amount} ${itemWithTx.unit}) will be added back to Batch ${itemWithTx.batchNo}.`)) {
      return;
    }

    // 1. Restore Inventory Quantity & Remove Transaction
    setItems(prevItems => prevItems.map(i => {
      if (i.batchNo === itemWithTx.batchNo) {
        return {
          ...i,
          quantity: i.quantity + transaction.amount,
          transactions: i.transactions.filter(tx => tx.id !== transactionId)
        };
      }
      return i;
    }));

    // 2. Reset Request status if it was linked
    if (transaction.requestId) {
      setRequests(prevReqs => prevReqs.map(r => {
        if (r.id === transaction.requestId) {
          return {
            ...r,
            status: 'Pending',
            acceptedBy: undefined
          };
        }
        return r;
      }));
    }

    // Refresh selected item if we're looking at details
    if (selectedItem?.batchNo === itemWithTx.batchNo) {
      setSelectedItem(prev => prev ? {
        ...prev,
        quantity: prev.quantity + transaction.amount,
        transactions: prev.transactions.filter(tx => tx.id !== transactionId)
      } : null);
    }
  };

  const lowStockItems = items.filter(i => i.quantity < 5);
  const expiredItems = items.filter(i => new Date(i.dateOfExpiry) < new Date());
  const quarantineItems = items.filter(i => i.status === BatchStatus.QUARANTINE);

  const filteredItems = items.filter(item => 
    item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.batchNo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.vendorName.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      {/* Sidebar */}
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col sticky top-0 h-screen overflow-y-auto z-40">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <img 
              src={LOGO_URL} 
              alt="Basis Laboratories Logo" 
              className="w-10 h-10 rounded-lg shadow-sm border border-slate-700 bg-white"
            />
            <div className="flex flex-col">
              <span className="text-lg font-bold tracking-tight leading-none">Basis</span>
              <span className="text-xs text-slate-400 font-medium tracking-wide uppercase">Laboratories</span>
            </div>
          </div>

          <nav className="space-y-2">
            <button 
              onClick={() => setView('dashboard')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'dashboard' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <TableCellsIcon className="w-5 h-5" />
              Inventory
            </button>
            <button 
              onClick={() => setView('add')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'add' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <PlusIcon className="w-5 h-5" />
              Add Stock
            </button>
            <button 
              onClick={() => setView('requests')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'requests' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <div className="relative">
                <ClipboardDocumentCheckIcon className="w-5 h-5" />
                {requests.filter(r => r.status === 'Pending').length > 0 && (
                  <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full animate-ping"></span>
                )}
              </div>
              Material Requests
            </button>
            <button 
              onClick={() => setView('ai-insights')}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === 'ai-insights' ? 'bg-teal-600' : 'hover:bg-slate-800'}`}
            >
              <LightBulbIcon className="w-5 h-5" />
              AI Insights
            </button>
          </nav>
        </div>

        {/* Sync Status Sidebar Widget */}
        <div className="mt-auto p-4 m-4 bg-slate-800 rounded-xl border border-slate-700">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[10px] uppercase font-bold text-slate-400">Excel Online Sync</span>
            {isSyncing ? (
              <ArrowPathIcon className="w-3 h-3 text-teal-400 animate-spin" />
            ) : (
              <CloudArrowUpIcon className="w-3 h-3 text-slate-500" />
            )}
          </div>
          <div className="flex flex-col gap-1">
            <div className="text-xs font-medium flex items-center gap-2">
              <div className={`w-1.5 h-1.5 rounded-full ${excelLink ? 'bg-teal-500 sync-pulse' : 'bg-slate-600'}`}></div>
              {excelLink ? 'Linked & Active' : 'Not Linked'}
            </div>
            {lastSync && (
              <div className="text-[10px] text-slate-500">
                Last updated: {lastSync.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </div>
            )}
            {!excelLink && (
              <button 
                onClick={() => setShowLinkModal(true)}
                className="mt-2 text-[10px] bg-teal-600 hover:bg-teal-700 py-1 rounded text-center transition-colors"
              >
                Setup Linking
              </button>
            )}
          </div>
        </div>

        <div className="p-6 border-t border-slate-800 text-xs text-slate-400">
          v1.1.1 Laboratory MS
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 bg-slate-50/80 backdrop-blur-md z-30 py-4 -mt-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">
              {view === 'dashboard' && 'Inventory Dashboard'}
              {view === 'add' && 'Register New Batch'}
              {view === 'edit' && `Editing Batch: ${selectedItem?.batchNo}`}
              {view === 'details' && `Details: ${selectedItem?.chemicalName}`}
              {view === 'ai-insights' && 'AI Inventory Analysis'}
              {view === 'requests' && 'Material Request System'}
            </h1>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative">
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm relative"
                title="System Notifications"
              >
                <BellAlertIcon className="w-5 h-5" />
                {(lowStockItems.length + expiredItems.length + quarantineItems.length) > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-600 text-white text-[8px] font-bold px-1 rounded-full border border-white">
                    {lowStockItems.length + expiredItems.length + quarantineItems.length}
                  </span>
                )}
              </button>

              {showNotifications && (
                <div className="absolute right-0 mt-2 w-80 bg-white border border-slate-200 rounded-xl shadow-xl z-50 max-h-96 overflow-y-auto p-4">
                  <div className="flex justify-between items-center mb-3 pb-2 border-b border-slate-100">
                    <h4 className="font-bold text-slate-800 text-sm">Action Required</h4>
                    <button onClick={() => setShowNotifications(false)} className="text-slate-400 hover:text-slate-600">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>
                  <div className="space-y-3">
                    {lowStockItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-amber-50 border border-amber-100 rounded-lg text-xs">
                        <div className="font-bold text-amber-800">Low Stock Alert: {item.batchNo}</div>
                        <div className="text-amber-700">Chemical: {item.chemicalName}</div>
                        <div className="text-amber-600 font-semibold">Remaining: {item.quantity} {item.unit}</div>
                      </div>
                    ))}
                    {expiredItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-red-50 border border-red-100 rounded-lg text-xs">
                        <div className="font-bold text-red-800">Batch Expired: {item.batchNo}</div>
                        <div className="text-red-700">Expiry: {item.dateOfExpiry}</div>
                      </div>
                    ))}
                    {quarantineItems.map(item => (
                      <div key={item.batchNo} className="p-2 bg-blue-50 border border-blue-100 rounded-lg text-xs">
                        <div className="font-bold text-blue-800">In Quarantine: {item.batchNo}</div>
                        <div className="text-blue-700">Needs testing/approval.</div>
                      </div>
                    ))}
                    {lowStockItems.length === 0 && expiredItems.length === 0 && quarantineItems.length === 0 && (
                      <div className="text-center py-4 text-slate-400 text-xs">
                        All systems normal. No pending alerts.
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>

            {view === 'dashboard' && (
              <>
                <div className="relative hidden lg:block">
                  <MagnifyingGlassIcon className="w-5 h-5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Search records..."
                    className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg w-64 focus:ring-2 focus:ring-teal-500 outline-none transition-all shadow-sm text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>
                <button 
                  onClick={exportToExcel}
                  className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-all shadow-sm text-sm font-medium"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Export Comprehensive Excel
                </button>
                <button 
                  onClick={() => setShowLinkModal(true)}
                  className="p-2 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-600 transition-all shadow-sm"
                  title="Cloud Sync Settings"
                >
                  <LinkIcon className="w-5 h-5" />
                </button>
              </>
            )}
          </div>
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable 
                items={filteredItems} 
                onEdit={(item) => {
                  setSelectedItem(item);
                  setView('edit');
                }}
                onView={(item) => {
                  setSelectedItem(item);
                  setView('details');
                }}
              />
            </>
          )}

          {(view === 'add' || view === 'edit') && (
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <InventoryForm 
                initialData={view === 'edit' ? selectedItem : null}
                onSubmit={view === 'edit' ? handleUpdateItem : handleAddItem}
                onCancel={() => setView('dashboard')}
              />
            </div>
          )}

          {view === 'details' && selectedItem && (
            <ItemDetails 
              item={selectedItem} 
              onBack={() => setView('dashboard')}
              onRevert={handleRevertTransaction}
              requests={requests.filter(r => r.batchNo === selectedItem.batchNo)}
            />
          )}

          {view === 'requests' && (
            <RequestSystem 
              inventory={items} 
              existingRequests={requests}
              onAddRequest={handleAddRequest}
              onUpdateRequest={handleUpdateRequest}
            />
          )}

          {view === 'ai-insights' && <AIInsights items={items} />}
        </div>
      </main>

      {/* Excel Link Modal */}
      {showLinkModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden">
            <div className="bg-emerald-600 p-6 text-white">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                    <CloudArrowUpIcon className="w-6 h-6" />
                  </div>
                  <h3 className="text-xl font-bold">Link Excel Online</h3>
                </div>
                <button 
                  onClick={downloadBlueprint}
                  className="flex items-center gap-2 px-3 py-1.5 bg-white/10 hover:bg-white/20 rounded-lg text-xs font-semibold transition-all"
                  title="Download correct format blueprint"
                >
                  <DocumentArrowDownIcon className="w-4 h-4" />
                  Download Blueprint
                </button>
              </div>
              <p className="text-emerald-100 text-sm">
                Connect your laboratory records to a cloud spreadsheet for live reporting.
              </p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Excel Webhook or Share URL</label>
                <div className="relative">
                  <LinkIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="url" 
                    placeholder="https://onedrive.live.com/..."
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                    value={excelLink}
                    onChange={(e) => setExcelLink(e.target.value)}
                  />
                </div>
                <p className="mt-2 text-xs text-slate-500 leading-relaxed">
                  Tip: Use a Microsoft Power Automate Webhook or a public OneDrive share link. 
                </p>
              </div>
              <div className="bg-amber-50 border border-amber-100 p-3 rounded-lg flex gap-3">
                <LightBulbIcon className="w-5 h-5 text-amber-600 flex-shrink-0" />
                <p className="text-[11px] text-amber-800">
                  Ensure your Excel file columns match the <strong>Blueprint</strong> exactly to ensure synchronization works correctly.
                </p>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => {
                    localStorage.removeItem('basis_labs_excel_link');
                    setExcelLink('');
                    setShowLinkModal(false);
                  }}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200 transition-colors"
                >
                  Unlink Sheet
                </button>
                <button 
                  onClick={() => {
                    localStorage.setItem('basis_labs_excel_link', excelLink);
                    setShowLinkModal(false);
                    performSync();
