import React, { useState } from 'react';
import { ViewState, User } from '../types';
import { 
  EnvelopeIcon, 
  LockClosedIcon, 
  UserIcon, 
  ShieldCheckIcon, 
  CheckCircleIcon,
  ArrowRightIcon,
  ExclamationCircleIcon
} from '@heroicons/react/24/outline';

const LOGO_URL = "https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U";

interface AuthProps {
  view: ViewState;
  setView: (v: ViewState) => void;
  setCurrentUser: (u: User | null) => void;
  currentUser: User | null;
}

const Auth: React.FC<AuthProps> = ({ view, setView, setCurrentUser, currentUser }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const getUsers = (): User[] => {
    const saved = localStorage.getItem('basis_labs_users');
    return saved ? JSON.parse(saved) : [];
  };

  const saveUser = (user: User) => {
    const users = getUsers();
    localStorage.setItem('basis_labs_users', JSON.stringify([...users, user]));
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    setTimeout(() => {
      const users = getUsers();

      if (view === 'login') {
        const user = users.find(u => u.email === formData.email && u.password === formData.password);
        if (user) {
          setCurrentUser(user);
          if (user.isEmailConfirmed) {
            setView('dashboard');
          } else {
            setView('verify');
          }
        } else {
          setError('Invalid email or password.');
        }
      } else {
        // Signup logic
        if (users.some(u => u.email === formData.email)) {
          setError('Email already registered.');
        } else {
          const newUser: User = {
            name: formData.name,
            email: formData.email,
            password: formData.password,
            isEmailConfirmed: false
          };
          saveUser(newUser);
          setCurrentUser(newUser);
          setView('verify');
        }
      }
      setLoading(false);
    }, 1200);
  };

  const handleVerify = () => {
    setLoading(true);
    setTimeout(() => {
      if (currentUser) {
        const users = getUsers();
        const updatedUser = { ...currentUser, isEmailConfirmed: true };
        const updatedUsers = users.map(u => u.email === currentUser.email ? updatedUser : u);

        localStorage.setItem('basis_labs_users', JSON.stringify(updatedUsers));
        setCurrentUser(updatedUser);
        setView('dashboard');
      }
      setLoading(false);
    }, 1500);
  };

  const inputClasses = "w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all";
  const labelClasses = "block text-sm font-semibold text-slate-700 mb-1.5";

  if (view === 'verify') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-teal-50 rounded-full">
              <EnvelopeIcon className="w-12 h-12 text-teal-600 animate-bounce" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Check Your Inbox!</h2>
          <p className="text-slate-500 text-sm leading-relaxed mb-8">
