            Please verify your email to access the inventory system.
          </p>

          <div className="bg-slate-50 border border-slate-100 rounded-xl p-4 mb-8">
            <div className="flex items-center gap-3 text-left">
               <ShieldCheckIcon className="w-6 h-6 text-teal-600 flex-shrink-0" />
               <p className="text-[11px] text-slate-500">
                 For this simulation, click the button below to confirm your account and proceed to the dashboard.
               </p>
            </div>
          </div>

          <button 
            onClick={handleVerify}
            disabled={loading}
            className="w-full py-4 bg-teal-600 hover:bg-teal-700 text-white font-bold rounded-2xl shadow-lg shadow-teal-100 transition-all flex items-center justify-center gap-3 disabled:opacity-50"
          >
            {loading ? (
               <ArrowPathIcon className="w-5 h-5 animate-spin" />
            ) : (
              <>
                Confirm Registration
                <CheckCircleIcon className="w-5 h-5" />
              </>
            )}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4">
      <div className="mb-8 flex flex-col items-center gap-4">
         <img src={LOGO_URL} alt="Logo" className="w-20 h-20 rounded-2xl shadow-2xl bg-white p-1" />
         <div className="text-center">
            <h1 className="text-3xl font-bold text-white tracking-tight">Basis Laboratories</h1>
            <p className="text-slate-400 font-medium uppercase tracking-[0.2em] text-xs mt-1">Inventory Management System</p>
         </div>
      </div>

      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
        <div className="p-8">
          <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
             <h2 className="text-2xl font-bold text-slate-800">
               {view === 'login' ? 'Login' : 'Create Account'}
             </h2>
             <span className="text-xs text-slate-400 font-bold uppercase tracking-widest">Facility Access</span>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {error && (
              <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-700 text-xs font-medium">
                 <ExclamationCircleIcon className="w-5 h-5 flex-shrink-0" />
                 {error}
              </div>
            )}

            {view === 'signup' && (
              <div>
                <label className={labelClasses}>Full Name</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="John Doe"
                    required
                    className={inputClasses}
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                  />
                </div>
              </div>
            )}

            <div>
              <label className={labelClasses}>Gmail Address</label>
              <div className="relative">
                <EnvelopeIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                <input 
                  type="email" 
                  placeholder="name@gmail.com"
                  required
                  className={inputClasses}
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                />
              </div>
            </div>

            <div>
              <label className={labelClasses}>Password</label>
              <div className="relative">
                <LockClosedIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                <input 
                  type="password" 
                  placeholder="••••••••"
                  required
                  className={inputClasses}
                  value={formData.password}
                  onChange={(e) => setFormData({...formData, password: e.target.value})}
                />
              </div>
            </div>

            <button 
              type="submit"
              disabled={loading}
              className="w-full py-4 bg-teal-600 hover:bg-teal-700 text-white font-bold rounded-2xl shadow-lg shadow-teal-100 transition-all flex items-center justify-center gap-3 disabled:opacity-50 mt-4"
            >
              {loading ? (
                <ArrowPathIcon className="w-5 h-5 animate-spin" />
              ) : (
                <>
                  {view === 'login' ? 'Authenticate' : 'Sign Up'}
                  <ArrowRightIcon className="w-5 h-5" />
                </>
              )}
            </button>
          </form>
        </div>

        <div className="p-6 bg-slate-50 border-t border-slate-100 text-center">
           <button 
             onClick={() => { setView(view === 'login' ? 'signup' : 'login'); setError(''); }}
             className="text-sm font-medium text-slate-500 hover:text-teal-600 transition-colors"
           >
             {view === 'login' ? "Don't have an account? Create one" : "Already have an account? Login here"}
           </button>
        </div>
      </div>

      <div className="mt-8 text-slate-500 text-[10px] font-bold uppercase tracking-[0.3em]">
        © 2025 Basis Laboratories Pvt Ltd | Secure Core v1.2
      </div>
    </div>
  );
};

