interface AuthProps {
  view: ViewState;
  setView: (v: ViewState) => void;
  setCurrentUser: (u: User | null) => void;
  currentUser: User | null;
}

const Auth: React.FC<AuthProps> = ({ view, setView, setCurrentUser, currentUser }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: 'user' as UserRole
  });
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [loading, setLoading] = useState(false);

  const getUsers = (): User[] => {
    const saved = localStorage.getItem('basis_labs_users');
    return saved ? JSON.parse(saved) : [];
  };

  const saveUser = (user: User) => {
    const users = getUsers();
    const normalizedUser = { ...user, email: user.email.toLowerCase().trim() };
    const otherUsers = users.filter(u => u.email.toLowerCase().trim() !== normalizedUser.email);
    localStorage.setItem('basis_labs_users', JSON.stringify([...otherUsers, normalizedUser]));
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setLoading(true);

    const email = formData.email.toLowerCase().trim();
    const password = formData.password.trim();
    const selectedRole = formData.role;

    setTimeout(() => {
      const users = getUsers();

      if (view === 'login') {
        const user = users.find(u => 
          u.email.toLowerCase().trim() === email && 
          u.password === password && 
          u.role === selectedRole
        );
        if (user) {
          setCurrentUser(user);
          if (user.isEmailConfirmed) {
            setView('dashboard');
          } else {
            setView('verify');
          }
        } else {
          setError(`Invalid credentials for ${selectedRole.toUpperCase()} login.`);
        }
      } else if (view === 'signup') {
        if (users.some(u => u.email.toLowerCase().trim() === email)) {
          setError('This Gmail is already registered. Please login.');
        } else {
          const newUser: User = {
            name: formData.name.trim(),
            email: email,
            password: password,
            isEmailConfirmed: false,
            role: formData.role
          };
          saveUser(newUser);
          setCurrentUser(newUser);
          setView('verify');
        }
      } else if (view === 'forgot-password') {
        const user = users.find(u => u.email.toLowerCase().trim() === email);
        if (user) {
          setSuccessMsg(`A password reset link has been simulated for ${email}. (System: check developer console for reset logic)`);
          console.log(`%c[SYSTEM SIMULATION]%c Resetting password for: ${email}. User current password is: ${user.password}`, 'color: white; background: #0d9488; padding: 2px 5px; border-radius: 4px;', 'color: inherit');
        } else {
          setError('Account not found with this Gmail address.');
