          u.email.toLowerCase().trim() === currentUser.email.toLowerCase().trim() ? updatedUser : u
        );

        localStorage.setItem('basis_labs_users', JSON.stringify(updatedUsers));
        setCurrentUser(updatedUser);
        setView('dashboard');
