  REJECTED = 'Rejected'
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
  requestId?: string;
}

export interface InventoryItem {
  batchNo: string;
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  status: BatchStatus;
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
