  transactions: Transaction[];
}

export type RequestType = 'R&D' | 'QC' | 'Production';

export interface MaterialRequest {
  id: string;
  type: RequestType;
  chemicalName: string;
  batchNo: string;
  quantity: number;
  unit: string;
  requestedBy: string;
  acceptedBy?: string;
  date: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  departmentNotes?: string;
}

export type UserRole = 'admin' | 'user';

export interface User {
  id: string;
  name: string;
  email: string;
  password?: string;
  isEmailConfirmed: boolean;
  isApproved: boolean; // Admin must approve access
  role: UserRole;
  createdAt: string;
}

export interface AuditLog {
  id: string;
  userId: string;
  userEmail: string;
  userName: string;
  action: 'SIGN_IN' | 'SIGN_UP' | 'INVENTORY_ADD' | 'INVENTORY_UPDATE' | 'REQUEST_CREATE' | 'REQUEST_STATUS_CHANGE' | 'USER_ROLE_CHANGE' | 'USER_APPROVAL';
  details: string;
  timestamp: string;
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights' | 'requests' | 'login' | 'signup' | 'verify' | 'forgot-password' | 'admin-users' | 'admin-logs' | 'pending-approval';

import { InventoryItem, MaterialRequest, User, AuditLog, UserRole } from '../types';

class DatabaseService {
  private getStorage<T>(key: string): T[] {
    const data = localStorage.getItem(`basis_labs_${key}`);
    return data ? JSON.parse(data) : [];
  }

  private setStorage<T>(key: string, data: T[]) {
    localStorage.setItem(`basis_labs_${key}`, JSON.stringify(data));
  }

  // --- Users ---
  getUsers(): User[] {
    return this.getStorage<User>('users');
  }

  saveUser(user: User) {
    const users = this.getUsers();
    const index = users.findIndex(u => u.email === user.email);
    if (index > -1) {
      users[index] = user;
    } else {
      users.push(user);
    }
    this.setStorage('users', users);
  }

  // --- Logs ---
  getLogs(): AuditLog[] {
    return this.getStorage<AuditLog>('logs').sort((a, b) => 
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  async logAction(user: User, action: AuditLog['action'], details: string) {
    const logs = this.getLogs();
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userEmail: user.email,
      userName: user.name,
      action,
      details,
      timestamp: new Date().toISOString()
    };
    logs.push(newLog);
    this.setStorage('logs', logs);
  }

  // --- Inventory ---
  getInventory(): InventoryItem[] {
    return this.getStorage<InventoryItem>('inventory');
  }

  saveInventory(items: InventoryItem[]) {
    this.setStorage('inventory', items);
  }

  // --- Requests ---
  getRequests(): MaterialRequest[] {
    return this.getStorage<MaterialRequest>('requests');
  }

  saveRequests(reqs: MaterialRequest[]) {
    this.setStorage('requests', reqs);
  }
}

export const db = new DatabaseService();

