  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    const savedUser = localStorage.getItem('basis_labs_session');
    if (savedUser) {
      const user = JSON.parse(savedUser);
      setCurrentUser(user);
      if (user.isApproved) setView('dashboard');
      else setView('pending-approval');
    }
  }, []);

  useEffect(() => {
    if (currentUser) localStorage.setItem('basis_labs_session', JSON.stringify(currentUser));
    else localStorage.removeItem('basis_labs_session');
  }, [currentUser]);

  const isAdmin = currentUser?.role === 'admin';

