  const handleUpdateItem = (updatedItem: InventoryItem) => {
    const newItems = items.map(i => i.batchNo === updatedItem.batchNo ? updatedItem : i);
    db.saveInventory(newItems);
    setItems(newItems);
    db.logAction(currentUser!, 'INVENTORY_UPDATE', `Updated batch parameters for ${updatedItem.batchNo}`);
