        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />
              <InventoryTable items={items.filter(i => i.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) || i.batchNo.toLowerCase().includes(searchTerm.toLowerCase()))} onView={(item) => { setSelectedItem(item); setView('details'); }} onEdit={isAdmin ? (item) => { setSelectedItem(item); setView('edit'); } : undefined} />
            </>
          )}

          {(view === 'admin-users' || view === 'admin-logs') && isAdmin && (
            <AdminConsole view={view} currentUser={currentUser} />
          )}

          {view === 'add' && isAdmin && <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200"><InventoryForm onSubmit={handleAddItem} onCancel={() => setView('dashboard')} /></div>}
          {view === 'edit' && isAdmin && selectedItem && <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200"><InventoryForm initialData={selectedItem} onSubmit={handleUpdateItem} onCancel={() => setView('dashboard')} /></div>}
          {view === 'requests' && <RequestSystem inventory={items} existingRequests={requests} isAdmin={isAdmin} onAddRequest={(r) => { const n = [...requests, r]; db.saveRequests(n); setRequests(n); db.logAction(currentUser!, 'REQUEST_CREATE', `Placed ${r.type} request for ${r.batchNo}`); }} onUpdateRequest={(r) => { const n = requests.map(it => it.id === r.id ? r : it); db.saveRequests(n); setRequests(n); db.logAction(currentUser!, 'REQUEST_STATUS_CHANGE', `Updated status of request ${r.id} to ${r.status}`); }} />}
          {view === 'ai-insights' && <AIInsights items={items} />}
          {view === 'details' && selectedItem && <ItemDetails item={selectedItem} isAdmin={isAdmin} onBack={() => setView('dashboard')} onRevert={(id) => { /* Revert Logic */ }} requests={requests.filter(r => r.batchNo === selectedItem.batchNo)} />}
        </div>
      </main>
    </div>
  );
};

