import { InventoryItem, MaterialRequest, User, AuditLog, UserRole } from '../types';

const SUPER_ADMIN_EMAIL = 'tanujrao2006@gmail.com';
const SUPER_ADMIN_PASSWORD = 'NTR@2006';

class DatabaseService {
  constructor() {
    this.seedSuperAdmin();
  }

  private seedSuperAdmin() {
    const users = this.getUsers();
    const existingAdminIndex = users.findIndex(u => u.email.toLowerCase() === SUPER_ADMIN_EMAIL);

    if (existingAdminIndex === -1) {
      const superAdmin: User = {
        id: 'super-admin-001',
        name: 'System Admin',
        email: SUPER_ADMIN_EMAIL,
        password: SUPER_ADMIN_PASSWORD,
        isEmailConfirmed: true,
        isApproved: true,
        role: 'admin',
        createdAt: new Date().toISOString()
      };
      this.saveUser(superAdmin);
    } else {
      // Ensure the super admin always has the correct password and status if already seeded
      const admin = users[existingAdminIndex];
      if (admin.password !== SUPER_ADMIN_PASSWORD || !admin.isApproved || admin.role !== 'admin') {
        admin.password = SUPER_ADMIN_PASSWORD;
        admin.isApproved = true;
        admin.role = 'admin';
        this.saveUser(admin);
      }
    }
  }

  private getStorage<T>(key: string): T[] {
    const data = localStorage.getItem(`basis_labs_${key}`);
    return data ? JSON.parse(data) : [];
  }

  private setStorage<T>(key: string, data: T[]) {
    localStorage.setItem(`basis_labs_${key}`, JSON.stringify(data));
  }

  // --- Users ---
  getUsers(): User[] {
    return this.getStorage<User>('users');
  }

  saveUser(user: User) {
    const users = this.getUsers();
    const index = users.findIndex(u => u.email.toLowerCase() === user.email.toLowerCase());

    // Protection: Cannot change super admin role or approval status via standard save if it violates rules
    if (user.email.toLowerCase() === SUPER_ADMIN_EMAIL) {
      user.role = 'admin';
      user.isApproved = true;
    }

    if (index > -1) {
      users[index] = user;
    } else {
      users.push(user);
    }
    this.setStorage('users', users);
  }

  // --- Logs ---
  getLogs(): AuditLog[] {
    return this.getStorage<AuditLog>('logs').sort((a, b) => 
      new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
    );
  }

  async logAction(user: User, action: AuditLog['action'], details: string) {
    const logs = this.getLogs();
    const newLog: AuditLog = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userEmail: user.email,
      userName: user.name,
      action,
      details,
      timestamp: new Date().toISOString()
    };
    logs.push(newLog);
    this.setStorage('logs', logs);
  }

  // --- Inventory ---
  getInventory(): InventoryItem[] {
    return this.getStorage<InventoryItem>('inventory');
  }

  saveInventory(items: InventoryItem[]) {
    this.setStorage('inventory', items);
  }

  // --- Requests ---
  getRequests(): MaterialRequest[] {
    return this.getStorage<MaterialRequest>('requests');
  }

  saveRequests(reqs: MaterialRequest[]) {
    this.setStorage('requests', reqs);
  }
}

