  const handleUpdateRequestStatus = (updatedReq: MaterialRequest) => {
    // Check if the status changed to Approved to perform the automated deduction
    const previousReq = requests.find(r => r.id === updatedReq.id);

    if (updatedReq.status === 'Approved' && previousReq?.status === 'Pending') {
      const item = items.find(i => i.batchNo === updatedReq.batchNo);
      if (item) {
        if (item.quantity < updatedReq.quantity) {
          alert(`Insufficient stock! ${item.chemicalName} only has ${item.quantity} ${item.unit} available.`);
          return;
        }

        const newTransaction: Transaction = {
          id: `tx-${Math.random().toString(36).substr(2, 9)}`,
          batchNo: updatedReq.batchNo,
          amount: updatedReq.quantity,
          purpose: `${updatedReq.type} Request - ${updatedReq.requestedBy}`,
          date: new Date().toISOString().split('T')[0],
          requestId: updatedReq.id
        };

        const updatedItem = {
          ...item,
          quantity: item.quantity - updatedReq.quantity,
          transactions: [newTransaction, ...item.transactions]
        };

        const newItems = items.map(i => i.batchNo === item.batchNo ? updatedItem : i);
        db.saveInventory(newItems);
        setItems(newItems);
      }
    }

    const n = requests.map(it => it.id === updatedReq.id ? updatedReq : it);
    db.saveRequests(n);
    setRequests(n);
    db.logAction(currentUser!, 'REQUEST_STATUS_CHANGE', `Updated status of request ${updatedReq.id} to ${updatedReq.status}`);
  };

  const handleDownloadExcel = () => {
    const dataToExport = filteredItems.map(item => ({
      'Batch No': item.batchNo,
      'Chemical Name': item.chemicalName,
      'Physical Description': item.description,
      'Vendor Name': item.vendorName,
      'Vendor Qualification': item.vendorQualification,
      'Quantity': item.quantity,
      'Unit': item.unit,
      'Status': item.status,
      'QC Notes': item.statusNotes || '',
      'MFG Date': item.dateOfManufacturing,
      'Analysis Date': item.dateOfAnalysis,
      'Retest Date': item.dateOfRetest,
      'Expiry Date': item.dateOfExpiry
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Inventory");

    const dateStr = new Date().toISOString().split('T')[0];
    const fileName = `Basis_Labs_Inventory_${dateStr}.xlsx`;

    XLSX.writeFile(workbook, fileName);
    db.logAction(currentUser!, 'INVENTORY_UPDATE', `Exported inventory table to Excel (${fileName})`);
  };

  if (!currentUser || !currentUser.isEmailConfirmed || (!currentUser.isApproved && view !== 'pending-approval')) {
    return <Auth view={view} setView={setView} setCurrentUser={setCurrentUser} currentUser={currentUser} />;
  }

  const filteredItems = items.filter(item => {
    const matchesSearch = item.chemicalName.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          item.batchNo.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === 'All' || item.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50">
      <aside className="w-full md:w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col sticky top-0 h-screen z-40">
        <div className="p-6">
          <div className="flex items-center gap-3 mb-8">
            <img src={LOGO_URL} className="w-10 h-10 rounded-lg bg-white p-0.5" alt="logo" />
            <div className="flex flex-col">
              <span className="text-lg font-bold">Basis</span>
              <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Laboratories</span>
            </div>
          </div>

          <nav className="space-y-1">
            <NavItem active={view === 'dashboard'} icon={TableCellsIcon} label="Inventory" onClick={() => setView('dashboard')} />
            {isAdmin && <NavItem active={view === 'add'} icon={PlusIcon} label="Add Batch" onClick={() => setView('add')} />}
            <NavItem active={view === 'requests'} icon={ClipboardDocumentCheckIcon} label="Requests" onClick={() => setView('requests')} />
            <NavItem active={view === 'ai-insights'} icon={LightBulbIcon} label="AI Insights" onClick={() => setView('ai-insights')} />

            {isAdmin && (
              <div className="pt-4 mt-4 border-t border-slate-800 space-y-1">
                <span className="px-4 text-[10px] font-bold text-slate-500 uppercase tracking-tighter">Administration</span>
                <NavItem active={view === 'admin-users'} icon={UserGroupIcon} label="Users Management" onClick={() => setView('admin-users')} />
                <NavItem active={view === 'admin-logs'} icon={DocumentMagnifyingGlassIcon} label="Audit Logs" onClick={() => setView('admin-logs')} />
              </div>
            )}
          </nav>
        </div>

        <div className="mt-auto p-4 m-4 bg-slate-800 rounded-2xl border border-slate-700">
          <div className="flex items-center gap-3 mb-3">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-xs ${isAdmin ? 'bg-teal-500' : 'bg-blue-500'}`}>
              {currentUser.name.charAt(0)}
            </div>
            <div className="flex flex-col overflow-hidden">
              <span className="text-xs font-bold truncate">{currentUser.name}</span>
              <span className="text-[9px] text-slate-400 font-bold uppercase">{currentUser.role} Control</span>
            </div>
          </div>
          <button onClick={() => { setCurrentUser(null); setView('login'); }} className="w-full py-1.5 bg-slate-700 hover:bg-red-900/40 text-[10px] font-bold uppercase rounded transition-all">Sign Out</button>
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen">
        <header className="mb-8 flex justify-between items-center bg-slate-50/80 backdrop-blur-sm sticky top-0 z-30 py-2 -mt-2">
           <h1 className="text-2xl font-bold text-slate-800">
             {view === 'dashboard' ? 'Facility Inventory' : 
              view === 'admin-users' ? 'Staff Authorization' : 
              view === 'admin-logs' ? 'System Audit Trail' : 
              view.replace('-', ' ')}
           </h1>
           {view === 'dashboard' && (
             <div className="relative w-64 hidden lg:block">
               <MagnifyingGlassIcon className="w-4 h-4 absolute left-3 top-3 text-slate-400" />
               <input type="text" placeholder="Search batch or chemical..." className="w-full pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
             </div>
           )}
        </header>

        <div className="max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <>
              <DashboardStats items={items} />

              <div className="mb-6 flex flex-wrap items-center justify-between gap-4 bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                <div className="flex flex-wrap items-center gap-4">
                  <div className="flex items-center gap-2 text-slate-500 mr-2">
                    <FunnelIcon className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-wider">Filter Status:</span>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {(['All', BatchStatus.APPROVED, BatchStatus.QUARANTINE, BatchStatus.REJECTED] as const).map((status) => (
                      <button
                        key={status}
                        onClick={() => setStatusFilter(status)}
                        className={`px-4 py-1.5 rounded-full text-xs font-bold transition-all border ${
                          statusFilter === status 
                          ? 'bg-teal-600 text-white border-teal-600 shadow-md shadow-teal-100' 
                          : 'bg-white text-slate-600 border-slate-200 hover:border-teal-300 hover:bg-teal-50'
                        }`}
                      >
                        {status}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  <button
                    onClick={handleDownloadExcel}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white text-xs font-bold uppercase rounded-xl hover:bg-slate-700 transition-all shadow-lg shadow-slate-200"
                    title="Export current view to Excel"
                  >
                    <ArrowDownTrayIcon className="w-4 h-4" />
                    Export Excel
                  </button>

                  <div className="relative flex-1 min-w-[150px] lg:hidden">
                    <MagnifyingGlassIcon className="w-4 h-4 absolute left-3 top-2.5 text-slate-400" />
                    <input type="text" placeholder="Search..." className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs focus:ring-2 focus:ring-teal-500 outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                  </div>
                </div>
              </div>

              <InventoryTable 
                items={filteredItems} 
                onView={(item) => { setSelectedItem(item); setView('details'); }} 
                onEdit={isAdmin ? (item) => { setSelectedItem(item); setView('edit'); } : undefined} 
              />
            </>
          )}

          {(view === 'admin-users' || view === 'admin-logs') && isAdmin && (
            <AdminConsole view={view} currentUser={currentUser} />
          )}

          {view === 'add' && isAdmin && <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200"><InventoryForm onSubmit={handleAddItem} onCancel={() => setView('dashboard')} /></div>}
          {view === 'edit' && isAdmin && selectedItem && <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200"><InventoryForm initialData={selectedItem} onSubmit={handleUpdateItem} onCancel={() => setView('dashboard')} /></div>}
          {view === 'requests' && <RequestSystem inventory={items} existingRequests={requests} isAdmin={isAdmin} onAddRequest={(r) => { const n = [...requests, r]; db.saveRequests(n); setRequests(n); db.logAction(currentUser!, 'REQUEST_CREATE', `Placed ${r.type} request for ${r.batchNo}`); }} onUpdateRequest={handleUpdateRequestStatus} />}
          {view === 'ai-insights' && <AIInsights items={items} />}
          {view === 'details' && selectedItem && <ItemDetails item={selectedItem} isAdmin={isAdmin} onBack={() => setView('dashboard')} onRevert={(id) => handleRevertTransaction(selectedItem.batchNo, id)} requests={requests.filter(r => r.batchNo === selectedItem.batchNo)} />}
        </div>
      </main>
    </div>
  );
};

const NavItem: React.FC<{ active: boolean; icon: any; label: string; onClick: () => void }> = ({ active, icon: Icon, label, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${active ? 'bg-teal-600 shadow-lg shadow-teal-900/50' : 'hover:bg-slate-800 text-slate-400 hover:text-white'}`}>
    <Icon className="w-5 h-5" />
    <span className="text-sm font-medium">{label}</span>
  </button>
);

export default App;

export enum ChemicalState {
  SOLID = 'Solid',
  LIQUID = 'Liquid'
}

export enum BatchStatus {
  QUARANTINE = 'Quarantine',
  APPROVED = 'Approved',
  REJECTED = 'Rejected'
}

export interface StatusLog {
  id: string;
  from: BatchStatus;
  to: BatchStatus;
  date: string;
  reason?: string;
  changedBy: string;
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
  requestId?: string;
}

export interface InventoryItem {
  batchNo: string;
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  status: BatchStatus;
  statusNotes?: string; 
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
  dateOfExpiry: string;
  transactions: Transaction[];
  statusHistory?: StatusLog[];
}

export type RequestType = 'R&D' | 'QC' | 'Production';

export interface MaterialRequest {
  id: string;
  type: RequestType;
  chemicalName: string;
  batchNo: string;
  quantity: number;
  unit: string;
  requestedBy: string;
  acceptedBy?: string;
  date: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  departmentNotes?: string;
}

export type UserRole = 'admin' | 'user';

export interface User {
  id: string;
  name: string;
  email: string;
  password?: string;
  isEmailConfirmed: boolean;
  isApproved: boolean; // Admin must approve access
  role: UserRole;
  createdAt: string;
}

export interface AuditLog {
  id: string;
  userId: string;
  userEmail: string;
  userName: string;
  action: 'SIGN_IN' | 'SIGN_UP' | 'INVENTORY_ADD' | 'INVENTORY_UPDATE' | 'REQUEST_CREATE' | 'REQUEST_STATUS_CHANGE' | 'USER_ROLE_CHANGE' | 'USER_APPROVAL';
  details: string;
  timestamp: string;
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights' | 'requests' | 'login' | 'signup' | 'verify' | 'forgot-password' | 'admin-users' | 'admin-logs' | 'pending-approval';

