    <span className="text-sm font-medium">{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { InventoryItem, ChemicalState, BatchStatus } from '../types';
import { HashtagIcon, ChatBubbleLeftRightIcon } from '@heroicons/react/24/outline';

interface InventoryFormProps {
  initialData?: InventoryItem | null;
  onSubmit: (item: InventoryItem) => void;
  onCancel: () => void;
}

const InventoryForm: React.FC<InventoryFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Omit<InventoryItem, 'transactions'>>({
    batchNo: '',
    vendorName: '',
    vendorQualification: 'New',
    quantity: 0,
    unit: 'kg',
    chemicalName: '',
    description: ChemicalState.SOLID,
    status: BatchStatus.QUARANTINE,
    statusNotes: '',
    dateOfManufacturing: '',
    dateOfAnalysis: '',
    dateOfRetest: '',
    dateOfExpiry: '',
    statusHistory: [],
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseFloat(value) || 0 : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      ...formData,
      transactions: initialData?.transactions || [],
      statusHistory: initialData?.statusHistory || []
