import React, { useState } from 'react';
import { InventoryItem, MaterialRequest, BatchStatus } from '../types';
import { 
  ArrowLeftIcon, 
  DocumentTextIcon, 
  CalendarDaysIcon, 
  UserIcon, 
  HashtagIcon,
