                      </button>
                    )}
                  </div>
                  {showReschedule && (
                    <div className="mt-2 p-3 bg-slate-50 border border-slate-200 rounded-lg">
                      <input 
                        type="date" 
                        className="w-full text-xs p-2 border border-slate-300 rounded outline-none mb-2"
