export default App;

import React, { useState, useEffect } from 'react';
import { InventoryItem, ChemicalState, BatchStatus } from '../types';
import { HashtagIcon, ChatBubbleLeftRightIcon } from '@heroicons/react/24/outline';

interface InventoryFormProps {
  initialData?: InventoryItem | null;
  onSubmit: (item: InventoryItem) => void;
  onCancel: () => void;
}

const InventoryForm: React.FC<InventoryFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Omit<InventoryItem, 'transactions'>>({
    batchNo: '',
    vendorName: '',
    vendorQualification: 'New',
    quantity: 0,
    unit: 'kg',
    chemicalName: '',
    description: ChemicalState.SOLID,
    status: BatchStatus.QUARANTINE,
    statusNotes: '',
    dateOfManufacturing: '',
    dateOfAnalysis: '',
    dateOfRetest: '',
    dateOfExpiry: '',
    statusHistory: [],
    analysisHistory: [],
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData
      });
    }
  }, [initialData]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'quantity' ? parseFloat(value) || 0 : value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      ...formData,
      transactions: initialData?.transactions || [],
      statusHistory: initialData?.statusHistory || [],
      analysisHistory: initialData?.analysisHistory || []
    } as InventoryItem);
  };

  const inputClasses = "w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg text-slate-900 text-sm focus:ring-teal-500 focus:border-teal-500 block outline-none transition-all";
  const labelClasses = "block mb-2 text-sm font-medium text-slate-700";

  return (
    <form onSubmit={handleSubmit} className="space-y-6 text-left">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Basic Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Primary Identity</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="md:col-span-1">
              <label className={labelClasses}>Unique Batch No</label>
              <div className="relative">
                <HashtagIcon className="w-4 h-4 absolute left-3 top-3 text-slate-400" />
                <input 
                  name="batchNo" 
                  value={formData.batchNo} 
                  onChange={handleChange} 
                  className={`${inputClasses} pl-9 font-mono font-bold`} 
                  required 
                  disabled={!!initialData}
                  placeholder="e.g. B-2024-X100"
                />
              </div>
            </div>
            <div className="md:col-span-1">
              <label className={labelClasses}>Chemical Name</label>
              <input 
                name="chemicalName" 
                value={formData.chemicalName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="e.g. Sodium Chloride"
              />
            </div>
            <div className="md:col-span-1">
              <label className={labelClasses}>Physical Description</label>
              <select 
                name="description" 
                value={formData.description} 
                onChange={handleChange} 
                className={inputClasses}
              >
                <option value={ChemicalState.SOLID}>Solid</option>
                <option value={ChemicalState.LIQUID}>Liquid</option>
              </select>
            </div>
          </div>
        </div>

        {/* Batch Status */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Batch Status Control</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Release Status</label>
              <select 
                name="status" 
                value={formData.status} 
                onChange={handleChange} 
                className={`${inputClasses} font-bold ${
                  formData.status === BatchStatus.APPROVED ? 'text-green-600 bg-green-50' : 
                  formData.status === BatchStatus.REJECTED ? 'text-red-600 bg-red-50' : 
                  'text-amber-600 bg-amber-50'
                }`}
                required
              >
                <option value={BatchStatus.QUARANTINE}>Quarantine (In Analysis)</option>
                <option value={BatchStatus.APPROVED}>Approved (Released)</option>
                <option value={BatchStatus.REJECTED}>Rejected (Failed)</option>
              </select>
            </div>
            <div>
              <label className={labelClasses}>QC Analysis Notes / Reason</label>
              <div className="relative">
                <ChatBubbleLeftRightIcon className="w-4 h-4 absolute left-3 top-3 text-slate-400" />
                <textarea 
                  name="statusNotes" 
                  value={formData.statusNotes || ''} 
                  onChange={handleChange} 
                  rows={2}
                  className={`${inputClasses} pl-9 resize-none`} 
                  placeholder={formData.status === BatchStatus.REJECTED ? "Enter mandatory rejection reason..." : "Enter analytical observations or reason for quarantine..."}
                  required={formData.status === BatchStatus.REJECTED}
                />
              </div>
            </div>
          </div>
        </div>

        {/* Vendor Info */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Vendor & Quality</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Vendor Name</label>
              <input 
                name="vendorName" 
                value={formData.vendorName} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="Supplier Name"
              />
            </div>
            <div>
              <label className={labelClasses}>Vendor Qualification</label>
              <select 
                name="vendorQualification" 
                value={formData.vendorQualification} 
                onChange={handleChange} 
                className={inputClasses}
                required
              >
                <option value="Qualified">Qualified</option>
                <option value="New">New</option>
              </select>
            </div>
          </div>
        </div>

        {/* Quantity */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Stock Details</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className={labelClasses}>Quantity</label>
              <input 
                type="number" 
                step="0.01" 
                name="quantity" 
                value={formData.quantity} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
              />
            </div>
            <div>
              <label className={labelClasses}>Unit</label>
              <input 
                name="unit" 
                value={formData.unit} 
                onChange={handleChange} 
                className={inputClasses} 
                required 
                placeholder="kg, L, etc."
              />
            </div>
          </div>
        </div>

        {/* Dates */}
        <div className="space-y-4 col-span-1 md:col-span-3">
          <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Date Schedule</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div>
              <label className={labelClasses}>Manufacturing Date</label>
              <input type="date" name="dateOfManufacturing" value={formData.dateOfManufacturing} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Analysis Date</label>
              <input type="date" name="dateOfAnalysis" value={formData.dateOfAnalysis} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Retest Date</label>
              <input type="date" name="dateOfRetest" value={formData.dateOfRetest} onChange={handleChange} className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Expiry Date</label>
              <input type="date" name="dateOfExpiry" value={formData.dateOfExpiry} onChange={handleChange} className={inputClasses} required />
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-6 border-t">
        <button 
          type="button" 
          onClick={onCancel}
          className="px-6 py-2.5 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors"
        >
          Cancel
        </button>
        <button 
          type="submit"
          className="px-6 py-2.5 text-sm font-medium text-white bg-teal-600 rounded-lg hover:bg-teal-700 transition-colors shadow-sm"
        >
          {initialData ? 'Update Identity' : 'Save Identity'}
        </button>
      </div>
    </form>
  );
};

export default InventoryForm;

import React, { useState } from 'react';
import { InventoryItem, MaterialRequest, BatchStatus, AnalysisRecord } from '../types';
import { 
  ArrowLeftIcon, 
  DocumentTextIcon, 
  CalendarDaysIcon, 
  UserIcon, 
  HashtagIcon,
  ShieldCheckIcon,
  ClipboardDocumentCheckIcon,
  ArrowPathIcon,
  ChatBubbleLeftRightIcon,
  ClockIcon,
  CheckBadgeIcon,
  BeakerIcon,
  CheckIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';

interface ItemDetailsProps {
  item: InventoryItem;
  onBack: () => void;
  onRevert: (transactionId: string) => void;
  onUpdateItem: (updatedItem: InventoryItem) => void;
  requests: MaterialRequest[];
  isAdmin: boolean;
}

const ItemDetails: React.FC<ItemDetailsProps> = ({ item, onBack, onRevert, onUpdateItem, requests, isAdmin }) => {
  const [showAnalysisForm, setShowAnalysisForm] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');
  const [nextRetestDate, setNextRetestDate] = useState('');
  const [performerName, setPerformerName] = useState('');

  const getStatusColor = (status: BatchStatus) => {
    switch(status) {
      case BatchStatus.APPROVED: return 'text-green-600';
      case BatchStatus.REJECTED: return 'text-red-600';
      default: return 'text-amber-600';
    }
  };

  const getStatusBg = (status: BatchStatus) => {
    switch(status) {
      case BatchStatus.APPROVED: return 'bg-green-50 border-green-100';
      case BatchStatus.REJECTED: return 'bg-red-50 border-red-100';
      default: return 'bg-amber-50 border-amber-100';
    }
  };

  const handleCompleteAnalysis = () => {
    if (!analysisResult || !nextRetestDate || !performerName) {
      alert("Please fill in all analysis fields.");
      return;
    }

    const newRecord: AnalysisRecord = {
      id: `ana-${Date.now()}`,
      analysisDate: item.dateOfRetest, // Retest date becomes the actual analysis date
      result: analysisResult,
      performedBy: performerName,
      nextRetestDate: nextRetestDate
    };

    const updatedItem: InventoryItem = {
      ...item,
      dateOfAnalysis: item.dateOfRetest,
      dateOfRetest: nextRetestDate,
      analysisHistory: [newRecord, ...(item.analysisHistory || [])]
    };

    onUpdateItem(updatedItem);
    setShowAnalysisForm(false);
    setAnalysisResult('');
    setNextRetestDate('');
    setPerformerName('');
    alert("Analysis successfully logged. Dates updated.");
  };

  return (
    <div className="space-y-6">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-slate-600 hover:text-teal-600 transition-colors mb-4"
      >
        <ArrowLeftIcon className="w-4 h-4" />
        Back to Dashboard
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 text-left">
        {/* Profile Card */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 text-teal-600 mb-1">
              <HashtagIcon className="w-4 h-4" />
              <span className="text-xs font-bold uppercase tracking-widest">Unique Identity</span>
            </div>
            <h2 className="text-2xl font-mono font-bold text-slate-900 mb-4">{item.batchNo}</h2>

            <div className="space-y-4 mb-6 pt-4 border-t border-slate-100">
               <div className="flex justify-between items-center">
                  <div>
                    <div className="text-xs text-slate-400 uppercase font-bold">Batch Status</div>
                    <div className={`text-sm font-bold uppercase ${getStatusColor(item.status)}`}>{item.status}</div>
                  </div>
                  <ShieldCheckIcon className={`w-6 h-6 ${getStatusColor(item.status)}`} />
               </div>

               {item.status !== BatchStatus.APPROVED && item.statusNotes && (
                 <div className={`p-3 border rounded-lg ${getStatusBg(item.status)}`}>
                    <div className="flex items-center gap-2 text-[10px] text-slate-400 uppercase font-bold mb-1">
                      <ChatBubbleLeftRightIcon className="w-3 h-3" />
                      QC Analysis Notes / Reason
                    </div>
                    <div className="text-xs text-slate-600 italic leading-relaxed">
                      "{item.statusNotes}"
                    </div>
                 </div>
               )}

               <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Chemical Name</div>
                  <div className="text-lg text-slate-800 font-semibold">{item.chemicalName}</div>
               </div>
            </div>

            <div className="flex items-center justify-between p-4 bg-slate-50 rounded-lg mb-6">
              <span className="text-sm text-slate-600 font-medium">Available Stock</span>
              <span className={`text-lg font-bold ${item.quantity < 5 ? 'text-red-600' : 'text-teal-600'}`}>
                {item.quantity} {item.unit}
              </span>
            </div>

            <div className="space-y-4">
              <div className="flex items-start gap-3">
                <UserIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Vendor</div>
                  <div className="text-sm text-slate-800 font-medium">{item.vendorName}</div>
                  <div className="text-[10px] text-slate-500 font-bold uppercase">{item.vendorQualification}</div>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <CheckBadgeIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Last Analysis Date</div>
                  <div className="text-sm text-slate-800 font-medium">{item.dateOfAnalysis}</div>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <ClockIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div className="flex-1">
                  <div className="flex justify-between items-start">
                    <div>
                      <div className="text-xs text-slate-400 uppercase font-bold">Next Retest Due</div>
                      <div className="text-sm text-slate-800 font-medium">{item.dateOfRetest}</div>
                    </div>
                  </div>
                </div>
              </div>

              {isAdmin && !showAnalysisForm && (
                <button 
                  onClick={() => setShowAnalysisForm(true)}
                  className="w-full mt-4 flex items-center justify-center gap-2 py-3 bg-slate-800 text-white rounded-xl text-xs font-bold uppercase tracking-wider hover:bg-slate-700 transition-all shadow-md"
                >
                  <BeakerIcon className="w-4 h-4" />
                  Analysis Completed
                </button>
              )}

              {isAdmin && showAnalysisForm && (
                <div className="mt-4 p-4 bg-teal-50 border border-teal-200 rounded-xl space-y-3 animate-fade-in">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] font-bold text-teal-700 uppercase tracking-widest">New Analysis Entry</span>
                    <button onClick={() => setShowAnalysisForm(false)} className="text-slate-400 hover:text-red-500">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Analysis Result</label>
                    <textarea 
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      placeholder="Enter quality results..."
                      rows={2}
                      value={analysisResult}
                      onChange={(e) => setAnalysisResult(e.target.value)}
                    />
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Performed By</label>
                    <input 
                      type="text"
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      placeholder="Analyst name"
                      value={performerName}
                      onChange={(e) => setPerformerName(e.target.value)}
                    />
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Next Retest Date</label>
                    <input 
                      type="date"
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      value={nextRetestDate}
                      onChange={(e) => setNextRetestDate(e.target.value)}
                    />
                  </div>

                  <button 
                    onClick={handleCompleteAnalysis}
                    className="w-full py-2 bg-teal-600 text-white rounded-lg text-[10px] font-bold uppercase tracking-wider hover:bg-teal-700 shadow-sm"
                  >
                    Confirm & Update Dates
                  </button>
                </div>
              )}

              <div className="flex items-start gap-3">
                <CalendarDaysIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Expiry Date</div>
                  <div className={`text-sm font-medium ${new Date(item.dateOfExpiry) < new Date() ? 'text-red-600' : 'text-slate-800'}`}>
                    {item.dateOfExpiry}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right Columns */}
        <div className="lg:col-span-2 space-y-6">
          {/* Status History */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <ShieldCheckIcon className="w-5 h-5 text-teal-600" />
                Status Transition History
              </h3>
            </div>
            <div className="p-6">
              {!item.statusHistory || item.statusHistory.length === 0 ? (
                <p className="text-center text-slate-400 text-sm py-4">No status changes recorded for this batch.</p>
              ) : (
                <div className="space-y-4">
                  {item.statusHistory.map((log, idx) => (
                    <div key={log.id} className="relative flex gap-4 pl-8">
                      {idx !== item.statusHistory!.length - 1 && (
                        <div className="absolute left-3 top-6 bottom-[-24px] w-0.5 bg-slate-100"></div>
                      )}

                      <div className={`absolute left-0 top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${getStatusColor(log.to).replace('text', 'bg').replace('600', '500')}`}>
                      </div>

                      <div className="flex-1 pb-6">
                        <div className="flex justify-between items-start mb-1">
                          <div className="text-sm font-bold text-slate-800">
                            Status changed to <span className={getStatusColor(log.to)}>{log.to}</span>
                          </div>
                          <span className="text-[10px] text-slate-400 font-mono font-bold uppercase">{log.date}</span>
                        </div>
                        <div className="text-xs text-slate-500 mb-2">
                          Moved from <span className="font-semibold">{log.from}</span> by <span className="font-semibold">{log.changedBy}</span>
                        </div>
                        {log.reason && (
                          <div className="p-2 bg-slate-50 border border-slate-100 rounded text-xs text-slate-600 italic">
                            "{log.reason}"
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Usage History & Transactions */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[200px]">
            <div className="p-6 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <DocumentTextIcon className="w-5 h-5 text-teal-600" />
                Usage History & Transactions
              </h3>
            </div>

            <div className="overflow-x-auto">
              {item.transactions.length === 0 ? (
                <div className="p-12 text-center text-slate-400">
                  <p>No usage recorded for this unique batch yet.</p>
                </div>
              ) : (
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                    <tr>
                      <th className="px-6 py-3">Date</th>
                      <th className="px-6 py-3">Purpose</th>
                      <th className="px-6 py-3">Amount Used</th>
                      {isAdmin && <th className="px-6 py-3 text-right">Actions</th>}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {item.transactions.map((tx) => (
                      <tr key={tx.id} className="hover:bg-slate-50 group">
                        <td className="px-6 py-4 text-slate-500 font-mono">{tx.date}</td>
                        <td className="px-6 py-4 font-medium text-slate-800">{tx.purpose}</td>
                        <td className="px-6 py-4 text-red-600 font-bold">-{tx.amount} {item.unit}</td>
                        {isAdmin && (
                          <td className="px-6 py-4 text-right">
                            <button 
                              onClick={() => onRevert(tx.id)}
                              className="px-2 py-1 text-[10px] font-bold text-slate-400 hover:text-amber-600 border border-transparent hover:border-amber-200 rounded transition-all opacity-0 group-hover:opacity-100"
                            >
                              REVERT
                            </button>
                          </td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </div>

          {/* Analysis Result Records */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-200 bg-slate-50">
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <BeakerIcon className="w-5 h-5 text-teal-600" />
                QC Analysis History
              </h3>
            </div>
            <div className="overflow-x-auto">
               {!item.analysisHistory || item.analysisHistory.length === 0 ? (
                 <div className="p-12 text-center text-slate-400">
                   <p>No historical analysis records available.</p>
                 </div>
               ) : (
                 <table className="w-full text-left text-sm">
                   <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                     <tr>
                       <th className="px-6 py-3">Analysis Date</th>
                       <th className="px-6 py-3">Performed By</th>
                       <th className="px-6 py-3">Result / Observations</th>
                       <th className="px-6 py-3">Next Retest Set</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100">
                     {item.analysisHistory.map((ana) => (
                       <tr key={ana.id} className="hover:bg-slate-50">
                         <td className="px-6 py-4 font-mono text-slate-700">{ana.analysisDate}</td>
                         <td className="px-6 py-4 font-medium text-slate-800">{ana.performedBy}</td>
                         <td className="px-6 py-4">
                           <div className="text-xs text-slate-600 max-w-xs leading-relaxed italic">"{ana.result}"</div>
                         </td>
                         <td className="px-6 py-4 text-teal-600 font-bold">{ana.nextRetestDate}</td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ItemDetails;

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { InventoryItem, MaterialRequest, RequestType, BatchStatus } from '../types';
import { 
  BeakerIcon, 
  AcademicCapIcon, 
  CpuChipIcon, 
  ArrowLeftIcon,
  CheckCircleIcon,
  ClockIcon,
  UserIcon,
  InformationCircleIcon,
  HashtagIcon,
  XCircleIcon,
  ArrowDownTrayIcon
} from '@heroicons/react/24/outline';

interface RequestSystemProps {
  inventory: InventoryItem[];
  existingRequests: MaterialRequest[];
  onAddRequest: (request: MaterialRequest) => void;
  onUpdateRequest: (request: MaterialRequest) => void;
  isAdmin: boolean;
}

const RequestSystem: React.FC<RequestSystemProps> = ({ inventory, existingRequests, onAddRequest, onUpdateRequest, isAdmin }) => {
  const [selectedType, setSelectedType] = useState<RequestType | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showApprovalModal, setShowApprovalModal] = useState<MaterialRequest | null>(null);
  const [acceptingPerson, setAcceptingPerson] = useState('');

  const [formData, setFormData] = useState({
    batchNo: '',
    quantity: 0,
    requestedBy: '',
    notes: ''
  });

  const handleTypeSelect = (type: RequestType) => {
    setSelectedType(type);
    setFormData({ batchNo: '', quantity: 0, requestedBy: '', notes: '' });
  };

  const handleExportRequestsExcel = () => {
    const dataToExport = existingRequests.map(req => ({
      'Request ID': req.id,
      'Department': req.type,
      'Batch No': req.batchNo,
      'Chemical Name': req.chemicalName,
      'Quantity': req.quantity,
      'Unit': req.unit,
      'Requested By': req.requestedBy,
      'Date': req.date,
      'Status': req.status,
      'Accepted By': req.acceptedBy || 'N/A',
      'Notes': req.departmentNotes || ''
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Material Requests");

    const dateStr = new Date().toISOString().split('T')[0];
    const fileName = `Basis_Labs_Requests_${dateStr}.xlsx`;

    XLSX.writeFile(workbook, fileName);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedType) return;

    const selectedItem = inventory.find(i => i.batchNo === formData.batchNo);
    if (!selectedItem) {
      alert("Please select a valid Unique Batch No.");
      return;
    }

    if (selectedItem.status === BatchStatus.REJECTED) {
      alert("This batch is REJECTED and cannot be requested for use.");
      return;
    }

    const newRequest: MaterialRequest = {
      id: Math.random().toString(36).substr(2, 9),
      type: selectedType,
      batchNo: formData.batchNo,
      chemicalName: selectedItem.chemicalName,
      quantity: formData.quantity,
      unit: selectedItem.unit,
      requestedBy: formData.requestedBy,
      date: new Date().toISOString().split('T')[0],
      status: 'Pending',
      departmentNotes: formData.notes
    };

    onAddRequest(newRequest);
    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      setSelectedType(null);
    }, 1500);
  };

  const handleApprove = () => {
    if (!showApprovalModal || !acceptingPerson.trim()) {
      alert("Please enter the accepting person's name.");
      return;
    }

    const updatedRequest: MaterialRequest = {
      ...showApprovalModal,
      status: 'Approved',
      acceptedBy: acceptingPerson
    };

    onUpdateRequest(updatedRequest);
    setShowApprovalModal(null);
    setAcceptingPerson('');
  };

  const handleReject = (req: MaterialRequest) => {
    const updatedRequest: MaterialRequest = {
      ...req,
      status: 'Rejected'
    };
    onUpdateRequest(updatedRequest);
  };

  const departmentConfigs = {
    'R&D': {
      icon: AcademicCapIcon,
      color: 'purple',
      description: 'Research chemicals and experimentation.',
      bg: 'bg-purple-50',
      border: 'border-purple-200',
      text: 'text-purple-700',
      btn: 'bg-purple-600 hover:bg-purple-700'
    },
    'QC': {
      icon: BeakerIcon,
      color: 'amber',
      description: 'Quality analysis and testing reagents.',
      bg: 'bg-amber-50',
      border: 'border-amber-200',
      text: 'text-amber-700',
      btn: 'bg-amber-600 hover:bg-amber-700'
    },
    'Production': {
      icon: CpuChipIcon,
      color: 'blue',
      description: 'Bulk raw materials for manufacturing.',
      bg: 'bg-blue-50',
      border: 'border-blue-200',
      text: 'text-blue-700',
      btn: 'bg-blue-600 hover:bg-blue-700'
    }
  };

  if (isSubmitting) {
    return (
      <div className="flex flex-col items-center justify-center py-20 animate-pulse">
        <CheckCircleIcon className="w-20 h-20 text-teal-500 mb-4" />
        <h2 className="text-2xl font-bold text-slate-800">Request Submitted!</h2>
        <p className="text-slate-500">Routing request to Material Management for approval...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Upper Section: Type Selection or Form */}
      {!selectedType ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {(Object.keys(departmentConfigs) as RequestType[]).map((type) => {
            const config = departmentConfigs[type];
            return (
              <button
                key={type}
                onClick={() => handleTypeSelect(type)}
                className={`flex flex-col items-center p-8 bg-white border ${config.border} rounded-2xl shadow-sm hover:shadow-md transition-all group`}
              >
                <div className={`p-4 rounded-xl ${config.bg} ${config.text} mb-4 group-hover:scale-110 transition-transform`}>
                  <config.icon className="w-10 h-10" />
                </div>
                <h3 className={`text-xl font-bold ${config.text} mb-2`}>{type} Request</h3>
                <p className="text-sm text-slate-500 text-center leading-relaxed">
                  {config.description}
                </p>
                <div className={`mt-6 py-2 px-6 rounded-lg font-semibold text-white ${config.btn} transition-colors`}>
                  Open Form
                </div>
              </button>
            );
          })}
        </div>
      ) : (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden max-w-2xl mx-auto">
          <div className={`${departmentConfigs[selectedType].bg} p-6 border-b ${departmentConfigs[selectedType].border}`}>
            <button 
              onClick={() => setSelectedType(null)}
              className="flex items-center gap-2 text-slate-600 hover:text-slate-900 mb-4 text-sm font-medium"
            >
              <ArrowLeftIcon className="w-4 h-4" />
              Cancel Requisition
            </button>
            <div className="flex items-center gap-4">
              <div className={`p-3 rounded-xl bg-white ${departmentConfigs[selectedType].text}`}>
                {React.createElement(departmentConfigs[selectedType].icon, { className: "w-8 h-8" })}
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800">{selectedType} Material Requisition</h2>
                <p className="text-slate-500 text-sm">Targeting Unique Batch Numbers for traceability.</p>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="p-8 space-y-6 text-left">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Select Unique ID (Batch No)</label>
                <div className="relative">
                  <HashtagIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <select 
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all appearance-none"
                    value={formData.batchNo}
                    onChange={(e) => setFormData({...formData, batchNo: e.target.value})}
                    required
                  >
                    <option value="">-- Select by Unique Batch No --</option>
                    {inventory.map(item => (
                      <option key={item.batchNo} value={item.batchNo} disabled={item.status === BatchStatus.REJECTED}>
                        {item.batchNo} | {item.chemicalName} {item.status === BatchStatus.REJECTED ? '(REJECTED)' : `(Avail: ${item.quantity} ${item.unit})`}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Quantity Required</label>
                <input 
                  type="number"
                  step="0.01"
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  placeholder="0.00"
                  value={formData.quantity}
                  onChange={(e) => setFormData({...formData, quantity: parseFloat(e.target.value) || 0})}
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Requested By (Staff Name)</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="Enter name"
                    value={formData.requestedBy}
                    onChange={(e) => setFormData({...formData, requestedBy: e.target.value})}
                    required
                  />
                </div>
              </div>

              <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Purpose / Additional Notes</label>
                <textarea 
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all h-24"
                  placeholder="Specific usage details..."
                  value={formData.notes}
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                ></textarea>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                type="submit"
                className={`w-full py-4 text-white font-bold rounded-xl shadow-lg transition-all ${departmentConfigs[selectedType].btn}`}
              >
                Submit Request
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Lower Section: Requisition History (Always Visible) */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="p-6 border-b border-slate-100 bg-slate-50 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <ClockIcon className="w-5 h-5 text-teal-600" />
              Material Requisition History {isAdmin && '(Admin Management View)'}
            </h3>
            <p className="text-xs text-slate-500 mt-1">Full audit log of all requested material batches and their current processing status.</p>
          </div>
          {existingRequests.length > 0 && (
            <button
              onClick={handleExportRequestsExcel}
              className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white text-xs font-bold uppercase rounded-xl hover:bg-slate-700 transition-all shadow-lg shadow-slate-200 flex-shrink-0"
              title="Download full requisition history as Excel"
            >
              <ArrowDownTrayIcon className="w-4 h-4" />
              Export History to Excel
            </button>
          )}
        </div>
        <div className="overflow-x-auto">
          {existingRequests.length === 0 ? (
            <div className="p-12 text-center text-slate-400">
              <InformationCircleIcon className="w-10 h-10 mx-auto mb-2 opacity-20" />
              <p>No material requests placed yet.</p>
            </div>
          ) : (
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                <tr>
                  <th className="px-6 py-3">Dept</th>
                  <th className="px-6 py-3">Batch No</th>
                  <th className="px-6 py-3">Chemical</th>
                  <th className="px-6 py-3">Qty</th>
                  <th className="px-6 py-3">Requested By</th>
                  <th className="px-6 py-3">Status</th>
                  {isAdmin && <th className="px-6 py-3 text-right">Actions</th>}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {existingRequests.map((req) => (
                  <tr key={req.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${
                        req.type === 'R&D' ? 'bg-purple-100 text-purple-700' :
                        req.type === 'QC' ? 'bg-amber-100 text-amber-700' :
                        'bg-blue-100 text-blue-700'
                      }`}>
                        {req.type}
                      </span>
                    </td>
                    <td className="px-6 py-4 font-mono font-bold text-slate-900">{req.batchNo}</td>
                    <td className="px-6 py-4 text-slate-600">{req.chemicalName}</td>
                    <td className="px-6 py-4 font-semibold">{req.quantity} {req.unit}</td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-slate-800 font-medium">{req.requestedBy}</span>
                        <span className="text-[10px] text-slate-400">{req.date}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`flex items-center gap-1.5 font-bold uppercase text-[10px] ${
                        req.status === 'Approved' ? 'text-green-600' : 
                        req.status === 'Rejected' ? 'text-red-600' : 'text-amber-600'
                      }`}>
                        {req.status}
                      </span>
                    </td>
                    {isAdmin && (
                      <td className="px-6 py-4 text-right">
                        {req.status === 'Pending' && (
                          <div className="flex justify-end gap-2">
                            <button 
                              onClick={() => setShowApprovalModal(req)}
                              className="px-3 py-1 bg-green-600 text-white rounded-lg text-[10px] font-bold hover:bg-green-700 transition-colors shadow-sm"
                            >
                              Approve
                            </button>
                            <button 
                              onClick={() => handleReject(req)}
                              className="px-3 py-1 bg-red-600 text-white rounded-lg text-[10px] font-bold hover:bg-red-700 transition-colors shadow-sm"
                            >
                              Reject
                            </button>
                          </div>
                        )}
                        {req.status === 'Approved' && (
                          <span className="text-[10px] text-slate-400 italic">Auth by: {req.acceptedBy}</span>
                        )}
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* Acceptance Name Modal */}
      {isAdmin && showApprovalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="bg-green-600 p-6 text-white">
              <h3 className="text-xl font-bold">Approve Material Requisition</h3>
              <p className="text-green-100 text-sm">Batch: {showApprovalModal.batchNo}</p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Accepting Person Name</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Authorized Staff Name"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-green-500 outline-none transition-all"
                    value={acceptingPerson}
                    onChange={(e) => setAcceptingPerson(e.target.value)}
                    autoFocus
                  />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => setShowApprovalModal(null)}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleApprove}
                  className="flex-1 py-3 text-sm font-medium text-white bg-green-600 rounded-xl hover:bg-green-700 shadow-lg shadow-green-200"
                >
                  Confirm & Approve
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RequestSystem;

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { InventoryItem, MaterialRequest, BatchStatus, AnalysisRecord } from '../types';
import { 
  ArrowLeftIcon, 
  DocumentTextIcon, 
  CalendarDaysIcon, 
  UserIcon, 
  HashtagIcon,
  ShieldCheckIcon,
  ClipboardDocumentCheckIcon,
  ArrowPathIcon,
  ChatBubbleLeftRightIcon,
  ClockIcon,
  CheckBadgeIcon,
  BeakerIcon,
  CheckIcon,
  XMarkIcon,
  ArrowDownTrayIcon
} from '@heroicons/react/24/outline';

interface ItemDetailsProps {
  item: InventoryItem;
  onBack: () => void;
  onRevert: (transactionId: string) => void;
  onUpdateItem: (updatedItem: InventoryItem) => void;
  requests: MaterialRequest[];
  isAdmin: boolean;
}

const ItemDetails: React.FC<ItemDetailsProps> = ({ item, onBack, onRevert, onUpdateItem, requests, isAdmin }) => {
  const [showAnalysisForm, setShowAnalysisForm] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');
  const [nextRetestDate, setNextRetestDate] = useState('');
  const [performerName, setPerformerName] = useState('');

  const getStatusColor = (status: BatchStatus) => {
    switch(status) {
      case BatchStatus.APPROVED: return 'text-green-600';
      case BatchStatus.REJECTED: return 'text-red-600';
      default: return 'text-amber-600';
    }
  };

  const getStatusBg = (status: BatchStatus) => {
    switch(status) {
      case BatchStatus.APPROVED: return 'bg-green-50 border-green-100';
      case BatchStatus.REJECTED: return 'bg-red-50 border-red-100';
      default: return 'bg-amber-50 border-amber-100';
    }
  };

  const handleExportUsageExcel = () => {
    const dataToExport = item.transactions.map(tx => ({
      'Batch No': item.batchNo,
      'Chemical': item.chemicalName,
      'Date': tx.date,
      'Purpose': tx.purpose,
      'Amount Used': tx.amount,
      'Unit': item.unit,
      'Transaction ID': tx.id
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Usage History");
    XLSX.writeFile(workbook, `Usage_${item.batchNo}_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleExportAnalysisExcel = () => {
    const history = item.analysisHistory || [];
    const dataToExport = history.map(ana => ({
      'Batch No': item.batchNo,
      'Chemical': item.chemicalName,
      'Analysis Date': ana.analysisDate,
      'Performed By': ana.performedBy,
      'Result': ana.result,
      'Next Retest Date': ana.nextRetestDate
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Analysis History");
    XLSX.writeFile(workbook, `Analysis_${item.batchNo}_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleCompleteAnalysis = () => {
    if (!analysisResult || !nextRetestDate || !performerName) {
      alert("Please fill in all analysis fields.");
      return;
    }

    const newRecord: AnalysisRecord = {
      id: `ana-${Date.now()}`,
      analysisDate: item.dateOfRetest, // Retest date becomes the actual analysis date
      result: analysisResult,
      performedBy: performerName,
      nextRetestDate: nextRetestDate
    };

    const updatedItem: InventoryItem = {
      ...item,
      dateOfAnalysis: item.dateOfRetest,
      dateOfRetest: nextRetestDate,
      analysisHistory: [newRecord, ...(item.analysisHistory || [])]
    };

    onUpdateItem(updatedItem);
    setShowAnalysisForm(false);
    setAnalysisResult('');
    setNextRetestDate('');
    setPerformerName('');
    alert("Analysis successfully logged. Dates updated.");
  };

  return (
    <div className="space-y-6">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-slate-600 hover:text-teal-600 transition-colors mb-4"
      >
        <ArrowLeftIcon className="w-4 h-4" />
        Back to Dashboard
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 text-left">
        {/* Profile Card */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 text-teal-600 mb-1">
              <HashtagIcon className="w-4 h-4" />
              <span className="text-xs font-bold uppercase tracking-widest">Unique Identity</span>
            </div>
            <h2 className="text-2xl font-mono font-bold text-slate-900 mb-4">{item.batchNo}</h2>

            <div className="space-y-4 mb-6 pt-4 border-t border-slate-100">
               <div className="flex justify-between items-center">
                  <div>
                    <div className="text-xs text-slate-400 uppercase font-bold">Batch Status</div>
                    <div className={`text-sm font-bold uppercase ${getStatusColor(item.status)}`}>{item.status}</div>
                  </div>
                  <ShieldCheckIcon className={`w-6 h-6 ${getStatusColor(item.status)}`} />
               </div>

               {item.status !== BatchStatus.APPROVED && item.statusNotes && (
                 <div className={`p-3 border rounded-lg ${getStatusBg(item.status)}`}>
                    <div className="flex items-center gap-2 text-[10px] text-slate-400 uppercase font-bold mb-1">
                      <ChatBubbleLeftRightIcon className="w-3 h-3" />
                      QC Analysis Notes / Reason
                    </div>
                    <div className="text-xs text-slate-600 italic leading-relaxed">
                      "{item.statusNotes}"
                    </div>
                 </div>
               )}

               <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Chemical Name</div>
                  <div className="text-lg text-slate-800 font-semibold">{item.chemicalName}</div>
               </div>
            </div>

            <div className="flex items-center justify-between p-4 bg-slate-50 rounded-lg mb-6">
              <span className="text-sm text-slate-600 font-medium">Available Stock</span>
              <span className={`text-lg font-bold ${item.quantity < 5 ? 'text-red-600' : 'text-teal-600'}`}>
                {item.quantity} {item.unit}
              </span>
            </div>

            <div className="space-y-4">
              <div className="flex items-start gap-3">
                <UserIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Vendor</div>
                  <div className="text-sm text-slate-800 font-medium">{item.vendorName}</div>
                  <div className="text-[10px] text-slate-500 font-bold uppercase">{item.vendorQualification}</div>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <CheckBadgeIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Last Analysis Date</div>
                  <div className="text-sm text-slate-800 font-medium">{item.dateOfAnalysis}</div>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <ClockIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div className="flex-1">
                  <div className="flex justify-between items-start">
                    <div>
                      <div className="text-xs text-slate-400 uppercase font-bold">Next Retest Due</div>
                      <div className="text-sm text-slate-800 font-medium">{item.dateOfRetest}</div>
                    </div>
                  </div>
                </div>
              </div>

              {isAdmin && !showAnalysisForm && (
                <button 
                  onClick={() => setShowAnalysisForm(true)}
                  className="w-full mt-4 flex items-center justify-center gap-2 py-3 bg-slate-800 text-white rounded-xl text-xs font-bold uppercase tracking-wider hover:bg-slate-700 transition-all shadow-md"
                >
                  <BeakerIcon className="w-4 h-4" />
                  Analysis Completed
                </button>
              )}

              {isAdmin && showAnalysisForm && (
                <div className="mt-4 p-4 bg-teal-50 border border-teal-200 rounded-xl space-y-3 animate-fade-in">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] font-bold text-teal-700 uppercase tracking-widest">New Analysis Entry</span>
                    <button onClick={() => setShowAnalysisForm(false)} className="text-slate-400 hover:text-red-500">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Analysis Result</label>
                    <textarea 
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      placeholder="Enter quality results..."
                      rows={2}
                      value={analysisResult}
                      onChange={(e) => setAnalysisResult(e.target.value)}
                    />
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Performed By</label>
                    <input 
                      type="text"
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      placeholder="Analyst name"
                      value={performerName}
                      onChange={(e) => setPerformerName(e.target.value)}
                    />
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Next Retest Date</label>
                    <input 
                      type="date"
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      value={nextRetestDate}
                      onChange={(e) => setNextRetestDate(e.target.value)}
                    />
                  </div>

                  <button 
                    onClick={handleCompleteAnalysis}
                    className="w-full py-2 bg-teal-600 text-white rounded-lg text-[10px] font-bold uppercase tracking-wider hover:bg-teal-700 shadow-sm"
                  >
                    Confirm & Update Dates
                  </button>
                </div>
              )}

              <div className="flex items-start gap-3">
                <CalendarDaysIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Expiry Date</div>
                  <div className={`text-sm font-medium ${new Date(item.dateOfExpiry) < new Date() ? 'text-red-600' : 'text-slate-800'}`}>
                    {item.dateOfExpiry}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Right Columns */}
        <div className="lg:col-span-2 space-y-6">
          {/* Status History */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <ShieldCheckIcon className="w-5 h-5 text-teal-600" />
                Status Transition History
              </h3>
            </div>
            <div className="p-6">
              {!item.statusHistory || item.statusHistory.length === 0 ? (
                <p className="text-center text-slate-400 text-sm py-4">No status changes recorded for this batch.</p>
              ) : (
                <div className="space-y-4">
                  {item.statusHistory.map((log, idx) => (
                    <div key={log.id} className="relative flex gap-4 pl-8">
                      {idx !== item.statusHistory!.length - 1 && (
                        <div className="absolute left-3 top-6 bottom-[-24px] w-0.5 bg-slate-100"></div>
                      )}

                      <div className={`absolute left-0 top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm flex items-center justify-center ${getStatusColor(log.to).replace('text', 'bg').replace('600', '500')}`}>
                      </div>

                      <div className="flex-1 pb-6">
                        <div className="flex justify-between items-start mb-1">
                          <div className="text-sm font-bold text-slate-800">
                            Status changed to <span className={getStatusColor(log.to)}>{log.to}</span>
                          </div>
                          <span className="text-[10px] text-slate-400 font-mono font-bold uppercase">{log.date}</span>
                        </div>
                        <div className="text-xs text-slate-500 mb-2">
                          Moved from <span className="font-semibold">{log.from}</span> by <span className="font-semibold">{log.changedBy}</span>
                        </div>
                        {log.reason && (
                          <div className="p-2 bg-slate-50 border border-slate-100 rounded text-xs text-slate-600 italic">
                            "{log.reason}"
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Usage History & Transactions */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden min-h-[200px]">
            <div className="p-6 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <DocumentTextIcon className="w-5 h-5 text-teal-600" />
                Usage History & Transactions
              </h3>
              {item.transactions.length > 0 && (
                <button 
                  onClick={handleExportUsageExcel}
                  className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 text-white text-[10px] font-bold uppercase rounded-lg hover:bg-slate-700 transition-all"
                >
                  <ArrowDownTrayIcon className="w-3.5 h-3.5" />
                  Export Usage
                </button>
              )}
            </div>

            <div className="overflow-x-auto">
              {item.transactions.length === 0 ? (
                <div className="p-12 text-center text-slate-400">
                  <p>No usage recorded for this unique batch yet.</p>
                </div>
              ) : (
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                    <tr>
                      <th className="px-6 py-3">Date</th>
                      <th className="px-6 py-3">Purpose</th>
                      <th className="px-6 py-3">Amount Used</th>
                      {isAdmin && <th className="px-6 py-3 text-right">Actions</th>}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {item.transactions.map((tx) => (
                      <tr key={tx.id} className="hover:bg-slate-50 group">
                        <td className="px-6 py-4 text-slate-500 font-mono">{tx.date}</td>
                        <td className="px-6 py-4 font-medium text-slate-800">{tx.purpose}</td>
                        <td className="px-6 py-4 text-red-600 font-bold">-{tx.amount} {item.unit}</td>
                        {isAdmin && (
                          <td className="px-6 py-4 text-right">
                            <button 
                              onClick={() => onRevert(tx.id)}
                              className="px-2 py-1 text-[10px] font-bold text-slate-400 hover:text-amber-600 border border-transparent hover:border-amber-200 rounded transition-all opacity-0 group-hover:opacity-100"
                            >
                              REVERT
                            </button>
                          </td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </div>

          {/* Analysis Result Records */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden text-left">
            <div className="p-6 border-b border-slate-200 bg-slate-50 flex justify-between items-center">
              <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                <BeakerIcon className="w-5 h-5 text-teal-600" />
                QC Analysis History
              </h3>
              {(item.analysisHistory && item.analysisHistory.length > 0) && (
                <button 
                  onClick={handleExportAnalysisExcel}
                  className="flex items-center gap-2 px-3 py-1.5 bg-slate-800 text-white text-[10px] font-bold uppercase rounded-lg hover:bg-slate-700 transition-all"
                >
                  <ArrowDownTrayIcon className="w-3.5 h-3.5" />
                  Export History
                </button>
              )}
            </div>
            <div className="overflow-x-auto">
               {!item.analysisHistory || item.analysisHistory.length === 0 ? (
                 <div className="p-12 text-center text-slate-400">
                   <p>No historical analysis records available.</p>
                 </div>
               ) : (
                 <table className="w-full text-left text-sm">
                   <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                     <tr>
                       <th className="px-6 py-3">Analysis Date</th>
                       <th className="px-6 py-3">Performed By</th>
                       <th className="px-6 py-3">Result / Observations</th>
                       <th className="px-6 py-3">Next Retest Set</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100">
                     {item.analysisHistory.map((ana) => (
                       <tr key={ana.id} className="hover:bg-slate-50">
                         <td className="px-6 py-4 font-mono text-slate-700">{ana.analysisDate}</td>
                         <td className="px-6 py-4 font-medium text-slate-800">{ana.performedBy}</td>
                         <td className="px-6 py-4">
                           <div className="text-xs text-slate-600 max-w-xs leading-relaxed italic">"{ana.result}"</div>
                         </td>
                         <td className="px-6 py-4 text-teal-600 font-bold">{ana.nextRetestDate}</td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ItemDetails;

import React, { useState } from 'react';
import { ViewState, User, UserRole } from '../types';
import { db } from '../services/DatabaseService';
import { 
  EnvelopeIcon, 
  LockClosedIcon, 
  UserIcon, 
  ShieldCheckIcon, 
  CheckCircleIcon,
  ArrowRightIcon,
  ExclamationCircleIcon,
  ArrowPathIcon,
  ArrowLeftOnRectangleIcon,
  ArrowLeftIcon,
  KeyIcon,
  BriefcaseIcon,
  UserGroupIcon,
  ClockIcon,
  EnvelopeOpenIcon
} from '@heroicons/react/24/outline';

const SUPER_ADMIN_EMAIL = 'tanujrao2006@gmail.com';

interface AuthProps {
  view: ViewState;
  setView: (v: ViewState) => void;
  setCurrentUser: (u: User | null) => void;
  currentUser: User | null;
}

const Auth: React.FC<AuthProps> = ({ view, setView, setCurrentUser, currentUser }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: 'user' as UserRole
  });
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [loading, setLoading] = useState(false);
  const [recoveryEmailSent, setRecoveryEmailSent] = useState(false);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setLoading(true);

    const email = formData.email.toLowerCase().trim();
    const password = formData.password.trim();
    const selectedRole = formData.role;

    setTimeout(() => {
      const users = db.getUsers();

      if (view === 'login') {
        const user = users.find(u => 
          u.email.toLowerCase().trim() === email && 
          u.password === password &&
          u.role === selectedRole
        );

        if (user) {
          if (!user.isApproved) {
             setError('Access Pending: Your account is awaiting Admin approval.');
             setLoading(false);
             return;
          }

          setCurrentUser(user);
          db.logAction(user, 'SIGN_IN', `Authenticated as ${user.role}`);
          if (user.isEmailConfirmed) {
            setView('dashboard');
          } else {
            setView('verify');
          }
        } else {
          setError(`Invalid credentials for ${selectedRole.toUpperCase()}.`);
        }
      } else if (view === 'signup') {
        if (users.some(u => u.email.toLowerCase().trim() === email)) {
          setError('This Gmail is already registered. Please login.');
        } else {
          const newUser: User = {
            id: Math.random().toString(36).substr(2, 9),
            name: formData.name.trim(),
            email: email,
            password: password,
            isEmailConfirmed: false,
            isApproved: false, 
            role: 'user', 
            createdAt: new Date().toISOString()
          };
          db.saveUser(newUser);
          db.logAction(newUser, 'SIGN_UP', 'User registered, pending admin approval');
          setCurrentUser(newUser);
          setView('verify');
        }
      } else if (view === 'forgot-password') {
        const user = users.find(u => u.email.toLowerCase().trim() === email);
        if (user) {
          // In a real app, this would call a backend API to send an actual email
          console.log(`%c [MAIL SIMULATOR] Sending password to: ${email}`, 'color: #0d9488; font-weight: bold;');
          console.log(`%c Password Found: ${user.password}`, 'color: #0d9488;');
          setRecoveryEmailSent(true);
        } else {
          setError('We could not find an account associated with this email address.');
        }
      }
      setLoading(false);
    }, 1200);
  };

  const handleVerify = () => {
    setLoading(true);
    setTimeout(() => {
      if (currentUser) {
        const updatedUser = { ...currentUser, isEmailConfirmed: true };
        db.saveUser(updatedUser);
        setCurrentUser(updatedUser);
        if (!updatedUser.isApproved) {
          setView('pending-approval');
        } else {
          setView('dashboard');
        }
      }
      setLoading(false);
    }, 1500);
  };

  // --- Specialized Views ---

  if (recoveryEmailSent) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-teal-50 rounded-full">
              <EnvelopeOpenIcon className="w-12 h-12 text-teal-600 animate-pulse" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Check Your Mail</h2>
          <p className="text-slate-500 text-sm leading-relaxed mb-8">
            A password recovery email has been sent to:<br/>
            <span className="font-bold text-slate-700">{formData.email}</span>
          </p>
          <div className="p-4 bg-teal-50 border border-teal-100 rounded-xl mb-8">
            <p className="text-[10px] text-teal-700 font-bold uppercase tracking-widest">Prototype Note</p>
            <p className="text-[11px] text-teal-600 italic">In this local environment, the password was found in the database and the mail process was simulated successfully.</p>
          </div>
          <button 
            onClick={() => { setRecoveryEmailSent(false); setView('login'); }}
            className="w-full py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-slate-700 transition-all"
          >
            Back to Login
          </button>
        </div>
      </div>
    );
  }

  if (view === 'pending-approval') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in relative">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-amber-50 rounded-full">
              <ClockIcon className="w-12 h-12 text-amber-600 animate-pulse" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Registration Complete</h2>
          <p className="text-slate-500 text-sm leading-relaxed mb-8">
            Your account is now pending **Admin Approval**. You will be able to log in once an authorized manager grants you access.
          </p>
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 text-xs text-slate-500 mb-8">
            Registered Email: <br/>
            <span className="font-bold text-slate-700">{currentUser?.email}</span>
          </div>
          <button 
            onClick={() => { setCurrentUser(null); setView('login'); }}
            className="w-full py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-slate-700 transition-all"
          >
            Return to Login
          </button>
        </div>
      </div>
    );
  }

  if (view === 'verify') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in relative">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-teal-50 rounded-full">
              <EnvelopeIcon className="w-12 h-12 text-teal-600 animate-bounce" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Confirm Email</h2>
          <p className="text-slate-500 text-sm mb-8">Confirmation link sent to: <br/><strong>{currentUser?.email}</strong></p>
          <button 
            onClick={handleVerify}
            className="w-full py-4 bg-teal-600 text-white font-bold rounded-2xl shadow-lg hover:bg-teal-700 transition-all"
          >
            Simulate Confirmation
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4">
      <div className="mb-8 flex flex-col items-center gap-4">
         <img src="https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U" alt="Logo" className="w-20 h-20 rounded-2xl shadow-2xl bg-white p-1" />
         <div className="text-center">
            <h1 className="text-3xl font-bold text-white tracking-tight">Basis Laboratories</h1>
            <p className="text-slate-400 font-medium uppercase tracking-[0.2em] text-xs mt-1">Inventory Management System</p>
         </div>
      </div>

      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
        <div className="p-8">
          <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
             <h2 className="text-2xl font-bold text-slate-800">
               {view === 'login' ? 'System Login' : view === 'signup' ? 'User Signup' : 'Account Recovery'}
             </h2>
             <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">v1.5.0 Secure</span>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {error && (
              <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-700 text-[11px] font-bold text-left leading-relaxed">
                 <ExclamationCircleIcon className="w-5 h-5 flex-shrink-0" />
                 {error}
              </div>
            )}

            {/* Role Selection (Only on Login) */}
            {view === 'login' && (
              <div className="grid grid-cols-2 gap-3 mb-4">
                <button type="button" onClick={() => setFormData({...formData, role: 'admin'})} className={`flex items-center justify-center gap-2 py-3 rounded-xl border-2 transition-all ${formData.role === 'admin' ? 'border-teal-600 bg-teal-50 text-teal-700' : 'border-slate-100 text-slate-400'}`}>
                  <BriefcaseIcon className="w-5 h-5" />
                  <span className="text-xs font-bold uppercase">Admin</span>
                </button>
                <button type="button" onClick={() => setFormData({...formData, role: 'user'})} className={`flex items-center justify-center gap-2 py-3 rounded-xl border-2 transition-all ${formData.role === 'user' ? 'border-teal-600 bg-teal-50 text-teal-700' : 'border-slate-100 text-slate-400'}`}>
                  <UserGroupIcon className="w-5 h-5" />
                  <span className="text-xs font-bold uppercase">User</span>
                </button>
              </div>
            )}

            {view === 'signup' && (
              <div className="relative">
                <UserIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                <input type="text" placeholder="Full Name" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-teal-500" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} />
              </div>
            )}

            <div className="relative">
              <EnvelopeIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
              <input 
                type="email" 
                placeholder="Gmail Address" 
                required 
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-teal-500" 
                value={formData.email} 
                onChange={(e) => setFormData({...formData, email: e.target.value})} 
                disabled={view === 'login' && formData.role === 'admin' && formData.email === SUPER_ADMIN_EMAIL}
              />
            </div>

            {view !== 'forgot-password' && (
              <div className="relative">
                <LockClosedIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                <input type="password" placeholder="Password" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-teal-500" value={formData.password} onChange={(e) => setFormData({...formData, password: e.target.value})} />
              </div>
            )}

            {view === 'login' && (
              <div className="text-right -mt-2">
                <button 
                  type="button" 
                  onClick={() => setView('forgot-password')}
                  className="text-[10px] font-bold text-slate-400 hover:text-teal-600 uppercase tracking-tight transition-colors"
                >
                  Forgot Password?
                </button>
              </div>
            )}

            <button type="submit" disabled={loading} className="w-full py-4 bg-teal-600 hover:bg-teal-700 text-white font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3">
              {loading ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : (
                view === 'login' ? `Authenticate` : 
                view === 'signup' ? 'Register Request' :
                'Send Recovery Mail'
              )}
            </button>
          </form>
        </div>

        <div className="p-6 bg-slate-50 border-t text-center space-y-3">
          {view === 'login' && formData.role === 'user' && (
            <button onClick={() => setView('signup')} className="text-xs font-bold text-slate-500 hover:text-teal-600 uppercase tracking-tight block w-full">
              New Staff? Request Account
            </button>
          )}

          {(view === 'signup' || view === 'forgot-password') && (
            <button onClick={() => setView('login')} className="text-xs font-bold text-slate-500 hover:text-teal-600 uppercase tracking-tight block w-full flex items-center justify-center gap-2">
              <ArrowLeftIcon className="w-3 h-3" />
              Back to Login
            </button>
          )}

          {view === 'login' && formData.role === 'admin' && (
            <p className="text-[10px] text-slate-400 font-bold uppercase">Admin Registration Restricted</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default Auth;

export enum ChemicalState {
  SOLID = 'Solid',
  LIQUID = 'Liquid'
}

export enum BatchStatus {
  QUARANTINE = 'Quarantine',
  APPROVED = 'Approved',
  REJECTED = 'Rejected'
}

export interface StatusLog {
  id: string;
  from: BatchStatus;
  to: BatchStatus;
  date: string;
  reason?: string;
  changedBy: string;
}

export interface Transaction {
  id: string;
  batchNo: string;
  amount: number;
  purpose: string;
  date: string;
  requestId?: string;
}

export interface AnalysisRecord {
  id: string;
  analysisDate: string;
  result: string;
  performedBy: string;
  nextRetestDate: string;
}

export interface InventoryItem {
  batchNo: string;
  vendorName: string;
  vendorQualification: string;
  quantity: number;
  unit: string;
  chemicalName: string;
  description: ChemicalState;
  status: BatchStatus;
  statusNotes?: string; 
  dateOfManufacturing: string;
  dateOfAnalysis: string;
  dateOfRetest: string;
  dateOfExpiry: string;
  transactions: Transaction[];
  statusHistory?: StatusLog[];
  analysisHistory?: AnalysisRecord[];
}

export type RequestType = 'R&D' | 'QC' | 'Production';

export interface MaterialRequest {
  id: string;
  type: RequestType;
  chemicalName: string;
  batchNo: string;
  vendorName: string; // Added to track supplier in requests
  quantity: number;
  unit: string;
  requestedBy: string;
  acceptedBy?: string;
  date: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  departmentNotes?: string;
}

export type UserRole = 'admin' | 'user';

export interface User {
  id: string;
  name: string;
  email: string;
  password?: string;
  isEmailConfirmed: boolean;
  isApproved: boolean; // Admin must approve access
  role: UserRole;
  createdAt: string;
}

export interface AuditLog {
  id: string;
  userId: string;
  userEmail: string;
  userName: string;
  action: 'SIGN_IN' | 'SIGN_UP' | 'INVENTORY_ADD' | 'INVENTORY_UPDATE' | 'REQUEST_CREATE' | 'REQUEST_STATUS_CHANGE' | 'USER_ROLE_CHANGE' | 'USER_APPROVAL';
  details: string;
  timestamp: string;
}

export type ViewState = 'dashboard' | 'add' | 'edit' | 'details' | 'ai-insights' | 'requests' | 'login' | 'signup' | 'verify' | 'forgot-password' | 'admin-users' | 'admin-logs' | 'pending-approval';

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { InventoryItem, MaterialRequest, RequestType, BatchStatus } from '../types';
import { 
  BeakerIcon, 
  AcademicCapIcon, 
  CpuChipIcon, 
  ArrowLeftIcon,
  CheckCircleIcon,
  ClockIcon,
  UserIcon,
  InformationCircleIcon,
  HashtagIcon,
  XCircleIcon,
  ArrowDownTrayIcon
} from '@heroicons/react/24/outline';

interface RequestSystemProps {
  inventory: InventoryItem[];
  existingRequests: MaterialRequest[];
  onAddRequest: (request: MaterialRequest) => void;
  onUpdateRequest: (request: MaterialRequest) => void;
  isAdmin: boolean;
}

const RequestSystem: React.FC<RequestSystemProps> = ({ inventory, existingRequests, onAddRequest, onUpdateRequest, isAdmin }) => {
  const [selectedType, setSelectedType] = useState<RequestType | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showApprovalModal, setShowApprovalModal] = useState<MaterialRequest | null>(null);
  const [acceptingPerson, setAcceptingPerson] = useState('');

  const [formData, setFormData] = useState({
    batchNo: '',
    quantity: 0,
    requestedBy: '',
    notes: ''
  });

  const handleTypeSelect = (type: RequestType) => {
    setSelectedType(type);
    setFormData({ batchNo: '', quantity: 0, requestedBy: '', notes: '' });
  };

  const handleExportRequestsExcel = () => {
    const dataToExport = existingRequests.map(req => ({
      'Request ID': req.id,
      'Department': req.type,
      'Date': req.date,
      'Chemical Name': req.chemicalName,
      'Batch No': req.batchNo,
      'Vendor': req.vendorName,
      'Quantity': req.quantity,
      'Unit': req.unit,
      'Requested By': req.requestedBy,
      'Status': req.status,
      'Approved By': req.acceptedBy || 'Pending',
      'Purpose/Notes': req.departmentNotes || ''
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Material Requests");

    const dateStr = new Date().toISOString().split('T')[0];
    const fileName = `Basis_Labs_Material_Requests_${dateStr}.xlsx`;

    XLSX.writeFile(workbook, fileName);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedType) return;

    const selectedItem = inventory.find(i => i.batchNo === formData.batchNo);
    if (!selectedItem) {
      alert("Please select a valid Unique Batch No.");
      return;
    }

    if (selectedItem.status === BatchStatus.REJECTED) {
      alert("This batch is REJECTED and cannot be requested for use.");
      return;
    }

    const newRequest: MaterialRequest = {
      id: Math.random().toString(36).substr(2, 9),
      type: selectedType,
      batchNo: formData.batchNo,
      chemicalName: selectedItem.chemicalName,
      vendorName: selectedItem.vendorName, // Captured from inventory
      quantity: formData.quantity,
      unit: selectedItem.unit,
      requestedBy: formData.requestedBy,
      date: new Date().toISOString().split('T')[0],
      status: 'Pending',
      departmentNotes: formData.notes
    };

    onAddRequest(newRequest);
    setIsSubmitting(true);
    setTimeout(() => {
      setIsSubmitting(false);
      setSelectedType(null);
    }, 1500);
  };

  const handleApprove = () => {
    if (!showApprovalModal || !acceptingPerson.trim()) {
      alert("Please enter the accepting person's name.");
      return;
    }

    const updatedRequest: MaterialRequest = {
      ...showApprovalModal,
      status: 'Approved',
      acceptedBy: acceptingPerson
    };

    onUpdateRequest(updatedRequest);
    setShowApprovalModal(null);
    setAcceptingPerson('');
  };

  const handleReject = (req: MaterialRequest) => {
    const updatedRequest: MaterialRequest = {
      ...req,
      status: 'Rejected'
    };
    onUpdateRequest(updatedRequest);
  };

  const departmentConfigs = {
    'R&D': {
      icon: AcademicCapIcon,
      color: 'purple',
      description: 'Research chemicals and experimentation.',
      bg: 'bg-purple-50',
      border: 'border-purple-200',
      text: 'text-purple-700',
      btn: 'bg-purple-600 hover:bg-purple-700'
    },
    'QC': {
      icon: BeakerIcon,
      color: 'amber',
      description: 'Quality analysis and testing reagents.',
      bg: 'bg-amber-50',
      border: 'border-amber-200',
      text: 'text-amber-700',
      btn: 'bg-amber-600 hover:bg-amber-700'
    },
    'Production': {
      icon: CpuChipIcon,
      color: 'blue',
      description: 'Bulk raw materials for manufacturing.',
      bg: 'bg-blue-50',
      border: 'border-blue-200',
      text: 'text-blue-700',
      btn: 'bg-blue-600 hover:bg-blue-700'
    }
  };

  if (isSubmitting) {
    return (
      <div className="flex flex-col items-center justify-center py-20 animate-pulse">
        <CheckCircleIcon className="w-20 h-20 text-teal-500 mb-4" />
        <h2 className="text-2xl font-bold text-slate-800">Request Submitted!</h2>
        <p className="text-slate-500">Routing request to Material Management for approval...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Upper Section: Type Selection or Form */}
      {!selectedType ? (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {(Object.keys(departmentConfigs) as RequestType[]).map((type) => {
            const config = departmentConfigs[type];
            return (
              <button
                key={type}
                onClick={() => handleTypeSelect(type)}
                className={`flex flex-col items-center p-8 bg-white border ${config.border} rounded-2xl shadow-sm hover:shadow-md transition-all group`}
              >
                <div className={`p-4 rounded-xl ${config.bg} ${config.text} mb-4 group-hover:scale-110 transition-transform`}>
                  <config.icon className="w-10 h-10" />
                </div>
                <h3 className={`text-xl font-bold ${config.text} mb-2`}>{type} Request</h3>
                <p className="text-sm text-slate-500 text-center leading-relaxed">
                  {config.description}
                </p>
                <div className={`mt-6 py-2 px-6 rounded-lg font-semibold text-white ${config.btn} transition-colors`}>
                  Open Form
                </div>
              </button>
            );
          })}
        </div>
      ) : (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden max-w-2xl mx-auto">
          <div className={`${departmentConfigs[selectedType].bg} p-6 border-b ${departmentConfigs[selectedType].border}`}>
            <button 
              onClick={() => setSelectedType(null)}
              className="flex items-center gap-2 text-slate-600 hover:text-slate-900 mb-4 text-sm font-medium"
            >
              <ArrowLeftIcon className="w-4 h-4" />
              Cancel Requisition
            </button>
            <div className="flex items-center gap-4">
              <div className={`p-3 rounded-xl bg-white ${departmentConfigs[selectedType].text}`}>
                {React.createElement(departmentConfigs[selectedType].icon, { className: "w-8 h-8" })}
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800">{selectedType} Material Requisition</h2>
                <p className="text-slate-500 text-sm">Targeting Unique Batch Numbers for traceability.</p>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="p-8 space-y-6 text-left">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Select Unique ID (Batch No)</label>
                <div className="relative">
                  <HashtagIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <select 
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all appearance-none"
                    value={formData.batchNo}
                    onChange={(e) => setFormData({...formData, batchNo: e.target.value})}
                    required
                  >
                    <option value="">-- Select by Unique Batch No --</option>
                    {inventory.map(item => (
                      <option key={item.batchNo} value={item.batchNo} disabled={item.status === BatchStatus.REJECTED}>
                        {item.batchNo} | {item.chemicalName} (Vendor: {item.vendorName}) {item.status === BatchStatus.REJECTED ? '[REJECTED]' : `[Avail: ${item.quantity} ${item.unit}]`}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Quantity Required</label>
                <input 
                  type="number"
                  step="0.01"
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                  placeholder="0.00"
                  value={formData.quantity}
                  onChange={(e) => setFormData({...formData, quantity: parseFloat(e.target.value) || 0})}
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Requested By (Staff Name)</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all"
                    placeholder="Enter name"
                    value={formData.requestedBy}
                    onChange={(e) => setFormData({...formData, requestedBy: e.target.value})}
                    required
                  />
                </div>
              </div>

              <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-1.5">Purpose / Additional Notes</label>
                <textarea 
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-teal-500 outline-none transition-all h-24"
                  placeholder="Specific usage details..."
                  value={formData.notes}
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                ></textarea>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                type="submit"
                className={`w-full py-4 text-white font-bold rounded-xl shadow-lg transition-all ${departmentConfigs[selectedType].btn}`}
              >
                Submit Request
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Lower Section: Requisition History (Always Visible) */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="p-6 border-b border-slate-100 bg-slate-50 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h3 className="font-bold text-slate-800 flex items-center gap-2">
              <ClockIcon className="w-5 h-5 text-teal-600" />
              Material Requisition History {isAdmin && '(Admin View)'}
            </h3>
            <p className="text-xs text-slate-500 mt-1">Audit log of all material batches and their requisition status.</p>
          </div>
          {existingRequests.length > 0 && (
            <button
              onClick={handleExportRequestsExcel}
              className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white text-xs font-bold uppercase rounded-xl hover:bg-slate-700 transition-all shadow-lg shadow-slate-200 flex-shrink-0"
              title="Download full requisition history as Excel"
            >
              <ArrowDownTrayIcon className="w-4 h-4" />
              Export History to Excel
            </button>
          )}
        </div>
        <div className="overflow-x-auto">
          {existingRequests.length === 0 ? (
            <div className="p-12 text-center text-slate-400">
              <InformationCircleIcon className="w-10 h-10 mx-auto mb-2 opacity-20" />
              <p>No material requests placed yet.</p>
            </div>
          ) : (
            <table className="w-full text-left text-sm">
              <thead className="bg-slate-50 text-slate-500 uppercase text-[10px] font-bold">
                <tr>
                  <th className="px-6 py-3">Dept</th>
                  <th className="px-6 py-3">Batch / Vendor</th>
                  <th className="px-6 py-3">Chemical</th>
                  <th className="px-6 py-3">Qty</th>
                  <th className="px-6 py-3">Requested By</th>
                  <th className="px-6 py-3">Status</th>
                  {isAdmin && <th className="px-6 py-3 text-right">Actions</th>}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {existingRequests.map((req) => (
                  <tr key={req.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4">
                      <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${
                        req.type === 'R&D' ? 'bg-purple-100 text-purple-700' :
                        req.type === 'QC' ? 'bg-amber-100 text-amber-700' :
                        'bg-blue-100 text-blue-700'
                      }`}>
                        {req.type}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="font-mono font-bold text-slate-900">{req.batchNo}</span>
                        <span className="text-[10px] text-slate-400 uppercase">{req.vendorName}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600">{req.chemicalName}</td>
                    <td className="px-6 py-4 font-semibold">{req.quantity} {req.unit}</td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-slate-800 font-medium">{req.requestedBy}</span>
                        <span className="text-[10px] text-slate-400">{req.date}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`flex items-center gap-1.5 font-bold uppercase text-[10px] ${
                        req.status === 'Approved' ? 'text-green-600' : 
                        req.status === 'Rejected' ? 'text-red-600' : 'text-amber-600'
                      }`}>
                        {req.status}
                      </span>
                    </td>
                    {isAdmin && (
                      <td className="px-6 py-4 text-right">
                        {req.status === 'Pending' && (
                          <div className="flex justify-end gap-2">
                            <button 
                              onClick={() => setShowApprovalModal(req)}
                              className="px-3 py-1 bg-green-600 text-white rounded-lg text-[10px] font-bold hover:bg-green-700 transition-colors shadow-sm"
                            >
                              Approve
                            </button>
                            <button 
                              onClick={() => handleReject(req)}
                              className="px-3 py-1 bg-red-600 text-white rounded-lg text-[10px] font-bold hover:bg-red-700 transition-colors shadow-sm"
                            >
                              Reject
                            </button>
                          </div>
                        )}
                        {req.status === 'Approved' && (
                          <span className="text-[10px] text-slate-400 italic">Auth by: {req.acceptedBy}</span>
                        )}
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* Acceptance Name Modal */}
      {isAdmin && showApprovalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="bg-green-600 p-6 text-white">
              <h3 className="text-xl font-bold">Approve Material Requisition</h3>
              <p className="text-green-100 text-sm">Batch: {showApprovalModal.batchNo}</p>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1.5 text-left">Accepting Person Name</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder="Authorized Staff Name"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-green-500 outline-none transition-all"
                    value={acceptingPerson}
                    onChange={(e) => setAcceptingPerson(e.target.value)}
                    autoFocus
                  />
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button 
                  onClick={() => setShowApprovalModal(null)}
                  className="flex-1 py-3 text-sm font-medium text-slate-600 bg-slate-100 rounded-xl hover:bg-slate-200"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleApprove}
                  className="flex-1 py-3 text-sm font-medium text-white bg-green-600 rounded-xl hover:bg-green-700 shadow-lg shadow-green-200"
                >
                  Confirm & Approve
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RequestSystem;

import React, { useState } from 'react';
import { ViewState, User, UserRole } from '../types';
import { db } from '../services/DatabaseService';
import { 
  EnvelopeIcon, 
  LockClosedIcon, 
  UserIcon, 
  ExclamationCircleIcon,
  ArrowPathIcon,
  ArrowLeftIcon,
  BriefcaseIcon,
  UserGroupIcon,
  ClockIcon,
  EnvelopeOpenIcon,
  InboxStackIcon
} from '@heroicons/react/24/outline';

const SUPER_ADMIN_EMAIL = 'tanujrao2006@gmail.com';

interface AuthProps {
  view: ViewState;
  setView: (v: ViewState) => void;
  setCurrentUser: (u: User | null) => void;
  currentUser: User | null;
}

const Auth: React.FC<AuthProps> = ({ view, setView, setCurrentUser, currentUser }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: 'user' as UserRole
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [recoveredPassword, setRecoveredPassword] = useState<string | null>(null);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const email = formData.email.toLowerCase().trim();
    const password = formData.password.trim();
    const selectedRole = formData.role;

    setTimeout(() => {
      const users = db.getUsers();

      if (view === 'login') {
        const user = users.find(u => 
          u.email.toLowerCase().trim() === email && 
          u.password === password &&
          u.role === selectedRole
        );

        if (user) {
          if (!user.isApproved) {
             setError('Access Pending: Your account is awaiting Admin approval.');
             setLoading(false);
             return;
          }

          setCurrentUser(user);
          db.logAction(user, 'SIGN_IN', `Authenticated as ${user.role}`);
          if (user.isEmailConfirmed) {
            setView('dashboard');
          } else {
            setView('verify');
          }
        } else {
          setError(`Invalid credentials for ${selectedRole.toUpperCase()}.`);
        }
      } else if (view === 'signup') {
        if (users.some(u => u.email.toLowerCase().trim() === email)) {
          setError('This Gmail is already registered. Please login.');
        } else {
          const newUser: User = {
            id: Math.random().toString(36).substr(2, 9),
            name: formData.name.trim(),
            email: email,
            password: password,
            isEmailConfirmed: false,
            isApproved: false, 
            role: 'user', 
            createdAt: new Date().toISOString()
          };
          db.saveUser(newUser);
          db.logAction(newUser, 'SIGN_UP', 'User registered, pending admin approval');
          setCurrentUser(newUser);
          setView('verify');
        }
      } else if (view === 'forgot-password') {
        const user = users.find(u => u.email.toLowerCase().trim() === email);
        if (user) {
          setRecoveredPassword(user.password || 'Unknown');
        } else {
          setError('We could not find an account associated with this email address.');
        }
      }
      setLoading(false);
    }, 1200);
  };

  const handleVerify = () => {
    setLoading(true);
    setTimeout(() => {
      if (currentUser) {
        const updatedUser = { ...currentUser, isEmailConfirmed: true };
        db.saveUser(updatedUser);
        setCurrentUser(updatedUser);
        if (!updatedUser.isApproved) {
          setView('pending-approval');
        } else {
          setView('dashboard');
        }
      }
      setLoading(false);
    }, 1500);
  };

  // --- Specialized Views ---

  if (recoveredPassword) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-fade-in">
          <div className="p-8 text-center border-b border-slate-100">
            <div className="flex justify-center mb-4">
              <div className="p-4 bg-teal-50 rounded-full">
                <EnvelopeOpenIcon className="w-10 h-10 text-teal-600 animate-pulse" />
              </div>
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-1">Recovery Sent</h2>
            <p className="text-slate-500 text-sm">A simulation email has been generated below.</p>
          </div>

          <div className="p-8 bg-slate-50">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
               <div className="px-4 py-3 bg-slate-100 border-b flex items-center gap-2">
                  <InboxStackIcon className="w-4 h-4 text-slate-400" />
                  <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Simulated Inbox Preview</span>
               </div>
               <div className="p-6 text-left space-y-4">
                  <div className="grid grid-cols-4 gap-2 text-xs border-b border-slate-100 pb-3">
                    <span className="text-slate-400 font-bold uppercase">From:</span>
                    <span className="col-span-3 text-slate-700 font-medium">Basis Labs System &lt;noreply@basislabs.com&gt;</span>
                    <span className="text-slate-400 font-bold uppercase">To:</span>
                    <span className="col-span-3 text-teal-600 font-bold">{formData.email}</span>
                    <span className="text-slate-400 font-bold uppercase">Subject:</span>
                    <span className="col-span-3 text-slate-800 font-bold">Account Password Recovery</span>
                  </div>
                  <div className="py-4 space-y-4">
                    <p className="text-sm text-slate-600">Dear User,</p>
                    <p className="text-sm text-slate-600 leading-relaxed">
                      You requested a password recovery for your account at **Basis Laboratories Pvt Ltd**. 
                      Your current registered password is:
                    </p>
                    <div className="bg-teal-50 border-2 border-dashed border-teal-200 p-4 rounded-xl text-center">
                      <span className="text-2xl font-mono font-black text-teal-700 tracking-[0.2em]">{recoveredPassword}</span>
                    </div>
                    <p className="text-xs text-slate-400 italic mt-4">
                      Note: This is a standalone browser simulation. In a live system, this data would be sent via SMTP to your actual Gmail inbox.
                    </p>
                  </div>
               </div>
            </div>
          </div>

          <div className="p-6">
            <button 
              onClick={() => { setRecoveredPassword(null); setView('login'); }}
              className="w-full py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-slate-700 transition-all shadow-lg"
            >
              Return to Login
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'pending-approval') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in relative">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-amber-50 rounded-full">
              <ClockIcon className="w-12 h-12 text-amber-600 animate-pulse" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Registration Complete</h2>
          <p className="text-slate-500 text-sm leading-relaxed mb-8">
            Your account is now pending **Admin Approval**. You will be able to log in once an authorized manager grants you access.
          </p>
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 text-xs text-slate-500 mb-8">
            Registered Email: <br/>
            <span className="font-bold text-slate-700">{currentUser?.email}</span>
          </div>
          <button 
            onClick={() => { setCurrentUser(null); setView('login'); }}
            className="w-full py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-slate-700 transition-all"
          >
            Return to Login
          </button>
        </div>
      </div>
    );
  }

  if (view === 'verify') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in relative">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-teal-50 rounded-full">
              <EnvelopeIcon className="w-12 h-12 text-teal-600 animate-bounce" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Confirm Email</h2>
          <p className="text-slate-500 text-sm mb-8">Confirmation link sent to: <br/><strong>{currentUser?.email}</strong></p>
          <button 
            onClick={handleVerify}
            className="w-full py-4 bg-teal-600 text-white font-bold rounded-2xl shadow-lg hover:bg-teal-700 transition-all"
          >
            Simulate Confirmation
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4">
      <div className="mb-8 flex flex-col items-center gap-4">
         <img src="https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U" alt="Logo" className="w-20 h-20 rounded-2xl shadow-2xl bg-white p-1" />
         <div className="text-center">
            <h1 className="text-3xl font-bold text-white tracking-tight">Basis Laboratories</h1>
            <p className="text-slate-400 font-medium uppercase tracking-[0.2em] text-xs mt-1">Inventory Management System</p>
         </div>
      </div>

      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
        <div className="p-8">
          <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
             <h2 className="text-2xl font-bold text-slate-800">
               {view === 'login' ? 'System Login' : view === 'signup' ? 'User Signup' : 'Account Recovery'}
             </h2>
             <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">v1.5.0 Secure</span>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {error && (
              <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-700 text-[11px] font-bold text-left leading-relaxed">
                 <ExclamationCircleIcon className="w-5 h-5 flex-shrink-0" />
                 {error}
              </div>
            )}

            {/* Role Selection (Only on Login) */}
            {view === 'login' && (
              <div className="grid grid-cols-2 gap-3 mb-4">
                <button type="button" onClick={() => setFormData({...formData, role: 'admin'})} className={`flex items-center justify-center gap-2 py-3 rounded-xl border-2 transition-all ${formData.role === 'admin' ? 'border-teal-600 bg-teal-50 text-teal-700' : 'border-slate-100 text-slate-400'}`}>
                  <BriefcaseIcon className="w-5 h-5" />
                  <span className="text-xs font-bold uppercase">Admin</span>
                </button>
                <button type="button" onClick={() => setFormData({...formData, role: 'user'})} className={`flex items-center justify-center gap-2 py-3 rounded-xl border-2 transition-all ${formData.role === 'user' ? 'border-teal-600 bg-teal-50 text-teal-700' : 'border-slate-100 text-slate-400'}`}>
                  <UserGroupIcon className="w-5 h-5" />
                  <span className="text-xs font-bold uppercase">User</span>
                </button>
              </div>
            )}

            {view === 'signup' && (
              <div className="relative">
                <UserIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                <input type="text" placeholder="Full Name" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-teal-500" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} />
              </div>
            )}

            <div className="relative">
              <EnvelopeIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
              <input 
                type="email" 
                placeholder="Gmail Address" 
                required 
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-teal-500" 
                value={formData.email} 
                onChange={(e) => setFormData({...formData, email: e.target.value})} 
                disabled={view === 'login' && formData.role === 'admin' && formData.email === SUPER_ADMIN_EMAIL}
              />
            </div>

            {view !== 'forgot-password' && (
              <div className="relative">
                <LockClosedIcon className="w-5 h-5 absolute left-3 top-3.5 text-slate-400" />
                <input type="password" placeholder="Password" required className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-teal-500" value={formData.password} onChange={(e) => setFormData({...formData, password: e.target.value})} />
              </div>
            )}

            {view === 'login' && (
              <div className="text-right -mt-2">
                <button 
                  type="button" 
                  onClick={() => setView('forgot-password')}
                  className="text-[10px] font-bold text-slate-400 hover:text-teal-600 uppercase tracking-tight transition-colors"
                >
                  Forgot Password?
                </button>
              </div>
            )}

            <button type="submit" disabled={loading} className="w-full py-4 bg-teal-600 hover:bg-teal-700 text-white font-bold rounded-2xl shadow-lg transition-all flex items-center justify-center gap-3">
              {loading ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : (
                view === 'login' ? `Authenticate` : 
                view === 'signup' ? 'Register Request' :
                'Send Recovery Mail'
              )}
            </button>
          </form>
        </div>

        <div className="p-6 bg-slate-50 border-t text-center space-y-3">
          {view === 'login' && formData.role === 'user' && (
            <button onClick={() => setView('signup')} className="text-xs font-bold text-slate-500 hover:text-teal-600 uppercase tracking-tight block w-full">
              New Staff? Request Account
            </button>
          )}

          {(view === 'signup' || view === 'forgot-password') && (
            <button onClick={() => setView('login')} className="text-xs font-bold text-slate-500 hover:text-teal-600 uppercase tracking-tight block w-full flex items-center justify-center gap-2">
              <ArrowLeftIcon className="w-3 h-3" />
              Back to Login
            </button>
          )}

          {view === 'login' && formData.role === 'admin' && (
            <p className="text-[10px] text-slate-400 font-bold uppercase">Admin Registration Restricted</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React from 'react';
import { InventoryItem, ChemicalState, BatchStatus } from '../types';
import { PencilSquareIcon, EyeIcon, ArchiveBoxIcon, HashtagIcon, ExclamationCircleIcon, ChatBubbleBottomCenterTextIcon } from '@heroicons/react/24/outline';

interface InventoryTableProps {
  items: InventoryItem[];
  onEdit?: (item: InventoryItem) => void;
  onView: (item: InventoryItem) => void;
}

const InventoryTable: React.FC<InventoryTableProps> = ({ items, onEdit, onView }) => {
  if (items.length === 0) {
    return (
      <div className="bg-white rounded-xl border border-dashed border-slate-300 p-12 text-center">
        <ArchiveBoxIcon className="w-12 h-12 text-slate-300 mx-auto mb-4" />
        <h3 className="text-lg font-medium text-slate-600">No inventory items found</h3>
        <p className="text-slate-400">Try adjusting your search or add a new unique batch.</p>
      </div>
    );
  }

  const getStatusStyle = (status: BatchStatus) => {
    switch (status) {
      case BatchStatus.APPROVED: return 'bg-green-100 text-green-700 border-green-200';
      case BatchStatus.REJECTED: return 'bg-red-100 text-red-700 border-red-200';
      case BatchStatus.QUARANTINE: return 'bg-amber-100 text-amber-700 border-amber-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 border-b border-slate-200 text-slate-600 uppercase text-xs font-semibold">
            <tr>
              <th className="px-6 py-4">Unique Batch No</th>
              <th className="px-6 py-4">Chemical Name</th>
              <th className="px-6 py-4">Vendor Details</th>
              <th className="px-6 py-4">Quantity</th>
              <th className="px-6 py-4 min-w-[200px]">Batch Status & Notes</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200">
            {items.map((item) => {
              const isLowStock = item.quantity < 5;

              return (
                <tr key={item.batchNo} className={`hover:bg-slate-50 transition-colors ${isLowStock ? 'bg-amber-50/30' : ''}`}>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-slate-100 rounded-lg text-slate-600">
                        <HashtagIcon className="w-5 h-5" />
                      </div>
                      <div className="font-mono font-bold text-slate-900 leading-none">
                        {item.batchNo}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${item.description === ChemicalState.SOLID ? 'bg-amber-400' : 'bg-blue-400'}`}></div>
                      <div className="font-semibold text-slate-700">{item.chemicalName}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="font-medium text-slate-700">{item.vendorName}</span>
                      <span className="text-[10px] text-slate-400 uppercase font-bold tracking-tight">{item.vendorQualification}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`font-medium ${isLowStock ? 'text-red-600 font-bold' : 'text-slate-700'}`}>
                        {item.quantity} {item.unit}
                      </div>
                      {isLowStock && (
                        <ExclamationCircleIcon className="w-4 h-4 text-red-500 animate-pulse" />
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col gap-2">
                      <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase border w-fit ${getStatusStyle(item.status)}`}>
                        {item.status}
                      </span>
                      {item.status !== BatchStatus.APPROVED && item.statusNotes && (
                        <div className="flex items-start gap-1.5 p-2 bg-slate-50 border border-slate-100 rounded-lg text-[11px] text-slate-600 leading-relaxed max-w-[250px]">
                          <ChatBubbleBottomCenterTextIcon className="w-3.5 h-3.5 mt-0.5 flex-shrink-0 text-slate-400" />
                          <span className="font-medium italic">{item.statusNotes}</span>
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => onView(item)}
                        className="p-1.5 text-slate-400 hover:text-teal-600 transition-colors"
                        title="View Full Details"
                      >
                        <EyeIcon className="w-5 h-5" />
                      </button>
                      {onEdit && (
                        <button 
                          onClick={() => onEdit(item)}
                          className="p-1.5 text-slate-400 hover:text-blue-600 transition-colors"
                          title="Edit Batch Profile (Admin Only)"
                        >
                          <PencilSquareIcon className="w-5 h-5" />
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default InventoryTable;

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { InventoryItem, MaterialRequest, BatchStatus, AnalysisRecord } from '../types';
import { 
  ArrowLeftIcon, 
  DocumentTextIcon, 
  CalendarDaysIcon, 
  UserIcon, 
  HashtagIcon,
  ShieldCheckIcon,
  ClipboardDocumentCheckIcon,
  ArrowPathIcon,
  ChatBubbleBottomCenterTextIcon,
  ClockIcon,
  CheckBadgeIcon,
  BeakerIcon,
  CheckIcon,
  XMarkIcon,
  ArrowDownTrayIcon
} from '@heroicons/react/24/outline';

interface ItemDetailsProps {
  item: InventoryItem;
  onBack: () => void;
  onRevert: (transactionId: string) => void;
  onUpdateItem: (updatedItem: InventoryItem) => void;
  requests: MaterialRequest[];
  isAdmin: boolean;
}

const ItemDetails: React.FC<ItemDetailsProps> = ({ item, onBack, onRevert, onUpdateItem, requests, isAdmin }) => {
  const [showAnalysisForm, setShowAnalysisForm] = useState(false);
  const [analysisResult, setAnalysisResult] = useState('');
  const [nextRetestDate, setNextRetestDate] = useState('');
  const [performerName, setPerformerName] = useState('');

  const getStatusColor = (status: BatchStatus) => {
    switch(status) {
      case BatchStatus.APPROVED: return 'text-green-600';
      case BatchStatus.REJECTED: return 'text-red-600';
      default: return 'text-amber-600';
    }
  };

  const getStatusBg = (status: BatchStatus) => {
    switch(status) {
      case BatchStatus.APPROVED: return 'bg-green-50 border-green-100';
      case BatchStatus.REJECTED: return 'bg-red-50 border-red-200';
      default: return 'bg-amber-50 border-amber-200';
    }
  };

  const handleExportUsageExcel = () => {
    const dataToExport = item.transactions.map(tx => ({
      'Batch No': item.batchNo,
      'Chemical': item.chemicalName,
      'Date': tx.date,
      'Purpose': tx.purpose,
      'Amount Used': tx.amount,
      'Unit': item.unit,
      'Transaction ID': tx.id
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Usage History");
    XLSX.writeFile(workbook, `Usage_${item.batchNo}_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleExportAnalysisExcel = () => {
    const history = item.analysisHistory || [];
    const dataToExport = history.map(ana => ({
      'Batch No': item.batchNo,
      'Chemical': item.chemicalName,
      'Analysis Date': ana.analysisDate,
      'Performed By': ana.performedBy,
      'Result': ana.result,
      'Next Retest Date': ana.nextRetestDate
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Analysis History");
    XLSX.writeFile(workbook, `Analysis_${item.batchNo}_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const handleCompleteAnalysis = () => {
    if (!analysisResult || !nextRetestDate || !performerName) {
      alert("Please fill in all analysis fields.");
      return;
    }

    const newRecord: AnalysisRecord = {
      id: `ana-${Date.now()}`,
      analysisDate: item.dateOfRetest, // Retest date becomes the actual analysis date
      result: analysisResult,
      performedBy: performerName,
      nextRetestDate: nextRetestDate
    };

    const updatedItem: InventoryItem = {
      ...item,
      dateOfAnalysis: item.dateOfRetest,
      dateOfRetest: nextRetestDate,
      analysisHistory: [newRecord, ...(item.analysisHistory || [])]
    };

    onUpdateItem(updatedItem);
    setShowAnalysisForm(false);
    setAnalysisResult('');
    setNextRetestDate('');
    setPerformerName('');
    alert("Analysis successfully logged. Dates updated.");
  };

  return (
    <div className="space-y-6">
      <button 
        onClick={onBack}
        className="flex items-center gap-2 text-slate-600 hover:text-teal-600 transition-colors mb-4"
      >
        <ArrowLeftIcon className="w-4 h-4" />
        Back to Dashboard
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 text-left">
        {/* Profile Card */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 text-teal-600 mb-1">
              <HashtagIcon className="w-4 h-4" />
              <span className="text-xs font-bold uppercase tracking-widest">Unique Identity</span>
            </div>
            <h2 className="text-2xl font-mono font-bold text-slate-900 mb-4">{item.batchNo}</h2>

            <div className="space-y-4 mb-6 pt-4 border-t border-slate-100">
               <div className="flex justify-between items-center">
                  <div>
                    <div className="text-xs text-slate-400 uppercase font-bold">Batch Status</div>
                    <div className={`text-sm font-bold uppercase ${getStatusColor(item.status)}`}>{item.status}</div>
                  </div>
                  <ShieldCheckIcon className={`w-6 h-6 ${getStatusColor(item.status)}`} />
               </div>

               {/* QC Notes Alert Box */}
               {item.status !== BatchStatus.APPROVED && item.statusNotes && (
                 <div className={`p-4 border-2 rounded-xl ${getStatusBg(item.status)} animate-fade-in`}>
                    <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest mb-2 text-slate-600">
                      <ChatBubbleBottomCenterTextIcon className="w-4 h-4" />
                      {item.status === BatchStatus.REJECTED ? 'Mandatory Rejection Reason' : 'Quarantine Observations'}
                    </div>
                    <div className="text-sm text-slate-800 font-bold leading-relaxed">
                      "{item.statusNotes}"
                    </div>
                 </div>
               )}

               <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Chemical Name</div>
                  <div className="text-lg text-slate-800 font-semibold">{item.chemicalName}</div>
               </div>
            </div>

            <div className="flex items-center justify-between p-4 bg-slate-50 rounded-lg mb-6">
              <span className="text-sm text-slate-600 font-medium">Available Stock</span>
              <span className={`text-lg font-bold ${item.quantity < 5 ? 'text-red-600' : 'text-teal-600'}`}>
                {item.quantity} {item.unit}
              </span>
            </div>

            <div className="space-y-4">
              <div className="flex items-start gap-3">
                <UserIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Vendor</div>
                  <div className="text-sm text-slate-800 font-medium">{item.vendorName}</div>
                  <div className="text-[10px] text-slate-500 font-bold uppercase">{item.vendorQualification}</div>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <CheckBadgeIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div>
                  <div className="text-xs text-slate-400 uppercase font-bold">Last Analysis Date</div>
                  <div className="text-sm text-slate-800 font-medium">{item.dateOfAnalysis}</div>
                </div>
              </div>

              <div className="flex items-start gap-3">
                <ClockIcon className="w-5 h-5 text-slate-400 mt-0.5" />
                <div className="flex-1">
                  <div className="flex justify-between items-start">
                    <div>
                      <div className="text-xs text-slate-400 uppercase font-bold">Next Retest Due</div>
                      <div className="text-sm text-slate-800 font-medium">{item.dateOfRetest}</div>
                    </div>
                  </div>
                </div>
              </div>

              {isAdmin && !showAnalysisForm && (
                <button 
                  onClick={() => setShowAnalysisForm(true)}
                  className="w-full mt-4 flex items-center justify-center gap-2 py-3 bg-slate-800 text-white rounded-xl text-xs font-bold uppercase tracking-wider hover:bg-slate-700 transition-all shadow-md"
                >
                  <BeakerIcon className="w-4 h-4" />
                  Analysis Completed
                </button>
              )}

              {isAdmin && showAnalysisForm && (
                <div className="mt-4 p-4 bg-teal-50 border border-teal-200 rounded-xl space-y-3 animate-fade-in">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-[10px] font-bold text-teal-700 uppercase tracking-widest">New Analysis Entry</span>
                    <button onClick={() => setShowAnalysisForm(false)} className="text-slate-400 hover:text-red-500">
                      <XMarkIcon className="w-4 h-4" />
                    </button>
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Analysis Result</label>
                    <textarea 
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      placeholder="Enter quality results..."
                      rows={2}
                      value={analysisResult}
                      onChange={(e) => setAnalysisResult(e.target.value)}
                    />
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Performed By</label>
                    <input 
                      type="text"
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      placeholder="Analyst name"
                      value={performerName}
                      onChange={(e) => setPerformerName(e.target.value)}
                    />
                  </div>

                  <div>
                    <label className="text-[10px] font-bold text-slate-500 uppercase">Next Retest Date</label>
                    <input 
                      type="date"
                      className="w-full p-2 text-xs border border-teal-100 rounded bg-white outline-none focus:ring-1 focus:ring-teal-500"
                      value={nextRetestDate}
                      onChange={(e) => setNextRetestDate(e.target.value)}
                    />
                  </div>

                  <button 
                    onClick={handleCompleteAnalysis}
                    className="w-full py-2 bg-teal-600 text-white rounded-lg text-[10px] font-bold uppercase tracking-wider hover:bg-teal-700 shadow-sm"
                  >
                    Confirm & Update Dates
                  </button>
                </div>
              )}

