import React, { useState } from 'react';
import { ViewState, User, UserRole } from '../types';
import { db } from '../services/DatabaseService';
import { 
  EnvelopeIcon, 
  LockClosedIcon, 
  UserIcon, 
  ExclamationCircleIcon,
  ArrowPathIcon,
  ArrowLeftIcon,
  BriefcaseIcon,
  UserGroupIcon,
  ClockIcon
} from '@heroicons/react/24/outline';

const SUPER_ADMIN_EMAIL = 'tanujrao2006@gmail.com';

interface AuthProps {
  view: ViewState;
  setView: (v: ViewState) => void;
  setCurrentUser: (u: User | null) => void;
  currentUser: User | null;
}

// Completed truncated file and added missing default export for Auth
const Auth: React.FC<AuthProps> = ({ view, setView, setCurrentUser, currentUser }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: 'user' as UserRole
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const email = formData.email.toLowerCase().trim();
    const password = formData.password.trim();
    const selectedRole = formData.role;

    setTimeout(() => {
      const users = db.getUsers();

      if (view === 'login') {
        const user = users.find(u => 
          u.email.toLowerCase().trim() === email && 
          u.password === password &&
          u.role === selectedRole
        );

        if (user) {
          if (!user.isApproved) {
             setError('Access Pending: Your account is awaiting Admin approval.');
             setLoading(false);
             return;
          }

          setCurrentUser(user);
          db.logAction(user, 'SIGN_IN', `Authenticated as ${user.role}`);
          if (user.isEmailConfirmed) {
            setView('dashboard');
          } else {
            setView('verify');
          }
        } else {
          setError(`Invalid credentials for ${selectedRole.toUpperCase()}.`);
        }
      } else if (view === 'signup') {
        if (users.some(u => u.email.toLowerCase().trim() === email)) {
          setError('This Gmail is already registered. Please login.');
        } else {
          const newUser: User = {
            id: Math.random().toString(36).substr(2, 9),
            name: formData.name.trim(),
            email: email,
            password: password,
            isEmailConfirmed: false,
            isApproved: false, 
            role: 'user', 
            createdAt: new Date().toISOString()
          };
          db.saveUser(newUser);
          db.logAction(newUser, 'SIGN_UP', 'User registered, pending admin approval');
          setCurrentUser(newUser);
          setView('verify');
        }
      }
      setLoading(false);
    }, 1200);
  };

  const handleVerify = () => {
    setLoading(true);
    setTimeout(() => {
      if (currentUser) {
        const updatedUser = { ...currentUser, isEmailConfirmed: true };
        db.saveUser(updatedUser);
        setCurrentUser(updatedUser);
        if (!updatedUser.isApproved) {
          setView('pending-approval');
        } else {
          setView('dashboard');
        }
      }
      setLoading(false);
    }, 1500);
  };

  if (view === 'pending-approval') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in relative">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-amber-50 rounded-full">
              <ClockIcon className="w-12 h-12 text-amber-600 animate-pulse" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Registration Complete</h2>
          <p className="text-slate-500 text-sm leading-relaxed mb-8">
            Your account is now pending **Admin Approval**. You will be able to log in once an authorized manager grants you access.
          </p>
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 text-xs text-slate-500 mb-8">
            Registered Email: <br/>
            <span className="font-bold text-slate-700">{currentUser?.email}</span>
          </div>
          <button 
            onClick={() => { setCurrentUser(null); setView('login'); }}
            className="w-full py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-slate-700 transition-all"
          >
            Return to Login
          </button>
        </div>
      </div>
    );
  }

  if (view === 'verify') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden text-center p-10 animate-fade-in relative">
          <div className="flex justify-center mb-6">
            <div className="p-4 bg-teal-50 rounded-full">
              <EnvelopeIcon className="w-12 h-12 text-teal-600 animate-bounce" />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-slate-800 mb-2">Confirm Email</h2>
          <p className="text-slate-500 text-sm mb-8">Confirmation link sent to: <br/><strong>{currentUser?.email}</strong></p>
          <button 
            onClick={handleVerify}
            className="w-full py-4 bg-teal-600 text-white font-bold rounded-2xl shadow-lg hover:bg-teal-700 transition-all"
          >
            Simulate Confirmation
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center p-4">
      <div className="mb-8 flex flex-col items-center gap-4">
         <img src="https://media.licdn.com/dms/image/v2/C4D0BAQHpjT4zGjfV_g/company-logo_200_200/company-logo_200_200/0/1631314781282?e=2147483647&v=beta&t=WDzVKIUkXdwKS7stXtOAnOj-y-QFuJvdr80p75i_88U" alt="Logo" className="w-20 h-20 rounded-2xl shadow-2xl bg-white p-1" />
         <div className="text-center">
            <h1 className="text-3xl font-bold text-white tracking-tight">Basis Laboratories</h1>
            <p className="text-slate-400 font-medium uppercase tracking-[0.2em] text-[10px]">Secure Inventory Management</p>
         </div>
      </div>

      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="p-8">
          <div className="flex justify-between items-center mb-8">
            <h2 className="text-2xl font-bold text-slate-800">
              {view === 'login' ? 'Sign In' : 'Create Account'}
            </h2>
            <button 
              onClick={() => { setView(view === 'login' ? 'signup' : 'login'); setError(''); }}
              className="text-teal-600 text-sm font-bold hover:underline"
            >
              {view === 'login' ? 'Register' : 'Login'}
            </button>
          </div>

          {error && (
            <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-600 text-sm">
              <ExclamationCircleIcon className="w-5 h-5 shrink-0" />
              <p>{error}</p>
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-4">
            {view === 'signup' && (
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase ml-1">Full Name</label>
                <div className="relative">
                  <UserIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                  <input 
                    type="text" 
                    required 
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-teal-500 transition-all"
                    placeholder="Enter your name"
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase ml-1">Email Address</label>
              <div className="relative">
                <EnvelopeIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                <input 
                  type="email" 
                  required 
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-teal-500 transition-all"
                  placeholder="name@gmail.com"
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase ml-1">Password</label>
              <div className="relative">
                <LockClosedIcon className="w-5 h-5 absolute left-3 top-3 text-slate-400" />
                <input 
                  type="password" 
                  required 
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-teal-500 transition-all"
                  placeholder="••••••••"
                  value={formData.password}
                  onChange={(e) => setFormData({...formData, password: e.target.value})}
                />
              </div>
            </div>

            {view === 'login' && (
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase ml-1">Role Selection</label>
                <div className="grid grid-cols-2 gap-3">
                  <button 
                    type="button"
                    onClick={() => setFormData({...formData, role: 'user'})}
                    className={`flex items-center justify-center gap-2 py-3 rounded-xl border transition-all ${formData.role === 'user' ? 'bg-teal-50 border-teal-500 text-teal-700 shadow-sm' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                  >
                    <BriefcaseIcon className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase">Staff</span>
                  </button>
                  <button 
                    type="button"
                    onClick={() => setFormData({...formData, role: 'admin'})}
                    className={`flex items-center justify-center gap-2 py-3 rounded-xl border transition-all ${formData.role === 'admin' ? 'bg-teal-50 border-teal-500 text-teal-700 shadow-sm' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                  >
                    <UserGroupIcon className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase">Admin</span>
                  </button>
                </div>
              </div>
            )}

            <button 
              type="submit" 
              disabled={loading}
              className="w-full py-4 bg-teal-600 text-white font-bold rounded-2xl shadow-lg hover:bg-teal-700 transition-all flex items-center justify-center gap-3 disabled:opacity-50"
            >
              {loading ? <ArrowPathIcon className="w-5 h-5 animate-spin" /> : null}
              {view === 'login' ? 'Sign In Securely' : 'Complete Registration'}
            </button>
          </form>
        </div>

        <div className="bg-slate-50 p-6 border-t border-slate-100 flex items-center gap-4 text-xs text-slate-400">
           <LockClosedIcon className="w-4 h-4" />
           <p>Enterprise grade 256-bit encryption active. Basis Laboratories Identity Service.</p>
        </div>
      </div>
    </div>
  );
};

export default Auth;
